INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-44019', 'gcn', 'EP260314a', '2026-03-15T12:33:39.000Z', '{"measurements":{"dec":null,"distance":null,"duration":"7.5 hours","energy":null,"fluence":null,"magnitude":{"i":"> 24.08","z":"> 23.17"},"other_measurements":{"exposure_time":"144 minutes","observation_end_time":"2026-03-15 11:14:09 UTC","observation_start_time":"2026-03-15 04:49:56 UTC"},"ra":null,"redshift":null,"tables":[]},"authors":{"affiliations":[],"authors":[],"institutions":[],"universities":[]},"telescopes":{"facilities":[],"instruments":[],"observatories":[],"telescopes":[]},"urls":[],"basic_data":{"author":{"email":"ffortin.sci.edu@gmail.com","institution":"IRAP","name":"F. Fortin"},"coordinates":{},"detectionTime":"1926-03-15T12:33:39.000Z","event":"EP260314a","eventType":"EP","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 44019\nSUBJECT: EP260314a: COLIBRÍ optical upper limit\nDATE: 26/03/15 12:33:39 GMT\nFROM: F. Fortin at IRAP <ffortin.sci.edu@gmail.com>\n\nFrancis Fortin (IRAP), Edilberto Aguilar-Ruiz (UNAM), Stéphane Basa (UAR Pytheas), William H. Lee (UNAM), Alan M. Watson (UNAM), Jean-Luc Atteia (IRAP), Camila Angulo (UNAM), Dalya Akl (NYUAD), Sarah Antier (IJCLAB), Rosa L. Becerra (UNAM), Nathaniel R. Butler (ASU), Damien Dornic (CPPM), Jean-Grégoire Ducoin (CPPM), Leonardo García García (UNAM), Ramandeep Gill (UNAM), Noémie Globus (UNAM), Marion Guelfand (CPPM), Asuka Kuwata (UNAM), Missimiliano Lincetto (CPPM), Nikos Mandarakas (LAM), Diego López-Cámara (UNAM), Francesco Magnani (CPPM), Enrique Moreno Méndez (UNAM), Margarita Pereyra (UNAM), Ny Avo Rakotondrainibe (LAM), Fredd Sánchez Álvarez (UNAM), Benjamin Schneider (LAM) and Antonio de Ugarte Postigo (LAM) report:\n\nWe imaged the field of EP260314a (Zhao et al., GCN Circ. 44010, Wu et al., GCN Circ. 44016) using the DDRAGO two-channel wide-field imager on the COLIBRÍ telescope. We observed from 2026-03-15 04:49:56 to 11:14:09 UTC (from 9.1 to 12.4 hours after the trigger) and obtained 144 minutes of simultaneous exposure in the i and z filters.\n\nThe data were reduced and coadded with the COLIBRÍ ASU pipeline. The photometry was calibrated using nearby stars from the PanSTARRS DR1 catalog, is in the AB system, and is not corrected for Galactic extinction.\n\nIn the stacked image, we do not detect the SVOM/VT optical counterpart candidate reported by Li et al., GCN Circ. 44013 down to the following 3-sigma limit:\n\ni > 24.08\nz > 23.17\n\nWhile a direct comparison of magnitudes between the i, z filters and the VT filters is not possible, we suggest that our limits may be consistent with a fading of the VT optical candidate, which would strengthen the hypothesis that it is the true counterpart of EP260314A.\n\nWe thank the staff of the Observatorio Astronómico Nacional at Sierra de San Pedro Mártir, as well as the technical and engineering teams at CEA, CPPM, IRAP, LAM, OHP, OSU Pytheas, and UNAM.\n\nCOLIBRÍ is an astronomical observatory developed and operated jointly by France (AMU, CNES and CNRS) and Mexico (UNAM and SECIHTI). It is located at the Observatorio Astronómico Nacional on the Sierra de San Pedro Mártir, Baja California, Mexico.\n"}', 'A team of international astronomers using the COLIBRÍ telescope at the Observatorio Astronómico Nacional in Mexico conducted follow-up observations of the gamma-ray burst EP260314a. They did not detect the reported optical counterpart candidate down to the limits of i > 24.08 and z > 23.17. The non-detection may suggest that the candidate is fading, strengthening the hypothesis that it is the true counterpart.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-44018', 'gcn', 'GRB 260312B', '2026-03-15T11:40:03.000Z', '{"measurements":{"dec":null,"distance":null,"duration":11.8,"duration_error":2.3,"energy":null,"fluence":null,"magnitude":null,"other_measurements":{},"ra":null,"redshift":null,"tables":[]},"authors":{"affiliations":["GRID Collaboration","Tsinghua University"],"authors":["Fanqing Zhou","Longhao Li","Chenyu Wang"],"institutions":["GRID Collaboration"],"universities":["Tsinghua University"]},"telescopes":{"facilities":[],"instruments":[],"observatories":[],"telescopes":["Fermi GBM","MASTER-Kislovodsk","BALROG","AstroSat CZTI"]},"urls":["https://doi.org/10.1007/s10686-021-09819-4","https://mirrors.tuna.tsinghua.edu.cn/GRID/data/GRID-GCN/GRB260312B/GRID_260312B_ltcv.pdf","https://doi.org/10.1007/s10686-019-09636-w"],"basic_data":{"author":{"email":"grid@tsinghua.edu.cn","institution":"Tsinghua University","name":"GRID Student Team"},"coordinates":{},"detectionTime":"1926-03-15T11:40:03.000Z","event":"GRB 260312B","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 44018\nSUBJECT: GRID detection of GRB 260312B\nDATE: 26/03/15 11:40:03 GMT\nFROM: GRID Student Team at Tsinghua University <grid@tsinghua.edu.cn>\n\nFanqing Zhou, Longhao Li, Chenyu Wang report on behalf of the GRID Collaboration:\n\nGRID-11B reports the detection of the long-duration GRB 260312B, which was also detected by Fermi GBM (GCN Circular 43969), MASTER-Kislovodsk (GCN Circular 43973), BALROG (GCN Circular 43970), Glowbug (GCN Circular 43976), AstroSat CZTI (GCN Circular 43989).\n\nThe event was triggered with GRID on 2026-03-12 at 09:46:46 UTC. The measured burst duration (T90) in the 30-2000 keV range is approximately 11.8+/-2.3 seconds. \n\nThe GRID light curve of this event can be found at https://mirrors.tuna.tsinghua.edu.cn/GRID/data/GRID-GCN/GRB260312B/GRID_260312B_ltcv.pdf.\n\nGRID is a student-led project to monitor the transient gamma-ray sky with multiple detectors onboard different nanosatellites in the era of multi-messenger astronomy. For more information about GRID, please refer to the following references: https://doi.org/10.1007/s10686-019-09636-w and https://doi.org/10.1007/s10686-021-09819-4."}', 'GRID Collaboration at Tsinghua University reports the detection of long-duration gamma-ray burst (GRB) 260312B on March 12, 2026, with a measured burst duration of approximately 11.8 seconds ± 2.3 seconds in the 30-2000 keV range. The event was also detected by Fermi GBM, MASTER-Kislovodsk, BALROG, and AstroSat CZTI. The GRID light curve can be found online.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-44017', 'gcn', 'IceCube-260315A', '2026-03-15T11:21:27.000Z', '{"measurements":{"dec":-1.9,"distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":null,"other_measurements":{"astrophysical_neutrino_purity":30,"false_alarm_rate":3.3512},"ra":175.69,"redshift":null,"tables":[]},"authors":{"affiliations":["Ruhr University Bochum, IceCube.wisc.edu"],"authors":["A. Zegarelli"],"institutions":["IceCube Collaboration"],"universities":["Ruhr University Bochum"]},"telescopes":{"facilities":["IceCube"],"instruments":[],"observatories":["IceCube Neutrino Observatory"],"telescopes":[]},"urls":["https://gcn.gsfc.nasa.gov/notices_amon_g_b/142272_46886533.amon","http://icecube.wisc.edu/","https://gcn.nasa.gov/circulars/43419","https://gcn.nasa.gov/missions/icecube/","https://gcn.nasa.gov/missions/icecube"],"basic_data":{"author":{"email":"azegarelli@icecube.wisc.edu","institution":"Ruhr University Bochum","name":"A. Zegarelli"},"coordinates":{"dec":20,"ra":1.1182472222222222},"detectionTime":"1926-03-15T11:21:27.000Z","event":"IceCube-260315A","eventType":"EP","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 44017\nSUBJECT:  IceCube-260315A - IceCube observation of a high-energy neutrino candidate track-like event\nDATE: 26/03/15 11:21:27 GMT\nFROM: A. Zegarelli at Ruhr University Bochum <azegarelli@icecube.wisc.edu>\n\nThe IceCube Collaboration (http://icecube.wisc.edu/) reports:\n\nOn 26-03-15 at 02:19:06.60 UT IceCube detected a track-like event with a moderate probability of being of astrophysical origin. \nThe event was selected by the ICECUBE_Astrotrack_BRONZE alert stream.\nThe average astrophysical neutrino purity for Bronze alerts is 30%.\nThis alert has an estimated false alarm rate of 3.3512 events per year due to atmospheric \nbackgrounds.\nThe IceCube detector was in a normal operating state at the time of detection.\n\nAfter the initial automated alert (https://gcn.gsfc.nasa.gov/notices_amon_g_b/142272_46886533.amon), more sophisticated reconstruction algorithms have been applied offline, with the direction refined to:\n\nDate: 26-03-15\nTime: 02:19:06.60 UT\nRA: 175.69 (+0.49/-0.46 deg 90% PSF containment) J2000\nDec: -1.90 (+0.53/-0.51 deg 90% PSF containment) J2000\n\nAs announced in GCN Circular 43419 (https://gcn.nasa.gov/circulars/43419), IceCube alert notices for high-energy track alerts are now also streamed via Kafka.\nIceCube Gold/Bronze track alerts are available on the Kafka topic ''gcn.notices.icecube.gold_bronze_track_alerts''.\nThe probability distribution of the true neutrino direction, allowing the extraction of precise 90% containment regions around the best-fit direction, is now available for revised reconstruction of high-energy track alerts. \nThe corresponding sky map is distributed as a FITS file and follows the explicit naming convention IceCube-YYMMDDX, where YYMMDD indicates the date of the event and X is a letter distinguishing multiple alerts on the same day. The download link is provided through the GCN schema distributed via Kafka.\nDetailed documentation describing the alert distribution, schemas, and probability maps is available at: https://gcn.nasa.gov/missions/icecube.\n\nNo known gamma-ray sources listed in the Fermi 4FGL-DR4 or 3FHL catalogs are located within the 90% uncertainty region of this event.\n\nThe IceCube Neutrino Observatory is a cubic-kilometer neutrino detector operating at the geographic South Pole, Antarctica.\n\nThe IceCube realtime alert point of contact can be reached at roc@icecube.wisc.edu"}', 'The IceCube Neutrino Observatory at the South Pole detected a high-energy neutrino candidate event on March 26, 2015. The event, IceCube-260315A, was initially identified with a moderate probability of astrophysical origin and a false alarm rate of 3.3512 events per year. Subsequent analysis refined the direction to RA: 175.69, Dec: -1.9, with a 30% astrophysical neutrino purity. No known gamma-ray sources were found within the 90% uncertainty region. IceCube Gold/Bronze track alerts are now available via Kafka for further analysis.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6868', 'gcn', 'GRB 071010', '2007-10-10T15:13:28.000Z', '{"measurements":{"dec":-32.385,"distance":null,"duration":6,"energy":null,"fluence":2e-7,"magnitude":null,"other_measurements":{"fluence_band":"15-150 keV","partial_coding":42,"peak_flux_band":"15-150 keV","peak_photon_flux":0.8,"power_law_index":2.33},"ra":288.04,"redshift":null,"tables":[]},"authors":{"affiliations":["GSFC/USRA","GSFC","GSFC/UMBC","GSFC","GSFC/UMD","GSFC/ORAU","GSFC","LANL","GSFC/UMBC","GSFC/ISAS","GSFC/ORAU","GSFC","GWU"],"authors":["H. Krimm","S. D. Barthelmy","J. Cummings","E. Fenimore","N. Gehrels","C. Guidorzi","C. Markwardt","D. Palmer","T. Sakamoto","G. Sato","M. Stamatikos","J. Tueller","T. Ukwatta"],"institutions":["NASA/GSFC","GSFC/USRA","GSFC/UMBC","GSFC/UMD","GSFC/ORAU","LANL","GWU"],"universities":["GSFC","UMBC","UMD","ORAU","ISAS","LANL","GWU"]},"telescopes":{"facilities":[],"instruments":[],"observatories":[],"telescopes":[]},"urls":[],"basic_data":{"author":{"email":"scott@lheamail.gsfc.nasa.gov","institution":"NASA/GSFC","name":"Scott Barthelmy"},"coordinates":{},"detectionTime":"2007-10-10T15:13:28.000Z","event":"GRB 071010","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6868\nSUBJECT: GRB 071010, Swift-BAT refined analysis\nDATE: 07/10/10 15:13:28 GMT\nFROM: Scott Barthelmy at NASA/GSFC  <scott@lheamail.gsfc.nasa.gov>\n\nH. Krimm (GSFC/USRA), S. D. Barthelmy (GSFC), J. Cummings (GSFC/UMBC),\nE. Fenimore (LANL), N. Gehrels (GSFC), C. Guidorzi (U.Bicocca&INAF-OAB),\nC. Markwardt (GSFC/UMD), D. Palmer (LANL), T. Sakamoto (GSFC/UMBC),\nG. Sato (GSFC/ISAS), M. Stamatikos (GSFC/ORAU), J. Tueller (GSFC),\nT. Ukwatta (GWU)\n(i.e. the Swift-BAT team):\n \nUsing the data set from T-239 to T+394 sec from the recent telemetry downlink,\nwe report further analysis of BAT GRB 071010 (trigger #293707)\n(Moretti, et al., GCN Circ. 6859).  The BAT ground-calculated position is\nRA, Dec = 288.040, -32.385 deg  which is \n   RA(J2000)  =  19h 12m 9.7s \n   Dec(J2000) = -32d 23'' 6\" \nwith an uncertainty of 2.5 arcmin, (radius, sys+stat, 90% containment).\nThe partial coding was 42%.\n \nThe mask-weighted light curve shows a single peak starting at ~T-10 sec,\npeaking at ~T+1 sec, and ending at ~T+20 sec.\nT90 (15-350 keV) is 6 +- 1 sec (estimated error including systematics).\n \nThe time-averaged spectrum from T-1.1 to T+5.9 sec is best fit by a simple\npower-law model.  The power law index of the time-averaged spectrum is\n2.33 +- 0.37.  The fluence in the 15-150 keV band is 2.0 +- 0.4 x 10^-7 erg/cm2.\nThe 1-sec peak photon flux measured from T+0.80 sec in the 15-150 keV band\nis 0.8 +- 0.3 ph/cm2/sec.  All the quoted errors are at the 90% confidence\nlevel."}', 'The Swift-BAT team reported a refined analysis of GRB 071010 (trigger #293707), a gamma-ray burst detected by Swift. The ground-calculated position was determined with an uncertainty of 2.5 arcmin, and the light curve showed a single peak starting at ~T-10 sec, peaking at ~T+1 sec, and ending at ~T+20 sec. The time-averaged spectrum was best fit by a simple power-law model with an index of 2.33 +- 0.37, and the fluence in the 15-150 keV band was 2.0 +- 0.4 x 10^-7 erg/cm2. The 1-sec peak photon flux measured in the same band was 0.8 +- 0.3 ph/cm2/sec.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6867', 'gcn', 'GRB 071006', '2007-10-10T13:38:48.000Z', '{"measurements":{"dec":null,"distance":null,"duration":60,"energy":{"cutoff_energy":334,"cutoff_energy_error_minus":-61,"cutoff_energy_error_plus":95,"peak_flux_energy":0.00000266,"peak_flux_energy_error_minus":-0.00000151,"peak_flux_energy_error_plus":4.5e-7},"fluence":{"main_peak_fluence":0.00000852,"main_peak_fluence_error_minus":-0.00000463,"main_peak_fluence_error_plus":4.7e-7,"total_fluence":0.0000208,"total_fluence_error_minus":-0.0000125,"total_fluence_error_plus":0.0000011},"magnitude":null,"other_measurements":{"alpha":0.84,"alpha_error_minus":-0.26,"alpha_error_plus":0.22,"chi2":62.2,"degrees_of_freedom":60},"ra":null,"redshift":null,"tables":[]},"authors":{"affiliations":["Ioffe Inst, on behalf of the Konus-Wind team"],"authors":["S. Golenetskii","R. Aptekar","E. Mazets","V. Pal''shin","D. Frederiks","T. Cline"],"institutions":["Ioffe Inst"],"universities":["Ioffe Inst"]},"telescopes":{"facilities":[],"instruments":[],"observatories":[],"telescopes":["Konus-Wind"]},"urls":["http://www.ioffe.rssi.ru/LEA/GRBs/GRB071006_T24133/"],"basic_data":{"author":{"email":"val@mail.ioffe.ru","institution":"Ioffe Inst","name":"Valentin Pal''shin"},"coordinates":{},"detectionTime":"2007-10-10T13:38:48.000Z","event":"GRB 071006","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6867\nSUBJECT: Konus-Wind observation of GRB 071006\nDATE: 07/10/10 13:38:48 GMT\nFROM: Valentin Pal''shin at Ioffe Inst  <val@mail.ioffe.ru>\n\nS. Golenetskii, R.Aptekar, E. Mazets, V. Pal''shin, D. Frederiks,\nand T. Cline on behalf of the Konus-Wind team report:\n\nThe long GRB 071006 (Cummings, GCN 6858) triggered\nKonus-Wind at T0=24133.617 s UT (06:42:13.617).\n\nThe burst started at T-T0 ~35 s and had a duration of ~60 s.\nAs observed by Konus-Wind the burst\nhad a fluence of 2.08(-1.25, +0.11)x10^-5 erg/cm2,\nand a 256-ms peak flux measured from T0+1.264 s\nof 2.66(-1.51, +0.45)x10^-6 erg/cm2/s\n(both in the 20 keV - 2 MeV energy range).\n\nThe spectrum integrated over the main peak (from T0 to T0+8.448 s)\nis well fitted (in the 20 keV - 2 MeV range)\nby a power law with exponential cutoff model:\ndN/dE ~ E^(-alpha)*exp(-E*(2-alpha)/Ep)\nwith alpha = 0.84(-0.26, +0.22)\nand Ep = 334(-61, +95) keV (chi2 = 62.2/60 dof).\nThe fluence of this part is 8.52(-4.63, +0.47)x10^-6 erg/cm2.\n\nAll the quoted errors are at the 90% confidence level.\n\nThe Konus-Wind light curve of this GRB is available\nat http://www.ioffe.rssi.ru/LEA/GRBs/GRB071006_T24133/"}', 'Astronomical alert: Konus-Wind observation of GRB 071006', 0.5, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6866', 'gcn', 'GRB071008', '2007-10-10T10:37:43.000Z', '{"measurements":{"dec":[44.32071,44.34459],"distance":null,"duration":6857,"energy":null,"fluence":null,"magnitude":null,"other_measurements":{"error_circle_radius_1":6.5,"error_circle_radius_2":7.5,"observation_duration":6857,"source_distance_from_bat_position_1":116,"source_distance_from_bat_position_2":40,"time_after_trigger":57000},"ra":[151.58851,151.5534],"redshift":null,"tables":[{"column_name":"RA(J2000)","value":"10 06 21.24"},{"column_name":"Dec(J2000)","value":"+44 19 14.5"},{"column_name":"RA(J2000)","value":"10 06 12.82"},{"column_name":"Dec(J2000)","value":"+44 20 40.5"}]},"authors":{"affiliations":["INAF-OAB","Univ. Bicocca & INAF-OAB"],"authors":["A. Moretti","C. Guidorzi","P. Romano"],"institutions":["Univ. Bicocca","INAF-OAB","Swift-XRT team"],"universities":["Univ. Bicocca","INAF-OAB"]},"telescopes":{"facilities":[],"instruments":["Swift-XRT"],"observatories":[],"telescopes":[]},"urls":["https://gcn.gsfc.nasa.gov/gcn3/gcn3_circulars.cfm?id=6866"],"basic_data":{"author":{"email":"alberto.moretti@brera.inaf.it","institution":"Obs Brera Merate","name":"Alberto Moretti"},"coordinates":{"dec":10.1059,"ra":44.32069444444445},"detectionTime":"2007-10-10T10:37:43.000Z","event":"GRB071008","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6866\nSUBJECT: GRB071008: Swift-XRT observation\nDATE: 07/10/10 10:37:43 GMT\nFROM: Alberto Moretti at Obs Brera Merate  <alberto.moretti@brera.inaf.it>\n\nA. Moretti (INAF-OAB), C. Guidorzi (Univ. Bicocca & INAF-OAB),\nP. Romano (Univ. Bicocca & INAF-OAB), report on behalf of the\nSwift-XRT team:\n\nSwift XRT observed the GRB 071008 (trigger=293587, Moretti et al., GCN\nCirc. 6856) beginning 57 ks after the BAT trigger.  In 6857s of Photon\nCounting mode data spanning 57-65 ks after the trigger in the BAT\nerror circle we found 2 faint sources at RA,Dec =151.58851,44.32071\nand RA,Dec =151.55340, 44.34459 which are\n\nRA(J2000) = 10 06 21.24  Dec(J2000)= +44 19 14.5\nRA(J2000) = 10 06 12.82  Dec(J2000)= +44 20 40.5\n\nwith error circles of radius 6.5 and 7.5 arcseconds (90%, including\nboresight uncertainties) respectively.\n\nThey are at 116 and 40 arcseconds from the BAT position, respectively.\nAt present, due to the paucity of the observed events, we are unable\nto determine whether these sources are fading.  Further observations\nwill be planned when the distance to the Sun will be larger.\n\n\nThis circular is an official product of the Swift-XRT team."}', 'The Swift-XRT team reported observing two faint sources, RA(J2000) = 10 06 21.24 Dec(J2000) = +44 19 14.5 and RA(J2000) = 10 06 12.82 Dec(J2000) = +44 20 40.5, at approximately 57 ks after the BAT trigger for GRB 071008. The sources, with error circles of 6.5 and 7.5 arcseconds, are located 116 and 40 arcseconds from the BAT position, respectively. The team is unable to determine if these sources are fading and plans further observations when the distance to the Sun is larger.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6865', 'gcn', 'GRB 071010', '2007-10-10T08:04:22.000Z', '{"measurements":{"dec":null,"distance":null,"duration":"30 minutes","energy":null,"fluence":null,"magnitude":14.3,"other_measurements":{"observation_start_time":"03:42:52 UT","time_after_burst":"100 sec"},"ra":null,"redshift":null,"tables":[]},"authors":{"affiliations":["INAF-OAB"],"authors":["Paolo D''Avanzo","D. Fugazza","S. Covino","L.A. Antonelli","L. Calzoletti","S. Campana","G. Chincarini","M.L. Conciatore","S. Cutini","V. D''Elia","F. Dalessio","F. Fiore","P. Goldoni","D. Guetta","C. Guidorzi","G.L. Israel","N. Masetti","A. Melandri","E. Meurs","L. Nicastro","E. Palazzi","E. Pian","S. Piranomonte","L. Stella","G. Stratta","G. Tagliaferri","G. Tosti","V. Testa","S.D. Vergani","F. Vitali"],"institutions":["INAF"],"universities":["INAF-OAB"]},"telescopes":{"facilities":[],"instruments":[],"observatories":["La Silla"],"telescopes":["REM","60-cm REM telescope"]},"urls":["https://ui.adsabs.harvard.edu/abs/2007GCN..6862....1H/abstract","https://gcn.gsfc.nasa.gov/gcn3/gcn3_search.msfc","https://ui.adsabs.harvard.edu/abs/2007GCN..6859....1M/abstract","https://ui.adsabs.harvard.edu/abs/2007GCN..6860....1K/abstract","https://ui.adsabs.harvard.edu/abs/2007GCN..6861....1B/abstract"],"basic_data":{"author":{"email":"paolo.davanzo@brera.inaf.it","institution":"INAF-OAB","name":"Paolo D''Avanzo"},"coordinates":{},"detectionTime":"2007-10-10T08:04:22.000Z","event":"GRB 071010","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6865\nSUBJECT: GRB 071010 REM NIR observations\nDATE: 07/10/10 08:04:22 GMT\nFROM: Paolo D''Avanzo at INAF-OAB  <paolo.davanzo@brera.inaf.it>\n\nP. D''Avanzo, D. Fugazza, S. Covino, L.A. Antonelli, L. Calzoletti, S. \nCampana, G.  Chincarini, M.L. Conciatore, S. Cutini, V. D''Elia, F. \nDalessio, F.  Fiore, P. Goldoni, D. Guetta,  C. Guidorzi, G.L. Israel, \nN. Masetti, A. Melandri, E. Meurs, L. Nicastro, E. Palazzi, E. Pian, S. \nPiranomonte, L.  Stella, G.  Stratta, G. Tagliaferri, G. Tosti, V. \nTesta, S.D. Vergani,  F. Vitali   report on behalf of the REM team:\n\nWe observed the field of the GRB 071010 (Moretti et al., GCN 6859)  with \nthe robotic 60-cm REM telescope located at La Silla (Chile). A set of \nobservations was performed automatically in the Z, J, H, K NIR filters \nstarting at 03:42:52 UT (about 100 sec after the burst) and lasted about \n30 minutes due to visibility constraints.\n\nThe analysis of the first set of H-band exposures clearly show the \noptical afterglow candidate reported by Klotz et al. (GCN 6860), Bloom \net al. (GCN. 6861), Haislip et al. (GCN. 6862) at a level of H =14.3 � \n0.2 (calibrated against the 2MASS catalog). The afterglow is clearly \ndetected in all bands.\n\nFuther analysis is in progress."}', 'The REM team reported the detection of the optical afterglow of GRB 071010 using the 60-cm REM telescope at La Silla, Chile. The afterglow was observed in the Z, J, H, and K NIR filters starting 100 seconds after the burst and lasted for 30 minutes. The afterglow was detected at a magnitude of H = 14.3 ± 0.2 in the H-band, and further analysis is ongoing.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6864', 'gcn', 'GRB 071010', '2007-10-10T07:56:39.000Z', '{"measurements":{"dec":null,"distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":null,"other_measurements":{"exposure_duration":"900s"},"ra":null,"redshift":0.98,"tables":[]},"authors":{"affiliations":["UCSC","UC Berkeley","U Chicago"],"authors":["Jason X. Prochaska","D. A. Perley","M. Modjaz","J.S. Bloom","D. Poznanski"],"institutions":["UCO/Lick Obs"],"universities":["UCSC","UC Berkeley","U Chicago"]},"telescopes":{"facilities":[],"instruments":["LRIS"],"observatories":["Lick Observatory"],"telescopes":["Keck","LRIS"]},"urls":[],"basic_data":{"author":{"email":"xavier@ucolick.org","institution":"UCO/Lick Obs","name":"Jason Prochaska"},"coordinates":{},"detectionTime":"2007-10-10T07:56:39.000Z","event":"GRB 071010","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6864\nSUBJECT: GRB 071010: Keck/LRIS Spectroscopy\nDATE: 07/10/10 07:56:39 GMT\nFROM: Jason Prochaska at UCO/Lick Obs  <xavier@ucolick.org>\n\nJason X. Prochaska (UCSC), D. A. Perley, M. Modjaz, J.S. Bloom,\nD. Poznanski (UC Berkeley), H.-W. Chen (U Chicago), report on behalf  \nof GRAASP:\n\n\"We observed the afterglow of GRB 071010 with the LRIS\ndual spectrometer for a series of 900s exposures starting\nat UT 05:00 under good conditions.  Analysis of the blue side\nreveals a strong MgII absorber and corresponding FeII lines\nat z=0.98.  The absence of strong features in the spectrum\nredward of 5700A suggests this is the redshift of\nthe GRB.  A more conservative upper limit is placed by\nthe absence of IGM signatures at 3400A which\nindicates z_GRB < 1.8.\n\nFurther analysis is in progress.\"\n\n\nThis GCN may be cited."}', 'Astronomers led by Jason Prochaska at UCSC report the discovery of a strong MgII absorber and corresponding FeII lines at redshift 0.98 in the afterglow spectrum of GRB 071010, observed with the Keck/LRIS spectrometer. This suggests the GRB is at a distance of approximately 11 billion light-years. Further analysis is ongoing.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6863', 'gcn', 'GRB 071010', '2007-10-10T07:35:34.000Z', '{"measurements":{"dec":null,"distance":null,"duration":{"fall_duration":90,"rise_duration":470},"energy":null,"fluence":null,"magnitude":17,"other_measurements":{"brightness_rate_fall":0.8,"brightness_rate_rise":-0.9,"final_brightness":19.1,"time_of_rise_peak":470,"uncertainty_brightness_rate_fall":0.1,"uncertainty_brightness_rate_rise":0.5,"uncertainty_time_of_rise_peak":60},"ra":null,"redshift":"<2","tables":[]},"authors":{"affiliations":["CESR-OMP","OHP","LATT-OMP"],"authors":["Klotz, A.","Boer, M.","Atteia, J.L."],"institutions":["CESR-OMP","OHP","LATT-OMP"],"universities":["CESR-CNRS","OHP","LATT-OMP"]},"telescopes":{"facilities":[],"instruments":[],"observatories":["La Silla observatory"],"telescopes":["TAROT"]},"urls":[],"basic_data":{"author":{"email":"Alain.Klotz@free.fr","institution":"CESR-CNRS","name":"Alain Klotz"},"coordinates":{},"detectionTime":"2007-10-10T07:35:34.000Z","event":"GRB 071010","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6863\nSUBJECT: GRB 071010: TAROT La Silla observatory photometry of the afterglow\nDATE: 07/10/10 07:35:34 GMT\nFROM: Alain Klotz at CESR-CNRS  <Alain.Klotz@free.fr>\n\nKlotz, A. (CESR-OMP), Boer M. (OHP), Atteia J.L. (LATT-OMP) report:\n\nWe derived accurate photometry of the afterglow\nof GRB 071010 (cf. Klotz et al. GCNC 6860) from\nTAROT, R and unfiltered images. We converted unfiltered\nmagnitudes into R band using a simple offset\nassuming a low redshift (z<2) and a continuum\nspectrum as described by Bloom et al. (GCNC 6861).\n\nThe afterglow is fainter than previously annonced\nin GCNC 6860. We observed a rise of brightness\nat a rate alpha=-0.9 (+/-0.5) until\nabout 470s after the trigger (+/-60s)\nwith a maximum brightness R=17.0.\n\nThen the afterglow has decreased at a rate\nalpha=+0.8 (+/-0.1) until at less 90 minutes\nafter the trigger (R=19.1 at t_trig+90min).\nObservations are now finished in Chile due to\nthe set of the GRB.\n\nThis message may be cited.."}', 'Astronomers using the TAROT telescope at La Silla observatory have reported new observations of the afterglow of GRB 071010. The afterglow was found to be fainter than previously announced and exhibited a rise in brightness with a rate of -0.9 (+/-0.5) until approximately 470 seconds after the trigger, peaking at R=17.0. The afterglow then decreased at a rate of +0.8 (+/-0.1) and was last observed at R=19.1 at 90 minutes after the trigger.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6862', 'gcn', 'GRB 071010', '2007-10-10T06:45:21.000Z', '{"measurements":{"dec":null,"distance":null,"duration":2.6,"energy":null,"fluence":null,"magnitude":17.5,"other_measurements":{"observation_start_time_after_burst":"90 seconds","observation_start_time_after_notification":"35 seconds"},"ra":null,"redshift":null,"tables":[]},"authors":{"affiliations":["U.North Carolina","CTIO"],"authors":["J. Haislip","D. Reichart","M. Nysewander","A. LaCluyze","K. Ivarsen","J. A. Crain","A. Foster","M. Schubel","J. Styblova","T. Brennan","A. Trotter"],"institutions":["CTIO (Cerro Tololo Inter-American Observatory)"],"universities":["University of North Carolina"]},"telescopes":{"facilities":[],"instruments":[],"observatories":["CTIO (Cerro Tololo Inter-American Observatory)"],"telescopes":["three of the 16\" PROMPT telescopes"]},"urls":["http://gcn.gsfc.nasa.gov"],"basic_data":{"author":{"email":"haislip@physics.unc.edu","institution":"U.North Carolina","name":"Josh Haislip"},"coordinates":{},"detectionTime":"2007-10-10T06:45:21.000Z","event":"GRB 071010","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6862\nSUBJECT: GRB 071010: Rapid PROMPT Detections\nDATE: 07/10/10 06:45:21 GMT\nFROM: Josh Haislip at U.North Carolina  <haislip@physics.unc.edu>\n\nJ. Haislip, D. Reichart, M. Nysewander, A. LaCluyze, K. Ivarsen, J. A. \nCrain, A. Foster, M. Schubel, J. Styblova, T. Brennan, and A. Trotter \nreport:\n\nSkynet observed the localization of GRB 071010 (Moretti et al., GCN 6859) \nwith three of the 16\" PROMPT telescopes at CTIO beginning 90 seconds after \nthe burst (35 seconds after notification) in BVRI.\n\nWe detect the afterglow (Klotz et al., GCN 6860) in all filters.  At 2.6 \nminutes after the burst, we measure I ~ 17.5 mag."}', 'GRB 071010: Three 16" PROMPT telescopes at CTIO detected the afterglow of the gamma-ray burst 90 seconds after it occurred, measuring a magnitude of 17.5 at 2.6 minutes post-burst.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6861', 'gcn', 'GRB 071010', '2007-10-10T05:37:15.000Z', '{"measurements":{"dec":"-32:24:07.16","distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":"20 - 21 mag","other_measurements":{"offset_north":"11.49\"","offset_west":"31.62\""},"ra":"19:12:14.624","redshift":null,"tables":[]},"authors":{"affiliations":["UC Berkeley","U Chicago","UCSC"],"authors":["J. S. Bloom","D. A. Perley","M. Modjaz","D. Poznanski","H.- W. Chen","J. X. Prochaska"],"institutions":["UC Berkeley","UC Chicago","UCSC"],"universities":["UC Berkeley","U Chicago","UCSC"]},"telescopes":{"facilities":[],"instruments":["LRIS"],"observatories":["Keck Observatory"],"telescopes":["Keck I"]},"urls":[],"basic_data":{"author":{"email":"jbloom@astron.berkeley.edu","institution":"UC Berkeley","name":"Josh Bloom"},"coordinates":{"dec":19.204062222222223},"detectionTime":"2007-10-10T05:37:15.000Z","event":"GRB 071010","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6861\nSUBJECT: GRB 071010: Keck Observations of the Afterglow\nDATE: 07/10/10 05:37:15 GMT\nFROM: Josh Bloom at UC Berkeley  <jbloom@astron.berkeley.edu>\n\nJ. S. Bloom, D. A. Perley, M. Modjaz, D. Poznanski (UC Berkeley), H.- \nW. Chen (U Chicago), and J. X. Prochaska (UCSC) report:\n\n\"We have conducted preliminary imaging with the Keck I telescope  \n(+LRIS) of the afterglow seen in TAROT (Klotz et al. GCN 6860) of GRB  \n071010 (Moretti et al. 6859). In the first set of short exposures  \n(~100 sec) in R and G bands (starting at 04:48:34 UT) we detect a  \nsource near that position with a magnitude comparable to the faintest  \ndetectable DSS sources (corresponding to R~20 - 21 mag). We report a  \nrefined position (+/- 300 mas relative to USNO B1.0):\n\n       ra= 19:12:14.624 dec= -32:24:07.16 J2000\n\nThe offset from the star at 19:12:17.121, -32:24:18.65 to the  \nafterglow is 31.62\" W, 11.49 \"N. Spectroscopy is underway and reports  \nfrom that analysis are forthcoming (the continuum is detected to the  \natmospheric cutoff in the blue, implying z<~2).\"\n\nThis message may be cited.\n\nWe thank A. Klotz for helpful conversations regarding the TAROT  \nafterglow detection."}', 'A team of astronomers led by UC Berkeley''s J. S. Bloom reported the detection of the afterglow of GRB 071010 using the Keck I telescope. The afterglow, located near the position reported by the TAROT team, was detected as a source with a magnitude comparable to the faintest detectable DSS sources, roughly R~20 - 21 mag. The team also provided a refined position and measured an offset of 31.62'''' W and 11.49'''' N from a nearby star. Spectroscopy is ongoing to determine the redshift and other properties of the afterglow.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6860', 'gcn', 'GRB 071010', '2007-10-10T04:09:00.000Z', '{"measurements":{"dec":"-32d 24'' 07.1\"","distance":null,"duration":124.7,"energy":null,"fluence":null,"magnitude":15.6,"other_measurements":{"elevation_of_field":"26 degrees","galactic_extinction_in_R_band":"1.3 magnitudes","observation_start_time_after_notice":"70.5s","observation_start_time_after_trigger":"124.7s"},"ra":"19h 12m 14.73s","redshift":null,"tables":[]},"authors":{"affiliations":["CESR-OMP","OHP","LATT-OMP"],"authors":["Alain Klotz"],"institutions":["CESR-CNRS","OHP","LATT-OMP"],"universities":["CNRS","OMP"]},"telescopes":{"facilities":[],"instruments":[],"observatories":["European Southern Observatory","La Silla observatory"],"telescopes":["TAROT"]},"urls":["http://www.swift.ac.uk/gcn3/293707.html"],"basic_data":{"author":{"email":"Alain.Klotz@free.fr","institution":"CESR-CNRS","name":"Alain Klotz"},"coordinates":{},"detectionTime":"2007-10-10T04:09:00.000Z","event":"GRB 071010","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6860\nSUBJECT: GRB 071010: TAROT La Silla observatory detection of the afterglow\nDATE: 07/10/10 04:09:00 GMT\nFROM: Alain Klotz at CESR-CNRS  <Alain.Klotz@free.fr>\n\nKlotz, A. (CESR-OMP), Boer M. (OHP), Atteia J.L. (LATT-OMP) report:\n\nWe imaged the field of GRB 071010 detected by SWIFT\n(trigger 293707) with the TAROT robotic telescope (D=25cm)\nlocated at the European Southern Observatory,\nLa Silla observatory, Chile.\n\nThe observations started 124.7s after the GRB trigger\n(70.5s after the notice). The elevation of the field decreased from\nfrom 26 degrees above horizon and weather conditions\nwere good.\n\nWe detect a new rsising source in the error box given by SWIFT\nat the following position (+/- 3 arcsec):\n\nRA(J2000.0) = 19h 12m 14.73s\nDEC(J2000.0) = -32d 24'' 07.1\"\n\nOT was R~15.6 at ~400s after GRB.\n\nWe continue to observe.\n\nMagnitudes were estimated with the nearby USNO-B1 stars\nand are not corrected for galactic dust extinction.\n\nN.B. Galactic coordinates are lon=  5.2380 lat=-18.2310\nand the galactic extinction in R band is 1.3 magnitudes\nestimated from D. Schlegel et al. 1998ApJ...500..525S.\n\nThis message may be cited."}', 'The TAROT robotic telescope at La Silla observatory in Chile detected a new source in the error box of the gamma-ray burst (GRB) 071010, observed by SWIFT, 124.7 seconds after the trigger. The source, located at RA(J2000.0) = 19h 12m 14.73s, DEC(J2000.0) = -32d 24'' 07.1', 0.9, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-686', 'gcn', 'GRB000528', '2000-06-02T23:12:58.000Z', '{"measurements":{"dec":null,"distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":null,"other_measurements":{"flux_limit":"0.14 mJy","frequency":"8.46 GHz","region_size":"1.5''","sigma_level":"3.5 sigma"},"ra":null,"redshift":null,"tables":[]},"authors":{"affiliations":["Caltech (ejb@astro.caltech.edu)","NRAO"],"authors":["Edo Berger","D. A. Frail"],"institutions":["Caltech","NRAO"],"universities":["Caltech"]},"telescopes":{"facilities":[],"instruments":[],"observatories":["NRAO"],"telescopes":["VLA"]},"urls":["https://gcn.gsfc.nasa.gov"],"basic_data":{"author":{"email":"ejb@astro.caltech.edu","institution":"Caltech","name":"Edo Berger"},"coordinates":{},"detectionTime":"2000-06-02T23:12:58.000Z","event":"GRB000528","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 686\nSUBJECT: GRB000528, Radio Observations\nDATE: 00/06/02 23:12:58 GMT\nFROM: Edo Berger at Caltech  <ejb@astro.caltech.edu>\n\nE. Berger (Caltech) and D. A. Frail (NRAO) report on behalf of a\nlarger collaboration:\n \n\"On June 1.11 UT we used the VLA at 8.46 GHz to observe the field centered\non the refined position provided by the SAX WFC (GCN 677).  There are no\nobvious radio candidates brighter than 0.14 mJy (3.5 sigma) inside the\n1.5'' region centered on object #2, which was identified by the SAX NFI\n(GCN 683). The 1.5'' region centered on object #1 contains one bright\nsource which is also present in the NRAO VLA Sky Survey (NVSS).  Further\nobservations are planned\"\n \nThis message may be cited."}', 'On June 1, 2002, a team led by Edo Berger at Caltech and D. A. Frail from NRAO used the VLA telescope to search for radio emission from the location of a gamma-ray burst (GRB000528) detected by SAX WFC. No significant radio sources were found within a 1.5'' region around the second identified object, but a bright source was detected outside this region which is present in the NRAO VLA Sky Survey. Further observations are planned.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6859', 'gcn', 'GRB 071010', '2007-10-10T03:56:03.000Z', '{"measurements":{"dec":"-32d 22'' 42\"","distance":null,"duration":"30 sec","energy":null,"fluence":null,"magnitude":null,"other_measurements":{"peak_count_rate":"~600 counts/sec (15-350 keV)","uncertainty_radius":"3 arcmin"},"ra":"19h 12m 24s","redshift":null,"tables":[]},"authors":{"affiliations":["LANL","GSFC/UMBC","NASA/GSFC","CRESST/USRA/GSFC","LANL","NASA/ORAU","GSFC/GWU"],"authors":["A. Moretti","W. H. Baumgartner","N. Gehrels","S. T. Holland","D. M. Palmer","M. Stamatikos","T. N. Ukwatta"],"institutions":["LANL","GSFC/UMBC","NASA/GSFC","CRESST/USRA","GSFC/GWU","MI/astro.it"],"universities":["LANL","NASA/GSFC","UMBC","CRESST/USRA","GSFC","GWU","MI/astro.it"]},"telescopes":{"facilities":[],"instruments":[],"observatories":[],"telescopes":["Swift Burst Alert Telescope (BAT)"]},"urls":["http://www.swift.psu.edu/too.html"],"basic_data":{"author":{"email":"palmer@lanl.gov","institution":"LANL","name":"David Palmer"},"coordinates":{"dec":2.135583611111111},"detectionTime":"2007-10-10T03:56:03.000Z","event":"GRB 071010","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6859\nSUBJECT: GRB 071010: Swift detection of a burst\nDATE: 07/10/10 03:56:03 GMT\nFROM: David Palmer at LANL  <palmer@lanl.gov>\n\nA. Moretti (INAF-OAB), W. H. Baumgartner (GSFC/UMBC),\nN. Gehrels (NASA/GSFC), S. T. Holland (CRESST/USRA/GSFC),\nD. M. Palmer (LANL), M. Stamatikos (NASA/ORAU) and\nT. N. Ukwatta (GSFC/GWU) report on behalf of the Swift Team:\n\nAt 03:41:12 UT, the Swift Burst Alert Telescope (BAT) triggered and\nlocated GRB 071010 (trigger=293707). \nThe BAT on-board calculated location is \nRA, Dec 288.101, -32.379 which is \n   RA(J2000) = 19h 12m 24s\n   Dec(J2000) = -32d 22'' 42\"\nwith an uncertainty of 3 arcmin (radius, 90% containment, including \nsystematic uncertainty).  The BAT light curve showed a broad\nstructure with a duration of about 30 sec.  The peak count rate\nwas ~600 counts/sec (15-350 keV), at ~2 sec after the trigger. \n\nBecause Swift is in the process of returning to normal operations, \nautomatic slewing to GRBs is currently disabled outside of\nbusiness hours (US EDT).  Therefore, there \nare no prompt XRT or UVOT observations of this burst. \n\nBurst Advocate for this burst is A. Moretti (moretti AT merate.mi.astro.it). \nPlease contact the BA by email if you require additional information\nregarding Swift followup of this burst. In extremely urgent cases, after\ntrying the Burst Advocate, you can contact the Swift PI by phone (see\nSwift TOO web site for information: http://www.swift.psu.edu/too.html.)"}', 'The Swift Burst Alert Telescope (BAT) detected a gamma-ray burst (GRB 071010) at 03:41:12 UT with a location of RA: 19h 12m 24s, Dec: -32d 22'' 42'''' and a duration of about 30 seconds. The peak count rate was ~600 counts/sec (15-350 keV). Swift is currently returning to normal operations and no prompt XRT or UVOT observations were made.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6858', 'gcn', 'GRB 071006', '2007-10-10T02:18:52.000Z', '{"measurements":{"dec":"-23d 09'' 14\"","distance":null,"duration":"80 sec","energy":null,"fluence":null,"magnitude":null,"other_measurements":{},"ra":"22h 21m 07s","redshift":null,"tables":[]},"authors":{"affiliations":["Swift-BAT team","CRESST/NASA/GSFC"],"authors":["J. R. Cummings"],"institutions":["NASA/GSFC","CRESST"],"universities":["NASA/GSFC"]},"telescopes":{"facilities":[],"instruments":[],"observatories":[],"telescopes":["Swift Burst Alert Telescope (BAT)"]},"urls":[""],"basic_data":{"author":{"email":"jayc@milkyway.gsfc.nasa.gov","institution":"NASA/GSFC/Swift","name":"Jay R. Cummings"},"coordinates":{"dec":3.051467222222222},"detectionTime":"2007-10-10T02:18:52.000Z","event":"GRB 071006","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6858\nSUBJECT: GRB 071006 Swift-BAT detection of a burst\nDATE: 07/10/10 02:18:52 GMT\nFROM: Jay R. Cummings at NASA/GSFC/Swift  <jayc@milkyway.gsfc.nasa.gov>\n\nJ. R. Cummings (CRESST/NASA/GSFC) for the Swift-BAT team\n\nAt 06:41:40 UT on October 6, the Swift Burst Alert Telescope (BAT)\ntriggered on GRB 071006. The burst began just before a preplanned\nslew, and no source was found automatically onboard. A source was \nfound during later ground analysis, at a location of \nRA, Dec 335.282, -23.154, which is\n   RA(J2000)  =  22h 21m 07s\n   Dec(J2000) = -23d 09'' 14\"\nwith an uncertainty of 2 arcmin (radius, 90% containment, including\nsystematic uncertainty). The BAT light curve shows two small peaks\non top of a gradual rise to a large peak at T+32 sec. The total\nduration is about 80 sec. The spectrum appears to be of average\nhardness for a long GRB.\n\nBecause the burst was detected on the ground, there are no prompt\nXRT data. We have requested a TOO to observe this burst on\nOctober 10."}', 'The Swift Burst Alert Telescope (BAT) detected a new gamma-ray burst (GRB 071006) on October 6, 2010. The burst occurred at RA 22h 21m 07s, Dec -23d 09'' 14'''' (J2000), with a duration of approximately 80 seconds and an uncertainty of 2 arcmin. The light curve shows two small peaks and a gradual rise to a large peak at T+32 sec. No X-ray data were obtained promptly, but a request for observation has been made.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6857', 'gcn', 'GRB071008', '2007-10-09T17:15:01.000Z', '{"measurements":{"dec":null,"distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":{"R":21.5},"other_measurements":{"observation_start_time":"05:43 UT","time_after_grb":"7.8 hours"},"ra":null,"redshift":null,"tables":[]},"authors":{"affiliations":["Inst.Astrophys.Andalucia, Granada","AIP Potsdam"],"authors":["Martin Jelinek","Alberto J. Castro-Tirado","Javier Gorosabel","R. Piontek"],"institutions":["Instituto de Astrofisica de Andalucia (IAA)"],"universities":["University of Granada (IAA-CSIC)"]},"telescopes":{"facilities":[],"instruments":[],"observatories":["La Palma"],"telescopes":["IAC 80cm telescope"]},"urls":["https://gcn.gsfc.nasa.gov/gcn3/gcn3_circulars.html?id=6856"],"basic_data":{"author":{"email":"mates@iaa.es","institution":"Inst.Astrophys.Andalucia,Granada","name":"Martin Jelinek"},"coordinates":{},"detectionTime":"2007-10-09T17:15:01.000Z","event":"GRB071008","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6857\nSUBJECT: GRB071008: IAC80 observation\nDATE: 07/10/09 17:15:01 GMT\nFROM: Martin Jelinek at Inst.Astrophys.Andalucia,Granada  <mates@iaa.es>\n\nMartin Jelinek,  Alberto J. Castro-Tirado,  Javier Gorosabel\n(IAA-CSIC Granada)  and  R. Piontek (AIP Potsdam)  report on\nbehalf of larger collaboration:\n\nWe   observed  the  Swift-BAT  errorbox  of   a  GRB  071008\n(trigger=293587, Moretti et al., GCN 6856), with an IAC 80cm\ntelescope at La Palma starting at  05:43 UT  (7.8h after the\nGRB). Our 3 x 180s  combined  R-band  image has  a  limiting\nmagnitude of R < 21.5  and does  not show any  new source in\ncomparison to a DSS-Red, implying  a DSS-equivalent limit to\nthe afterglow detection."}', 'A team of astronomers led by Martin Jelinek and colleagues observed the error box of GRB071008 (a gamma-ray burst) using the IAC 80cm telescope at La Palma. They did not detect any new source in their R-band image, which has a limiting magnitude of R < 21.5, implying no afterglow detection.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6856', 'gcn', 'GRB 071008', '2007-10-08T22:04:30.000Z', '{"measurements":{"dec":"+44d 20'' 02\"","distance":null,"duration":"15 sec","energy":null,"fluence":null,"magnitude":null,"other_measurements":{"peak_count_rate":"~1000 counts/sec (15-350 keV)","time_of_peak_count_rate":"~1 sec"},"ra":"10h 06m 11s","redshift":null,"tables":[]},"authors":{"affiliations":["INAF-OAB","PSU","NASA/GSFC","CRESST/USRA/GSFC","NASA/ORAU","GSFC/GWU","NASA/GSFC","LANL"],"authors":["A. Moretti","S. D. Barthelmy","D. N. Burrows","N. Gehrels","S. T. Holland","V. Mangano","F. E. Marshall","D. M. Palmer","M. Stamatikos","T. N. Ukwatta"],"institutions":["INAF-OAB","PSU","NASA/GSFC","CRESST/USRA/GSFC","NASA/ORAU"],"universities":["INAF-OAB","PSU","NASA/GSFC","CRESST/USRA/GSFC","NASA/ORAU","GSFC/GWU"]},"telescopes":{"facilities":[],"instruments":[],"observatories":[],"telescopes":["Swift Burst Alert Telescope (BAT)"]},"urls":["http://www.swift.psu.edu/too.html"],"basic_data":{"author":{"email":"scott@lheamail.gsfc.nasa.gov","institution":"NASA/GSFC","name":"Scott Barthelmy"},"coordinates":{"dec":1.0837633333333332},"detectionTime":"2007-10-08T22:04:30.000Z","event":"GRB 071008","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6856\nSUBJECT: GRB 071008: Swift detection of a burst\nDATE: 07/10/08 22:04:30 GMT\nFROM: Scott Barthelmy at NASA/GSFC  <scott@lheamail.gsfc.nasa.gov>\n\nA. Moretti (INAF-OAB), S. D. Barthelmy (GSFC), D. N. Burrows (PSU),\nN. Gehrels (NASA/GSFC), S. T. Holland (CRESST/USRA/GSFC),\nV. Mangano (INAF-IASFPA), F. E. Marshall (NASA/GSFC),\nD. M. Palmer (LANL), M. Stamatikos (NASA/ORAU) and\nT. N. Ukwatta (GSFC/GWU) report on behalf of the Swift Team:\n\nAt 21:55:56 UT, the Swift Burst Alert Telescope (BAT) triggered and\nlocated GRB 071008 (trigger=293587). \nThe BAT on-board calculated location is \nRA, Dec 151.548, +44.334 which is \n   RA(J2000)  =  10h 06m 11s\n   Dec(J2000) = +44d 20'' 02\"\nwith an uncertainty of 3 arcmin (radius, 90% containment, including \nsystematic uncertainty).  The BAT light curve shows a single peak\nwith a duration of about 15 sec.  The peak count rate\nwas ~1000 counts/sec (15-350 keV), at ~1 sec after the trigger. \n\nBecause Swift is in the process of returning to normal operations, \nautomatic slewing to GRBs is currently disabled outside of\nbusiness hours (US EDT).  Therefore, there \nare no prompt XRT or UVOT observations of this burst. \n\nBurst Advocate for this burst is A. Moretti (moretti AT merate.mi.astro.it). \nPlease contact the BA by email if you require additional information\nregarding Swift followup of this burst. In extremely urgent cases, after\ntrying the Burst Advocate, you can contact the Swift PI by phone (see\nSwift TOO web site for information: http://www.swift.psu.edu/too.html.)"}', 'The Swift Burst Alert Telescope (BAT) detected a gamma-ray burst (GRB 071008) with a trigger time of 21:55:56 UT, location RA 10h 06m 11s, Dec +44d 20'' 02', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6855', 'gcn', 'GRB 071003', '2007-10-06T16:01:59.000Z', '{"measurements":{"dec":null,"distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":null,"other_measurements":{},"ra":null,"redshift":null},"authors":{"affiliations":["U. Leicester","MSSL/UCL"],"authors":["R. Starling","P.A. Evans","K.L. Page","A.P. Beardmore","P. Schady"],"institutions":["U of Leicester","MSSL/UCL"],"universities":["University of Leicester"]},"telescopes":{"facilities":[],"instruments":[],"observatories":[],"telescopes":[]},"urls":["http://gcn.gsfc.nasa.gov"],"basic_data":{"author":{"email":"rlcs1@star.le.ac.uk","institution":"U of Leicester","name":"Rhaana Starling"},"coordinates":{},"detectionTime":"2007-10-06T16:01:59.000Z","event":"GRB 071003","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6855\nSUBJECT: GRB 071003: XRT refined analysis\nDATE: 07/10/06 16:01:59 GMT\nFROM: Rhaana Starling at U of Leicester  <rlcs1@star.le.ac.uk>\n\nR. Starling, P.A. Evans, K.L. Page, A.P. Beardmore (U. Leicester) and P. \nSchady (MSSL/UCL) report on behalf of the Swift team:\n\nWe report on Swift XRT observations of the GRB 071003 (trigger=292934,\nSchady et al., GCN  Circ. 6837) beginning 22.3 ks and ending 244 ks after\nthe BAT trigger, totalling 29.6 ks of photon counting mode data.\n\nWe refine the position given in Starling and Schady, GCN Circ. 6845, to\nRA,Dec(J2000) = 301.85090, 10.947225 deg, equivalent to:\nRA(J2000) =  20h 07m 24.22s\nDec(J2000)= +10d 56'' 50.0\"\nwith an error of radius 5.5 arcseconds (90%, including boresight\nuncertainties). This is 1.3 arcseconds away from the initial XRT position \nand 2.3 arcseconds from the optical transient (Li, GCN Circ. 6838).\n\nThe light curve is best fit with a broken power law with initial decay\nslope of alpha_1 = 1.0(+0.2/-0.4), T_bk = 3.9(+0.8/-0.4)E4 s and \nalpha_2 = 1.8(+/-0.4).\n\nThe spectrum can be modelled with a power law of photon index Gamma =\n2.1(+/-0.2) with fixed Galactic absorption of nH = 1.4E21 cm^-2 and\nallowing for intrinsic absorption at z = 1.1 (lower limit from Perley et\nal., GCN Circ. 6850) which we find is consistent with zero.\nThe mean observed (unabsorbed) 0.3-10 keV flux is 7E-13 (1E-12) \nerg/cm^2/s.\nThe count to flux conversion from these data is approximately 1 ct/s =\n4.7E-11 erg/cm^2/s.\n      \nThis is an official product of the Swift XRT team."}', 'Swift XRT team reports refined position, light curve, and spectrum analysis for GRB 071003 (trigger=292934). The position is refined to RA(J2000) = 20h 07m 24.22s, Dec(J2000) = +10d 56'' 50.0', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6854', 'gcn', 'GRB070920A', '2007-10-06T08:21:21.000Z', '{"measurements":{"dec":null,"distance":null,"duration":36,"energy":[{"unit":"GeV","value":225},{"unit":"GeV","value":300},{"unit":"GeV","value":400},{"unit":"GeV","value":1000},{"unit":"TeV","value":1},{"unit":"TeV","value":10}],"fluence":null,"magnitude":null,"other_measurements":{"Data Taking Start Time":"T0+690s","Exclusion Flux":[{"Energy Range":"225-300 GeV","Value":"1.9 x 10^(-7) erg/cm^2"},{"Energy Range":"300-400 GeV","Value":"1.0 x 10^(-7) erg/cm^2"},{"Energy Range":"400-1000 GeV","Value":"2.4 x 10^(-8) erg/cm^2"}],"Observation Duration":"36 min","Time Bin Exclusion":"100 s","Zenith Angle Range":"53-50 degrees"},"ra":null,"redshift":null,"tables":[{"Energy Range":"225-300 GeV","Flux Upper Limit":"7.1 x 10^(-8) erg/cm^2"},{"Energy Range":"300-400 GeV","Flux Upper Limit":"4.6 x 10^(-8) erg/cm^2"},{"Energy Range":"400-1000 GeV","Flux Upper Limit":"2.2 x 10^(-8) erg/cm^2"},{"Energy Range":"1-10 TeV","Flux Upper Limit":"0.53 x 10^(-8) erg/cm^2"}]},"authors":{"affiliations":["MPI/Muenchen","IAC/Tenerife","U. Padova","INFN/Trieste","U. Udine","for the MAGIC Collaboration"],"authors":["Galante N.","Garczarczyk M.","Gaug M.","Bastieri D.","Longo F.","Scapin V."],"institutions":["MPI/Muenchen","IAC/Tenerife"],"universities":["MPI/Muenchen","U. Padova","INFN/Trieste","U. Udine"]},"telescopes":{"facilities":[],"instruments":[],"observatories":[],"telescopes":["MAGIC Imaging Atmospheric Cherenkov Telescope"]},"urls":["http://gcn.gsfc.nasa.gov/gcn3/gcn3_circulars.cfm?id=6805"],"basic_data":{"author":{"email":"galante@mppmu.mpg.de","institution":"MPI,Muenchen","name":"Nicola Galante"},"coordinates":{},"detectionTime":"2007-10-06T08:21:21.000Z","event":"GRB070920A","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6854\nSUBJECT: GRB070920A: MAGIC telescope GeV observation\nDATE: 07/10/06 08:21:21 GMT\nFROM: Nicola Galante at MPI,Muenchen  <galante@mppmu.mpg.de>\n\nGalante N. (MPI/Muenchen), Garczarczyk M. (MPI/Muenchen),\nGaug M. (IAC/Tenerife), Bastieri D. (U. Padova), Longo F. (INFN/Trieste)\nand Scapin V. (U. Udine), for the MAGIC Collaboration\n\nThe MAGIC Imaging Atmospheric Cherenkov Telescope performed a follow-up\nobservation of the SWIFT/BAT burst GRB070920A (GCN circular 6805,\nGrupe D., et al.). We received the GCN alert at T0+539s. The data taking\nby MAGIC started at T0+690s, 2.5 minutes after the alert income.\nWe observed the sky positon for 36min spanning a zenith angle\nin the range 53-50 degrees.\n\nNo evidence for VHE gamma-ray emission above the analysis threshold of\nabout 250 GeV was found. A preliminary analysis, taking advantage\nfor the first time of the fast 2GHz digitalization from the\nnew data acquisition system, and for the hypothesis of\nsteady emission and assumption of a differential photon\nspectral index of -2.5, yields the following 95% CL differential flux\nupper limits (inc. 30% systematic error on the efficiency):\n\nE(225-300 GeV)  : 7.1 x 10^(-8) erg/cm^2\nE(300-400 GeV)  : 4.6 x 10^(-8) erg/cm^2\nE(400-1000 GeV) : 2.2 x 10^(-8) erg/cm^2\nE(1-10 TeV)     : 0.53 x 10^(-8) erg/cm^2\n\nThe upper limits correspond to the time period between T0+690s and\nT0+2490s. We can also exclude emission of a constant flux during our observation\nin any 100s time bin higher than:\n\nE(225-300 GeV)  : 1.9 x 10^(-7) erg/cm^2\nE(300-400 GeV)  : 1.0 x 10^(-7) erg/cm^2\nE(400-1000 GeV) : 2.4 x 10^(-8) erg/cm^2\n\nThis message can be cited."}', 'The MAGIC Imaging Atmospheric Cherenkov Telescope did not detect VHE gamma-ray emission above the analysis threshold of 250 GeV from GRB070920A, a gamma-ray burst observed by SWIFT/BAT. The observation started 2.5 minutes after the alert and covered a zenith angle range of 53-50 degrees. The upper limits on the differential flux were determined for various energy ranges.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6853', 'gcn', 'GRB 071003', '2007-10-05T20:13:04.000Z', '{"measurements":{"dec":null,"distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":null,"other_measurements":{"flux_density":"393 +/- 55 uJy","frequency":"8.46 GHz"},"ra":null,"redshift":null,"tables":[]},"authors":{"affiliations":["UVA/NRAO","NRAO"],"authors":["Poonam Chandra","D. A. Frail"],"institutions":["NRAO","Caltech-NRAO-Carnegie GRB Collaboration"],"universities":["University of Virginia"]},"telescopes":{"facilities":["National Science Foundation"],"instruments":[],"observatories":["National Radio Astronomy Observatory"],"telescopes":["VLA"]},"urls":["https://gcn.gsfc.nasa.gov/gcn3/gcn3_circular_detail.jsp?id=6853"],"basic_data":{"author":{"email":"pc8s@virginia.edu","institution":"U Virginia/NRAO","name":"Poonam Chandra"},"coordinates":{},"detectionTime":"2007-10-05T20:13:04.000Z","event":"GRB 071003","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6853\nSUBJECT: Radio detection of GRB 071003 with the VLA\nDATE: 07/10/05 20:13:04 GMT\nFROM: Poonam Chandra at U Virginia/NRAO  <pc8s@virginia.edu>\n\nP. Chandra (UVA/NRAO) and  D. A. Frail (NRAO) report on behalf of the\nCaltech-NRAO-Carnegie GRB Collaboration:\n\n\"We observed the field centered on the BAT position of the Swift burst\nGRB 070923 (GCN#6837) using the VLA at a frequency of 8.46 GHz\nand starting at 1.85 UT on Oct 5, 2007. We detect the radio afterglow at\nKAIT optical position (GCN#6838) with flux density of 393 +/- 55 uJy.\n\nFurther observations are planned.\n\nThe National Radio Astronomy Observatory is a facility of the National\nScience Foundation operated under cooperative agreement by Associated\nUniversities, Inc.\""}', 'Astronomers using the VLA radio telescope detected a radio afterglow from GRB 070923 at a flux density of 393 +/- 55 uJy at a frequency of 8.46 GHz.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6852', 'gcn', 'GRB 070810B', '2007-10-05T18:33:55.000Z', '{"measurements":{"dec":null,"distance":null,"duration":"13.8 ks","energy":null,"fluence":null,"magnitude":null,"other_measurements":{"background_count_rate_limit":"6.7e-4 count/s","observation_duration":"12.6 ks","observation_period":"42 days to 54 days"},"ra":null,"redshift":null,"tables":[{"count_rate_limit":"5.6e-4 count/s","detection_time":"initial epoch","sigma_level":"2-sigma","source":"S1"},{"count_rate":"1.6e-3 to 4.3e-3 count/s","count_rate_limit":"3.6e-3 count/s","detection_time":"second epoch","sigma_level":"4-sigma","source":"S2"}]},"authors":{"affiliations":["U. Leicester","NASA/GSFC"],"authors":["R. Starling","J.P. Osborne","K.L. Page","F.E. Marshall"],"institutions":["U. Leicester","NASA/GSFC"],"universities":["University of Leicester"]},"telescopes":{"facilities":[],"instruments":[],"observatories":[],"telescopes":[]},"urls":["https://gcn.gsfc.nasa.gov"],"basic_data":{"author":{"email":"rlcs1@star.le.ac.uk","institution":"U of Leicester","name":"Rhaana Starling"},"coordinates":{},"detectionTime":"2007-10-05T18:33:55.000Z","event":"GRB 070810B","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6852\nSUBJECT: GRB 070810B: further XRT analysis\nDATE: 07/10/05 18:33:55 GMT\nFROM: Rhaana Starling at U of Leicester  <rlcs1@star.le.ac.uk>\n\nR. Starling, J.P. Osborne, K.L. Page (U. Leicester) and F.E. Marshall\n(NASA/GSFC) report, on behalf of the Swift XRT team:\n\nPreviously, Swift XRT data for the short GRB 070810B (trigger=287409; \nMarshall et al., GCN Circ. 6743) up to 13.8 ks after the BAT trigger \nshowed two possible sources within the BAT refined error circle, detected \nat 2-sigma significance in 7.2 ks and termed S1 and S2 (Starling et al., \nGCN Circ. 6754).\n \nWe have analysed a further 12.6 ks of Swift XRT photon counting mode data\nbeginning 42 days and ending 54 days after the burst, in order to assess \nthe variability of the two possible afterglow candidates.\n\nIn this second epoch of data we detect one X-ray source at 4-sigma \nsignificance within the refined BAT error circle (Sakamoto et al., GCN \nCirc. 6753), corresponding to the source S2 described in GCN Circ. 6754.\nUsing Bayesian analysis we find that S2 has between 20 and 54 counts at \nthe 99% confidence level or 1.6e-3 to 4.3e-3 count/s, consistent with the \nfirst epoch limits of 5.6e-4 to 3.6e-3 count/s. This suggests that S2 is \na persistent faint source, and not the afterglow of GRB 070810B.\n \nThe possible source S1 (GCN Circ. 6754), detected only at the 2-sigma \nlevel in the intial epoch observations, is not detected in the second \nepoch observations, providing an upper limit on the count rate of 6.7e-4 \ncount/s at 99% confidence based on the background count rate. This is  \nabove the 3-sigma lower limit on the source count rate at epoch 1 of \n5.6e-4 count/s, hence we cannot determine whether or not this source has \nfaded. \n \nThis is an official product of the Swift XRT team."}', 'Swift XRT team analyzed additional data for GRB 070810B and detected a persistent faint source S2 at 4-sigma significance within the refined error circle, which is not the afterglow of the burst. The possible source S1, detected only at the 2-sigma level in the initial epoch observations, was not detected in the second epoch and has an upper limit on the count rate of 6.7e-4 count/s.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6851', 'gcn', 'GRB 071003', '2007-10-05T17:30:14.000Z', '{"measurements":{"dec":null,"distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":null,"other_measurements":{"observation_duration":"1800s","resolution":"R = 780","seeing_conditions":"1.0\"","time_after_burst":"~ 0.735 days"},"ra":null,"redshift":0.937,"tables":[]},"authors":{"affiliations":["INAF-OABr","INAF-OAR"],"authors":["D. Fugazza","F. Fiore","V. D''Elia","P. D''Avanzo","S. Piranomonte","L.A. Antonelli","G. Chincarini","S. Covino","G. Tagliaferri","M. Della Valle","A. Fernandez Soto"],"institutions":["INAF-OAB","INAF-OAR"],"universities":["Univ. Valencia","Univ. Bicocca"]},"telescopes":{"facilities":[],"instruments":["FORS2 camera"],"observatories":[],"telescopes":["ESO-Very Large Telescope"]},"urls":[],"basic_data":{"author":{"email":"paolo.davanzo@brera.inaf.it","institution":"INAF-OAB","name":"Paolo D''Avanzo"},"coordinates":{},"detectionTime":"2007-10-05T17:30:14.000Z","event":"GRB 071003","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6851\nSUBJECT: GRB 071003: VLT spectroscopy\nDATE: 07/10/05 17:30:14 GMT\nFROM: Paolo D''Avanzo at INAF-OAB  <paolo.davanzo@brera.inaf.it>\n\nD. Fugazza (INAF-OABr), F. Fiore, V. D''Elia (INAF-OAR), P. D''Avanzo \n(INAF-OABr), S. Piranomonte, L.A. Antonelli (INAF-OAR), G. Chincarini \n(Univ. Bicocca), S. Covino, G. Tagliaferri (INAF-OABr), M. Della Valle \n(INAF-OAA), A. Fernandez Soto (Univ. Valencia) report on behalf of the \nMISTICI collaboration:\n\nWe observed the optical afterglow of GRB 071003 (Schady et al., GCN \n6837; Li et al. GCN 6838; Cenko et al. GCN 6839) with the ESO-Very Large \nTelescope equipped with the FORS2 camera in spectroscopic mode. We took \na 1800s spectrum with the grism 600B (with a resolution of R = 780) on \nOct 04.055 UT (~ 0.735 days after the burst), under good seeing \nconditions (1.0\").\n\nThe detection of a MgII system at z=1.100 (Perley et al. GCN 6850), \ncannot be confirmed by our data, because the 2803 AA component of the \nMgII doublet is contamined by the NaI 5891 and 5897 AA doublet of the \nnearby bright star.\n\nWe also find significant lines at 5417 and 5430 AA, which we interpret \nas the MgII absorption doublet at 2797 and 2803 AA at z=0.937. FeII 2382 \nis also detected at the same redshift.\n\nIn addition, we find two more significant absorption lines (5417 and \n5446 AA), that can be identified as Ca H and K at z=0.372. \nAlternatively, the 5446 AA line can be interpreted as the  2803 AA \ncomponent of the MgII doublet at z=0.942, with the 2797 AA component \nsharing the absorption feature at 5430 AA with the MgII 2803 of the \nsystem at z=0.937. This can be another line-locking example like that of \nthe CIV system of GRB 021004 at z=2.3 (Fiore et al. 2005, ApJ, 624, 853; \nStarling et al. 2005, MNRAS, 360, 305 ).\n\nFinally, we find another MgII doublet at ~4000 AA (z=0.370), not \nconsistent with the Ca system at z=0.372. No emission lines are visible.\n\nIn summary our analysis of the FORS2 spectrum puts a lower limit on the \nredshift of GRB 071003 to z=0.937.\n\nWe thank VLT staff for performing the observations, in particular Thomas \nSzeifert and Alain Smette."}', 'Astronomers using the ESO-Very Large Telescope observed the optical afterglow of GRB 07103 with the FORS2 camera in spectroscopic mode. They detected significant absorption lines at 5417 and 5430 Å, which they interpret as the MgII absorption doublet at z=0.937. FeII 2382 was also detected at the same redshift. Additionally, they found two absorption lines that could be identified as Ca H and K at z=0.372 or the MgII doublet at z=0.942. The analysis puts a lower limit on the redshift of GRB 07103 to z=0.937.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6850', 'gcn', 'GRB 071003', '2007-10-04T13:11:24.000Z', '{"measurements":{"dec":null,"distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":{"R":19.1},"other_measurements":{"exposure_time":"10 minutes","time_after_trigger":"0.88 days","wavelength_range":"3300-8630 Angstroms"},"ra":null,"redshift":[1.1,0.372],"tables":[]},"authors":{"affiliations":["UC Berkeley","UC Davis"],"authors":["D. A. Perley","R. Chornock","J. S. Bloom","C. Fassnacht","M. W. Auger"],"institutions":["GRAASP"],"universities":["University of California, Berkeley","University of California, Davis"]},"telescopes":{"facilities":[],"instruments":["LRIS"],"observatories":[],"telescopes":["Keck I"]},"urls":[],"basic_data":{"author":{"email":"dperley@astro.berkeley.edu","institution":"U.C. Berkeley","name":"Daniel Perley"},"coordinates":{},"detectionTime":"2007-10-04T13:11:24.000Z","event":"GRB 071003","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6850\nSUBJECT: GRB 071003: Keck spectroscopy\nDATE: 07/10/04 13:11:24 GMT\nFROM: Daniel Perley at U.C. Berkeley  <dperley@astro.berkeley.edu>\n\nD. A. Perley, R. Chornock, J. S. Bloom (UC Berkeley), C. Fassnacht, and \nM. W. Auger (UC Davis) report on behalf of GRAASP:\n\nWe obtained spectroscopic follow-up of the bright transient associated \nwith GRB 071003 (Schady et al., GCN 6837; Li, GCN 6838) starting at \n07:51 UT on the night of 2007-10-04 using Keck I + LRIS (range 3300-8630 \nAngstroms).  Two 10-minute exposures were acquired.\n\nThe source is well-detected and a preliminary reduction reveals a smooth \nspectrum consistent with a GRB afterglow with multiple absorption-line \nsystems.  We identify a pair of absorption features at 5870 and 5886 \nAngstroms with the Mg II 2796, 2803 Angstrom doublet at a redshift of \n1.100.  Other absorption features are consistent with Fe II 2382, 2586, \nand 2599 Angstroms at this redshift.  This absorption system sets a \nlower limit on the redshift of the GRB of z=1.100.\n\nIn addition, numerous lines (e.g., Mg II 2796, 2803 Angstroms, Mg I 2852 \nAngstroms, and Fe II 2599 Angstroms) are present from an intervening \nabsorption system at z=0.372.\n\nNo strong supernova features or host-galaxy emission lines are seen in \nthe spectrum.\n\nThis suggests that the transient is a GRB afterglow undergoing a bright \nlate-time optical flare, similar to the afterglow of GRB 070311 (e.g. \nHalpern & Armstrong, GCN 6203; Guidorzi et al., astroph/0708.1383), \nrather than a supernova.  That flare peaked at R~22 approximately two \ndays after the burst. Improved photometry of the optical transient \nassociated with GRB 071003 gives a magnitude of R = 19.1 +/- 0.3 at \n04:49 UT (0.88 days after the trigger) and further rebrightening appears \npossible. Further monitoring is strongly encouraged."}', 'Astronomers at U.C. Berkeley and U.C. Davis report the discovery of absorption features in the spectrum of GRB 071003 using the Keck I telescope. The features indicate a redshift of 1.100 for the GRB and rule out a supernova explanation. An additional absorption system at z=0.372 was also detected.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-685', 'gcn', 'GRB 000529', '2000-06-01T21:06:28.000Z', '{"measurements":{"dec":"-61d 27'' 53\"","distance":null,"duration":{"unit":"seconds","value":23000},"energy":null,"fluence":null,"magnitude":null,"other_measurements":{"count_rate":{"error":0.001,"unit":"count/s","value":0.0041},"flux":{"unit":"erg/cm2/s","value":2.8e-13}},"ra":"00h 09m 48.3s","redshift":null,"tables":[]},"authors":{"affiliations":["IAS, CNR, Rome","OAR, Rome","ASI, Rome","ITESRE, CNR, Bologna","IFCAI, CNR, Palermo","SRON, Utrecht","BeppoSAX GRB Team"],"authors":["M. Feroci","G. Gandolfi","E. Costa","L. Piro","P. Soffitta","L.A. Antonelli","L. Salotti","A. Coletta","G. Celidonio","G. D''Andreta","M.R. Daniele","M. Stornelli","F. Frontera","E. Pian","L. Nicastro","J.J.M. in ''t Zand","J. Heise","M.J. Smith","J.M. Muller"],"institutions":["IAS/CNR Frascati","OAR, Rome","ASI, Rome","ITESRE, CNR, Bologna","IFCAI, CNR, Palermo","SRON, Utrecht","BeppoSAX GRB Team"],"universities":["IAS, CNR","CNR","ASI","IFCAI","CNR","SRON"]},"telescopes":{"facilities":[],"instruments":[],"observatories":[],"telescopes":[]},"urls":[],"basic_data":{"author":{"email":"feroci@ias.rm.cnr.it","institution":"IAS/CNR Frascati","name":"Marco Feroci"},"coordinates":{},"detectionTime":"2000-06-01T21:06:28.000Z","event":"GRB 000529","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 685\nSUBJECT: X-ray Afterglow of GRB 000529\nDATE: 00/06/01 21:06:28 GMT\nFROM: Marco Feroci at IAS/CNR Frascati  <feroci@ias.rm.cnr.it>\n\nGRB000529: candidate X-ray afterglow\n \n M. Feroci, G. Gandolfi, E. Costa, L. Piro, P. Soffitta (IAS, CNR, Rome),\n L.A. Antonelli (OAR, Rome), L. Salotti (ASI, Rome), A. Coletta, \n G. Celidonio, G. D''Andreta, M.R. Daniele, M. Stornelli (Telespazio, Rome),\n F. Frontera, E. Pian (ITESRE, CNR, Bologna), \n L. Nicastro (IFCAI, CNR, Palermo), \n J.J.M. in ''t Zand, J. Heise, M.J. Smith, J.M. Muller (SRON, Utrecht), \n on behalf of the BeppoSAX GRB Team, report:\n \n \"The WFC error box (GCN #676) of GRB 000529 was observed by the\n Narrow Field Instruments starting about 7.5 hours after the GRB.\n A preliminary analysis of the first 23 ks of this observation\n reveals a previously unknown weak X-ray source, 1SAX J0009.8-6128\n at the position RA = 00h 09m 48.3s Dec = -61d 27'' 53\", with a\n conservative error radius of 2 arcminutes.\n No other source is significantly detected in the field.\n By dividing the available observation in two portions, the source\n is detected only in the first ~11ks with a count rate of\n (4.1+-1.0)E-3 count/s, corresponding to 2.8E-13 erg/cm2/s \n (assuming a Crab-like energy spectrum). The lack of source detection \n in the second ~12ks makes the new source a reasonable candidate as the \n X-ray afterglow of GRB 000529.\n The position lies at 4.9 arcminutes from the WFC refined\n error box, and it therefore only partially overlaps with it. \n We note that the position of the  NFI source is consistent with \n the IPN annulus for this GRB (GCN #680).\n This message may be quoted in publications.\""}', 'Astronomical alert: X-ray Afterglow of GRB 000529', 0.5, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6849', 'gcn', 'GRB 071003', '2007-10-04T11:50:07.000Z', '{"measurements":{"dec":null,"distance":null,"duration":30,"energy":null,"fluence":0.0000532,"magnitude":null,"other_measurements":{"energy_range":"20 keV - 4 MeV","fluence_energy_range":"20 keV - 4 MeV","peak_flux":0.0000122,"peak_flux_energy_range":"20 keV - 4 MeV","time_of_peak_flux":2.464},"ra":null,"redshift":null,"tables":[{"Ep":799,"alpha":0.97,"chi2":74.2,"degrees_of_freedom":74},{"Ep":780,"alpha":0.76,"chi2":75.6,"degrees_of_freedom":74}]},"authors":{"affiliations":["Ioffe Inst"],"authors":["S. Golenetskii","R.Aptekar","E. Mazets","V. Pal''shin","D. Frederiks","T. Cline"],"institutions":["Ioffe Inst"],"universities":["Ioffe Inst"]},"telescopes":{"facilities":[],"instruments":["Konus-Wind"],"observatories":[],"telescopes":["Konus-Wind"]},"urls":["http://www.ioffe.rssi.ru/LEA/GRBs/GRB071003_T27655/"],"basic_data":{"author":{"email":"val@mail.ioffe.ru","institution":"Ioffe Inst","name":"Valentin Pal''shin"},"coordinates":{},"detectionTime":"2007-10-04T11:50:07.000Z","event":"GRB 071003","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6849\nSUBJECT: Konus-Wind observation of GRB 071003\nDATE: 07/10/04 11:50:07 GMT\nFROM: Valentin Pal''shin at Ioffe Inst  <val@mail.ioffe.ru>\n\nS. Golenetskii, R.Aptekar, E. Mazets, V. Pal''shin, D. Frederiks,\nand T. Cline on behalf of the Konus-Wind team report:\n\nThe long GRB 071003 (Swift-BAT trigger #292934:\nSchady et al., GCN 6837; Ukwatta et al., GCN 6842) triggered\nKonus-Wind at T0=27655.120 s UT (07:40:55.120).\n\nThe burst light curve shows a multipeaked structure\nwith a duration of ~30 s. There is a hint of\nthe weak extended emission reported by BAT\n(Ukwatta et al., GCN 6842) in the Konus-Wind data.\nAs observed by Konus-Wind the burst\nhad a fluence of 5.32(-0.67, +0.30)x10^-5 erg/cm2,\nand a 64-ms peak flux measured from T0+2.464 s\nof 1.22(-0.22, +0.19)x10^-5 erg/cm2/s\n(both in the 20 keV - 4 MeV energy range).\n\nThe time-integrated spectrum of the burst\n(from T0 to T0+30.720 s) is well fitted\n(in the 20 keV - 4 MeV range)\nby a power law with exponential cutoff model:\ndN/dE ~ E^(-alpha)*exp(-E*(2-alpha)/Ep)\nwith alpha = 0.97 +/- 0.07\nand Ep = 799(-100, +124) keV (chi2 = 74.2/74 dof).\nThe spectrum of the most intense part\n(from T0 to T0+14.336 s) is well fitted\n(in the same range)\nby a power law with exponential cutoff model\nwith alpha = 0.76 (-0.07, +0.06)\nand Ep = 780(-70, +81) keV (chi2 = 75.6/74 dof).\n\nAll the quoted errors are at the 90% confidence level.\n\nThe Konus-Wind light curve of this GRB is available\nat http://www.ioffe.rssi.ru/LEA/GRBs/GRB071003_T27655/"}', 'The Konus-Wind team reported the observation of long gamma-ray burst (GRB) 071003, which triggered the instrument at T0=27655.120s UT. The burst had a duration of approximately 30 seconds and a fluence of 5.32x10^-5 erg/cm2 in the 20 keV - 4 MeV energy range. The time-integrated and most intense part of the burst were found to be well-fitted by power law with exponential cutoff models. The quoted errors are at the 90% confidence level.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6848', 'gcn', 'GRB071003', '2007-10-04T10:15:37.000Z', '{"measurements":{"dec":null,"distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":[14.72,14.81,14.9],"other_measurements":{},"ra":null,"redshift":null,"tables":[{"Exp(s)":10,"Start Time from trigger (s)":189,"mag R":14.72},{"Exp(s)":10,"Start Time from trigger (s)":210,"mag R":14.81},{"Exp(s)":10,"Start Time from trigger (s)":229,"mag R":14.9}]},"authors":{"affiliations":["U. Bicocca & INAF-OAB","U. Ljubljana","Liverpool JMU"],"authors":["C. Guidorzi","D.F. Bersier","R.J. Smith","C.J. Mottram","M.F. Bode","D. Carter","S. Kobayashi","A. Melandri","C.G. Mundell","I.A. Steele","A. Gomboc","P. O''Brien","E. Rol","N. Bannister"],"institutions":["INAF-OAB"],"universities":["University of Bicocca","INAF-OAB","University of Ljubljana","Liverpool John Moores University"]},"telescopes":{"facilities":[],"instruments":[],"observatories":[],"telescopes":["Faulkes Telescope North"]},"urls":[],"basic_data":{"author":{"email":"cristiano.guidorzi@brera.inaf.it","institution":"INAF-OAB","name":"Cristiano Guidorzi"},"coordinates":{},"detectionTime":"2007-10-04T10:15:37.000Z","event":"GRB071003","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6848\nSUBJECT: GRB071003: Faulkes Telescope North observations\nDATE: 07/10/04 10:15:37 GMT\nFROM: Cristiano Guidorzi at INAF-OAB  <cristiano.guidorzi@brera.inaf.it>\n\nC. Guidorzi (U. Bicocca & INAF-OAB), D.F. Bersier, R.J. Smith,\nC.J. Mottram, M.F. Bode, D. Carter, S. Kobayashi, A. Melandri,\nC.G. Mundell, I.A. Steele (Liverpool JMU), A. Gomboc (U. Ljubljana),\nP. O''Brien, E. Rol, N. Bannister (U. Leicester) report:\n\n\nThe 2-m Faulkes Telescope North robotically followed up GRB071003\n(Schady et al., GCN Circ. 6837) beginning 189 s after the GRB\ntrigger time (UT 07:40:55).\nWe clearly detect the afterglow (Li et al., GCN Circ. 6838).\nWe measure the following magnitudes in the R filter:\n\nStart Time from trigger\n(s)                       Exp(s)      mag R\n----------------------------------------------------\n189                        10         14.72 +/- 0.01\n210                        10         14.81 +/- 0.01\n229                        10         14.90 +/- 0.01\n----------------------------------------------------\n\nMagnitudes are calibrated with respect to several nearby\nUSNO-B1 objects."}', 'The Faulkes Telescope North detected the afterglow of GRB071003, a gamma-ray burst, 189 seconds after the initial trigger. The team measured the magnitude of the afterglow in the R filter at three different exposure times: 14.72 ± 0.01 at 189 seconds, 14.81 ± 0.01 at 210 seconds, and 14.90 ± 0.01 at 229 seconds.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6847', 'gcn', 'GRB 071003', '2007-10-04T08:33:56.000Z', '{"measurements":{"dec":null,"distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":{"R":20},"other_measurements":{"exposure_time":300,"exposure_time_unit":"seconds","separation_from_detection":0.3,"separation_from_detection_unit":"\"","separation_from_host_galaxy":2,"separation_from_host_galaxy_unit":"\""},"ra":null,"redshift":null,"tables":[]},"authors":{"affiliations":["UC Berkeley","UC Davis","LBL"],"authors":["D. A. Perley","W. Li","J. S. Bloom","C. Fassnacht","P. Nugent"],"institutions":["UC Berkeley","UC Davis","LBL"],"universities":["University of California, Berkeley"]},"telescopes":{"facilities":[],"instruments":["LRIS"],"observatories":[],"telescopes":["Keck I"]},"urls":[],"basic_data":{"author":{"email":"dperley@astro.berkeley.edu","institution":"U.C. Berkeley","name":"Daniel Perley"},"coordinates":{},"detectionTime":"2007-10-04T08:33:56.000Z","event":"GRB 071003","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6847\nSUBJECT: GRB 071003: Possible rebrightening\nDATE: 07/10/04 08:33:56 GMT\nFROM: Daniel Perley at U.C. Berkeley  <dperley@astro.berkeley.edu>\n\nD. A. Perley, W. Li, J. S. Bloom (UC Berkeley), C. Fassnacht (UC Davis), \nand P. Nugent (LBL) report:\n\nOn the night of 2007-10-04 (UT) we imaged the field of GRB 071003 with \nKeck I + LRIS, in g+R filters simultaneously for 3 exposures of 300 \nseconds, starting at 04:49 UT.\n\nWe detect at the position reported by Li (GCN 6838) a bright source with \nan estimated magnitude of R~20, though photometry is complicated by the \npresence of the nearby 11th magnitude star.  The position is consistent \nwithin 0.3\" of the KAIT detection, strongly suggesting that this is the \nsame source.  Given the rapid fading noted in earlier circulars (GCN \n6841, GCN 6844) and the limit of R > 21 reported by Shih et al. (GCN \n6848) this may suggest that the optical afterglow is rebrightening, \neither due to a late-time flare or a rising low-redshift supernova.\n\nWe also note what appears to be a faint, extended object approximately \n2\" to the southwest of the afterglow (towards the bright star), which \nmay be the host galaxy of this burst.\n\nFurther analysis is in progress.  Additional observations are strongly \nencouraged to further examine the nature of this transient."}', 'Astronomical alert: GRB 071003: Possible rebrightening', 0.5, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6846', 'gcn', 'GRB 071003', '2007-10-04T01:07:53.000Z', '{"measurements":{"dec":null,"distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":21.5,"other_measurements":{"observation_time":"11:41:44 UT","time_after_burst":"4 hours"},"ra":null,"redshift":null,"tables":[]},"authors":{"affiliations":["Saitama U","EAFON team"],"authors":["C.Y. Shih","Y.H. Lee","Y. Urata","K.Y. Huang"],"institutions":["Saitama U","EAFON team"],"universities":["Saitama-u.ac.jp"]},"telescopes":{"facilities":[],"instruments":[],"observatories":[],"telescopes":["Lulin 1-m telescope"]},"urls":["http://gcn.gsfc.nasa.gov"],"basic_data":{"author":{"email":"urata@crystal.heal.phy.saitama-u.ac.jp","institution":"Saitama U","name":"Yuji Urata"},"coordinates":{},"detectionTime":"2007-10-04T01:07:53.000Z","event":"GRB 071003","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6846\nSUBJECT: GRB 071003 : Lulin R-band observations\nDATE: 07/10/04 01:07:53 GMT\nFROM: Yuji Urata at Saitama U  <urata@crystal.heal.phy.saitama-u.ac.jp>\n\nC.Y. Shih, Y.H. Lee, Y. Urata and K.Y. Huang on behalf of the EAFON team\n \n\"We have performed R-band observations for GRB 071003 field (Schady et\nal., GCN 6837; Li GCN 6838) using Lulin 1-m telescope at 11:41:44 UT\n(about 4 hours after the burst). There is no optical afterglow\nemission in our combined image with R<21.5 (3-sigma limit) derived\nfrom USNO-B1.0 red stars.\""}', 'The Lulin Observatory team, led by C.Y. Shih, Y.H. Lee, Y. Urata, and K.Y. Huang, reported no optical afterglow emission from GRB 071003 in R-band observations using the Lulin 1-m telescope, with a limiting magnitude of 21.5 (3-sigma) at 11:41:44 UT, approximately 4 hours after the burst.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6845', 'gcn', 'GRB 071003', '2007-10-03T23:15:38.000Z', '{"measurements":{"dec":10.94688,"distance":null,"duration":22000,"energy":null,"fluence":null,"magnitude":null,"other_measurements":{"count_rate":0.1,"distance_from_bat_position":35.5,"distance_from_optical_afterglow":3.6,"error_radius":5.7},"ra":301.85102,"redshift":null,"tables":[]},"authors":{"affiliations":["U. Leicester","MSSL/UCL"],"authors":["R. Starling","P. Schady","Schady et al.","Ukwatta et al.","Li"],"institutions":["MSSL/UCL"],"universities":["University of Leicester"]},"telescopes":{"facilities":[],"instruments":["Swift XRT"],"observatories":[],"telescopes":["Swift"]},"urls":["https://gcn.gsfc.nasa.gov"],"basic_data":{"author":{"email":"rlcs1@star.le.ac.uk","institution":"U of Leicester","name":"Rhaana Starling"},"coordinates":{},"detectionTime":"2007-10-03T23:15:38.000Z","event":"GRB 071003","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6845\nSUBJECT: GRB 071003: Swift XRT position\nDATE: 07/10/03 23:15:38 GMT\nFROM: Rhaana Starling at U of Leicester  <rlcs1@star.le.ac.uk>\n\nR. Starling (U. Leicester) and P. Schady (MSSL/UCL) report on behalf of \nthe Swift team:\n\nSwift XRT observed the GRB 071003 (trigger=292934, Schady et al., GCN \nCirc. 6837) beginning 22 ks after the BAT trigger.\nIn 2650 s of Photon Counting mode data spanning 22--25 ks after the \ntrigger a bright X-ray source (approximate count rate 0.1 count/s) is \ndetected at the position RA,Dec = 301.85102, +10.94688 deg, equivalent to:\nRA(J2000) =  20h 07m 24.25s\nDec(J2000)= +10d 56'' 48.8\"\nwith an error of radius 5.7 arcseconds (90%, including boresight \nuncertainties). This is 35.5 arcseconds from the BAT refined position \n(Ukwatta et al., GCN Circ. 6842) and 3.6 arcseconds from the optical \nafterglow position (Li, GCN Circ. 6838). \nFurther analysis will be reported in a subsequent circular.\n\nThis is an official product of the Swift XRT team."}', 'The Swift XRT team reports the detection of an X-ray source approximately 22,000 seconds after the gamma-ray burst GRB 071003. The source, located at RA(J2000) = 20h 07m 24.25s, Dec(J2000) = +10d 56'' 48.8', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6844', 'gcn', 'GRB 071003', '2007-10-03T23:14:54.000Z', '{"measurements":{"dec":null,"distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":[12.83,13.56,14.82,15.89],"other_measurements":{"observation_end_time":27,"power_law_index_1":-1.52,"power_law_index_1_error":0.06,"power_law_index_2":-0.89,"power_law_index_2_error":0.03,"power_law_index_3":-1.85,"power_law_index_3_error":0.1,"time_interval_1_end":1.2,"time_interval_1_start":0.7,"time_interval_2_end":4.3,"time_interval_2_start":1.2,"time_interval_3_end":7.4,"time_interval_3_start":4.3},"ra":null,"redshift":null,"tables":[{"Exptime(s)":5,"Mag":12.83,"Mag(err)":0.02,"t_start(s)":42},{"Exptime(s)":5,"Mag":13.56,"Mag(err)":0.03,"t_start(s)":67},{"Exptime(s)":20,"Mag":14.82,"Mag(err)":0.03,"t_start(s)":249},{"Exptime(s)":20,"Mag":15.89,"Mag(err)":0.06,"t_start(s)":431}]},"authors":{"affiliations":["UC Berkeley"],"authors":["W. Li","R. Chornock","A. V. Filippenko","D. A. Perley","J. S. Bloom"],"institutions":["KAIT/LOSS"],"universities":["University of California, Berkeley"]},"telescopes":{"facilities":[],"instruments":[],"observatories":[],"telescopes":["KAIT"]},"urls":["http://www.gcn.gsfc.nasa.gov/gcn3/gcn3_circulars.msf?is_new=1&is_html=1&is_gcn=1&is_public=1&is_alert=1&is_lat=1&is_lon=1&is_time=1&is_burst=1&is_message=1&is_gcnid=6844"],"basic_data":{"author":{"email":"weidong@astron.berkeley.edu","institution":"UC Berkeley KAIT/LOSS","name":"Weidong Li"},"coordinates":{},"detectionTime":"2007-10-03T23:14:54.000Z","event":"GRB 071003","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6844\nSUBJECT: GRB 071003: OA power-law decay indices from KAIT\nDATE: 07/10/03 23:14:54 GMT\nFROM: Weidong Li at UC Berkeley KAIT/LOSS  <weidong@astron.berkeley.edu>\n\nW. Li, R. Chornock, A. V. Filippenko, D. A. Perley, J. S. Bloom (University\nof California, Berkeley), on behalf of the KAIT GRB team, report:\n\nWe have analyzed the KAIT observations of the GRB 071003 optical \nafterglow (OA) reported by Li (GCN 6838) and confirmed by Cenko\nand Fox (GCN 6839). Our preliminary unfiltered light curve, calibrated\nwith USNO B1.0, shows two potential breaks for the OA in the first\n10 minutes after the burst. We measured a steep power law index of \n-1.52 +/- 0.06 between t = 0.7 min and 1.2 min after the burst (from\n5 x 5s images), possibly signaling the detection of the optical reverse\nshock emission from the GRB. A shallower power law index of -0.89\n+/- 0.03 is measured between t = 1.2 min and 4.3 min (from 3 images),\nsuggesting a break in the light curve between t = 1.2 min to 2.8 min. \nThe second potential break occurred at about 4 minutes after the burst,\nwith the power law decay index measured as -1.85 +/- 0.10 from 3 images\nobserved between t = 4.3 min to 7.4 min. We note this power law decay\nindex is consistent with the value reported by Swan et al. (GCN 6841)\nat later times. Our observations ended at about 27 minutes after the\nburst due to physical limits of KAIT.  The analysis of all the data is\nstill ongoing.\n\nThe overall behavior of the OA of GRB 071003 OA is similar to that of\nGRB 061126 (Perley et al., astro-ph/0703538), but with the breaks\noccurring at an earlier stage of the evolution.  We expect contamination\nfrom the nearby bright star as discussed by Li (GCN 6838), Cenko and Fox\n(GCN 6839), and Misra et al. (GCN 6840) to slightly affect the above\npower indices, but not the overall photometric behavior.\n\nSome selected KAIT unfiltered photometry:\n\nt_start(s)     Exptime(s)     Mag     Mag(err)\n\n 42            5.000        12.83   0.02\n 67            5.000        13.56   0.03\n249           20.000        14.82   0.03\n431           20.000        15.89   0.06\n\nThis message may be cited."}', 'A team at UC Berkeley''s KAIT/LOSS reports the detection of potential power-law decay indices in the optical afterglow of GRB 071003, indicating the presence of two breaks in the light curve. The first break occurs within the first 10 minutes and shows a steep power law index of -1.52 +/- 0.06. The second break occurs around 4 minutes after the burst with a shallower power law index of -0.89 +/- 0.03. The team suggests these breaks may represent the detection of the optical reverse shock emission and a change in the afterglow emission mechanism.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6843', 'gcn', 'GRB 071003', '2007-10-03T23:12:24.000Z', '{"measurements":{"dec":null,"distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":null,"other_measurements":{"airmass":"high","exposure_time":1700,"signal_to_noise_ratio":{"per_pixel":"1.3 km/s","value":1,"wavelength":"5000A"}},"ra":null,"redshift":{"upper_limit_1":3.4,"upper_limit_2":2.5,"upper_limit_3":1,"value":null},"tables":[]},"authors":{"affiliations":["UCB","UCSC","UCO/Lick"],"authors":["D. A. Perley","J. X. Prochaska","J. S. Bloom","G. Smith"],"institutions":["GRAASP collaboration"],"universities":["University of California, Berkeley","University of California, Santa Cruz"]},"telescopes":{"facilities":[],"instruments":["HIRES"],"observatories":[],"telescopes":["Keck"]},"urls":["https://gcn.gsfc.nasa.gov/gcn3/gcn3_circular_detail.jsp?id=6843"],"basic_data":{"author":{"email":"dperley@astro.berkeley.edu","institution":"U.C. Berkeley","name":"Daniel Perley"},"coordinates":{},"detectionTime":"2007-10-03T23:12:24.000Z","event":"GRB 071003","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6843\nSUBJECT: GRB 071003: Keck HIRES spectroscopy\nDATE: 07/10/03 23:12:24 GMT\nFROM: Daniel Perley at U.C. Berkeley  <dperley@astro.berkeley.edu>\n\nD. A. Perley (UCB), J. X. Prochaska (UCSC), J. S. Bloom (UCB), and G. \nSmith (UCO/Lick) report on behalf of the GRAASP collaboration:\n\nWe observed GRB 071003 (Schady et al., GCN 6837) with Keck/HIRESr \nstarting at UT 10:24 for one exposure of 1700s.  The data were acquired \nthrough very high airmass and have a low S/N ratio (~1 per 1.3 km/s \npixel at 5000A).\n\nWe identify no obvious absorption features in either the 2D image nor 1D \nspectrum.  Allowing for the following priors, we place the following \nupper limits on the GRB redshift:\n\n1.  Assuming the GRB host galaxy would emit no flux below the Lyman \nlimit, we infer z_GRB < 3.4\n\n2.  Assuming the GRB host galaxy would imprint a damped Lya profile on \nthe spectrum, we infer z_GRB < 2.5\n\n3.  Assuming the GRB host galaxy would imprint a strong MgII absorber on \nthe spectrum (EW > 1A), we infer z_GRB < 1.\n\nGiven these constraints and the U-band detection from Mishra et al. (GCN \n6840), it is possible that this GRB is at low redshift.  We encourage \nfollow-up observations to search for, or place limits on, a low-redshift \nhost galaxy or associated supernova."}', 'Astronomical alert: GRB 071003: Keck HIRES spectroscopy', 0.5, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6842', 'gcn', 'GRB 071003', '2007-10-03T22:22:49.000Z', '{"measurements":{"dec":"10d 57'' 16\"","distance":null,"duration":"150 +- 10 sec","energy":null,"fluence":"8.3 +- 0.3 x 10^-6 erg/cm2","magnitude":null,"other_measurements":{"partial_coding":"34%","peak_photon_flux":"6.3 +- 0.4 ph/cm2/sec","power_law_index":"1.36 +- 0.07"},"ra":"20h 07m 25.8s","redshift":null,"tables":[]},"authors":{"affiliations":["GWU","GSFC","UMBC","GSFC/UMD","GSFC/USRA","LANL","MSSL-UCL","GSFC/ORAU"],"authors":["T. Ukwatta","L. Barbier","S. D. Barthelmy","J. Cummings","E. Fenimore","N. Gehrels","H. Krimm","C. Markwardt","D. Palmer","A. Parsons","T. Sakamoto","G. Sato","P. Schady","M. Stamatikos","J. Tueller"],"institutions":["NASA/GSFC","GSFC/UMBC","GSFC/UMD","GSFC/USRA","LANL","MSSL-UCL","GSFC/ORAU"],"universities":["GSFC","UMBC","UMD","ISAS","LANL","ORAU"]},"telescopes":{"facilities":[],"instruments":[],"observatories":[],"telescopes":[]},"urls":["http://gcn.gsfc.nasa.gov"],"basic_data":{"author":{"email":"scott@lheamail.gsfc.nasa.gov","institution":"NASA/GSFC","name":"Scott Barthelmy"},"coordinates":{},"detectionTime":"2007-10-03T22:22:49.000Z","event":"GRB 071003","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6842\nSUBJECT: GRB 071003, Swift-BAT refined analysis\nDATE: 07/10/03 22:22:49 GMT\nFROM: Scott Barthelmy at NASA/GSFC  <scott@lheamail.gsfc.nasa.gov>\n\nT. Ukwatta (GWU), L. Barbier (GSFC), S. D. Barthelmy (GSFC),\nJ. Cummings (GSFC/UMBC), E. Fenimore (LANL), N. Gehrels (GSFC),\nH. Krimm (GSFC/USRA), C. Markwardt (GSFC/UMD), D. Palmer (LANL),\nA. Parsons (GSFC), T. Sakamoto (GSFC/UMBC), G. Sato (GSFC/ISAS),\nP. Schady (MSSL-UCL), M. Stamatikos (GSFC/ORAU), J. Tueller (GSFC)\n(i.e. the Swift-BAT team):\n \nUsing the data set from T-239 to T+584 sec from recent telemetry downlinks,\nwe report further analysis of BAT GRB 071003 (trigger #292934)\n(Schady, et al., GCN Circ. 6837).  The BAT ground-calculated position is\nRA, Dec = 301.857, 10.954 deg which is \n   RA(J2000)  = 20h 07m 25.8s \n   Dec(J2000) = 10d 57'' 16\" \nwith an uncertainty of 1.0 arcmin, (radius, sys+stat, 90% containment).\nThe partial coding was 34%.\n \nThe mask-weighted light curve shows a strong first peak with multiple\noverlapping subpeaks starting at ~T-20sec, peaking at T+0 sec, and ending\nat ~T+55 sec.  The second, much weaker peak starts at ~T+130 sec, peaks at\n~T+145 sec, and ends at ~T+220 sec.  T90 (15-350 keV) is 150 +- 10 sec\n(estimated error including systematics).\n \nThe time-averaged spectrum from T-7.6 to T+167.4 sec is best fit by a simple\npower-law model.  The power law index of the time-averaged spectrum is\n1.36 +- 0.07.  The fluence in the 15-150 keV band is 8.3 +- 0.3 x 10^-6 erg/cm2.\nThe 1-sec peak photon flux measured from T+0.37 sec in the 15-150 keV band\nis 6.3 +- 0.4 ph/cm2/sec.  All the quoted errors are at the 90% confidence\nlevel."}', 'Astronomical alert: GRB 071003, Swift-BAT refined analysis', 0.5, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6841', 'gcn', 'GRB 071003', '2007-10-03T22:02:30.000Z', '{"measurements":{"dec":null,"distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":16.04,"other_measurements":{"contaminating_star_magnitude":10.79,"decay_index":1.9,"flat_decay_start_time":"2000 seconds","observation_end_time":"3 hours after the start","observation_start_time":"9 minutes after the trigger","potential_OT_visibility_limit":"22nd mag"},"ra":null,"redshift":null,"tables":[]},"authors":{"affiliations":["U. of Michigan/ROTSE","MARGE collaboration"],"authors":["Heather Swan","I. Smith","W. Rujopakarn","F. Yuan","S. Yost","C. Akerlof","M. Skinner","R. Russell"],"institutions":["ROTSE (Rapid Optical Transient Se search Exploration)","MARGE collaboration","Aerospace Corporation","Boeing"],"universities":["University of Michigan","Rice University","Steward Observatory","University of Michigan"]},"telescopes":{"facilities":[],"instruments":["AEOS Burst Camera (ABC)"],"observatories":["Maui Space Surveillance System"],"telescopes":["AEOS telescope","Maui Space Surveillance System on Haleakala"]},"urls":["https://gcn.gsfc.nasa.gov/gcn3/gcn3_circulars.cfm?id=6837"],"basic_data":{"author":{"email":"hflewell@umich.edu","institution":"U.of Michigan/ROTSE","name":"Heather Swan"},"coordinates":{},"detectionTime":"2007-10-03T22:02:30.000Z","event":"GRB 071003","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6841\nSUBJECT: GRB 071003: MARGE Observations\nDATE: 07/10/03 22:02:30 GMT\nFROM: Heather Swan at U.of Michigan/ROTSE  <hflewell@umich.edu>\n\nH. Swan (U Mich), I. Smith (Rice), W. Rujopakarn (Steward), F. Yuan (U \nMich), S. Yost (College of St. Benedict), C. Akerlof (U Mich),  M. \nSkinner (Boeing), R. Russell (Aerospace Corporation) report on behalf of \nthe MARGE collaboration:\n\nThe AEOS Burst Camera (ABC) on the AEOS telescope, located at the Maui \nSpace Surveillance System on Haleakala, observed the fading counterpart \nto GRB071003 (Swift trigger 292934 (P. Schady et al. GCN 6837)). The \nimages are unfiltered 10s exposures which started ~9 minutes after the \ntrigger and ended ~ 3 hours later.\n\nWe detect the OT first identified by W. Li (GCN 6838). A preliminary \nanalysis gives a magnitude of approximately 16.04+/-0.01 at 7:40:55 UT. \nWe calibrated the OT to the USNO-B1.0 R2 band magnitudes of several \nnearby stars. We find that the early ABC data fades as a power law decay \nwith  index  ~1.9.\n\nWe note that the lightcurve has a flatter decay index after about 2000 \nseconds. This may be partially due to contamination from the nearby \n10.79 mag star that will be resolved by more careful analysis. It is \npossible that the OT is still visible (< 22nd mag).\n\nFurther observations are planned."}', 'The MARGE collaboration, using the AEOS Burst Camera on the AEOS telescope, observed the fading counterpart of GRB07103 (Swift trigger 292934) and detected an optical transient (OT) with an approximate magnitude of 16.04. The OT decayed as a power law with an index of ~1.9 in the early stages, but became flatter after about 2000 seconds due to contamination from a nearby star. Further observations are planned.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6840', 'gcn', 'GRB 071003', '2007-10-03T17:50:25.000Z', '{"measurements":{"dec":null,"distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":17,"other_measurements":{"exposure_time":300,"time_after_burst":7.5},"ra":null,"redshift":null,"tables":[]},"authors":{"affiliations":["ARIES, Nainital, India","IAA, Granada"],"authors":["K. Misra","S. B. Pandey","Rupak Roy","Alberto J. Castro-Tirado"],"institutions":["ARIES, Nainital, India","IAA, Granada"],"universities":["ARIES, Nainital, India","IAA, Granada"]},"telescopes":{"facilities":[],"instruments":[],"observatories":[],"telescopes":["1.04 m Sampurnanand Telescope"]},"urls":["https://gcn.gsfc.nasa.gov/gcn3/gcn3_circulars.cfm?id=6838","https://gcn.gsfc.nasa.gov/gcn3/gcn3_circulars.cfm?id=6839","https://gcn.gsfc.nasa.gov/gcn3/gcn3_circulars.cfm?id=6837"],"basic_data":{"author":{"email":"kuntal@aries.ernet.in","institution":"ARIES,Nainital,India","name":"Kuntal Mishra"},"coordinates":{},"detectionTime":"2007-10-03T17:50:25.000Z","event":"GRB 071003","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6840\nSUBJECT: GRB 071003 Optical observations\nDATE: 07/10/03 17:50:25 GMT\nFROM: Kuntal Mishra at ARIES,Nainital,India  <kuntal@aries.ernet.in>\n\nK. Misra, S. B. Pandey, Rupak Roy (ARIES, NainiTal, India) and Alberto\nJ. Castro-Tirado (IAA, Granada) on behalf of larger Indian GRB collaboration\n\nThe Swift GRB 071003 (Schady et al. GCN 6837) was observed using 1.04 m\nSampurnanand Telescope. The optical afterglow candidate reported by Li\n(GCN 6838), Cenko & Fox (GCN 6839) is clearly seen in U and B band \nframes in 300 sec exposure each. The fading nature of the source is seen\nand U ~ 17 mag was measured around 7.5 hours after the burst. The \ncontamination due\nto the nearby bright stars makes the photometry complicated. Multiband\nobservations and detailed observations are underway.\n\nThis message may be cited."}', 'The Swift gamma-ray burst GRB 071003, observed by Schady et al., was detected as an optical afterglow using the 1.04m Sampurnanand Telescope at ARIES, Nainital, India. The source was seen in U and B band frames with a magnitude of approximately 17 around 7.5 hours after the burst. Detailed and multiband observations are ongoing.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-684', 'gcn', 'GRB000529', '2000-06-01T19:20:07.000Z', '{"measurements":{"dec":-61.465,"distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":null,"other_measurements":{"error_radius":"2''","time_after_grb":"7.5 hours"},"ra":2.451,"redshift":null,"tables":[]},"authors":{"affiliations":["IAS/CNR Frascati"],"authors":["Giangiacomo Gandolfi"],"institutions":["IAS/CNR"],"universities":["IAS/CNR"]},"telescopes":{"facilities":["BeppoSAX"],"instruments":["Narrow Field Instruments","MECS"],"observatories":[],"telescopes":["BeppoSAX"]},"urls":[],"basic_data":{"author":{"email":"gandolfi@ias.rm.cnr.it","institution":"IAS/CNR Frascati","name":"Giangiacomo Gandolfi"},"coordinates":{"dec":4.083611111111111},"detectionTime":"2000-06-01T19:20:07.000Z","event":"GRB000529","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 684\nSUBJECT: GRB000529: BeppoSAX NFI follow-up preliminary analysis\nDATE: 00/06/01 19:20:07 GMT\nFROM: Giangiacomo Gandolfi at IAS/CNR Frascati  <gandolfi@ias.rm.cnr.it>\n\nA BeppoSAX follow up of GRB000529 with the Narrow Field Instruments\nstarted around May 29 at 16:10 UT, i.e. about 7.5 hours after the GRB.\n\nA preliminary analysis of the MECS (1.6-10 keV) data shows a possibly\nfading source in the field.\n\nR.A.(2000)= 2.451\nDEC(2000)= -61.465\n\nwith an error radius of 2''.\n\nA more detailed analysis is in progress.\n\nG. Gandolfi\non behalf of BeppoSAX Mission Scientist"}', 'A preliminary analysis of BeppoSAX NFI data for GRB000529 reveals a possible fading source with coordinates R.A.(2000) = 2.451, DEC(2000) = -61.465 and an error radius of 2''. A more detailed analysis is ongoing.', 0.8, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6839', 'gcn', 'GRB 071003', '2007-10-03T10:58:39.000Z', '{"measurements":{"dec":null,"distance":null,"duration":"3 minutes","energy":null,"fluence":null,"magnitude":14.5,"other_measurements":{"airmass":2.5,"decay_index":-1},"ra":null,"redshift":null,"tables":[]},"authors":{"affiliations":["Caltech (for S. B. Cenko)","Penn State (for D. B. Fox)"],"authors":["S. B. Cenko","D. B. Fox"],"institutions":["Caltech","Penn State"],"universities":["Caltech","Penn State"]},"telescopes":{"facilities":[],"instruments":[],"observatories":[],"telescopes":["Palomar 60-inch telescope"]},"urls":["http://gcn.gsfc.nasa.gov/gcn/gcn3_batch.msf?6837"],"basic_data":{"author":{"email":"cenko@srl.caltech.edu","institution":"Caltech","name":"S. Bradley Cenko"},"coordinates":{},"detectionTime":"2007-10-03T10:58:39.000Z","event":"GRB 071003","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6839\nSUBJECT: GRB 071003: P60 Confirmation of Optical Afterglow\nDATE: 07/10/03 10:58:39 GMT\nFROM: S. Bradley Cenko at Caltech  <cenko@srl.caltech.edu>\n\nS. B. Cenko (Caltech) and D. B. Fox (Penn State) report on behalf of a\nlarger collaboration:\n\nWe have imaged the field of GRB071003 (Schady et al., GCN 6837) with the\nautomated Palomar 60-inch telescope.  Observations began approximately 3\nminutes after the burst (~ 07:44 UT 10 October) and were taken at high\nairmass (~ 2.5).  At the location of the optical afterglow candidate (Li,\nGCN 6838) we detect a fading source in the g, R, i'', and z'' filters.\nWhile photometry is complicated by the nearby bright star (Li, GCN 6838),\nwe estimate a magnitude of R ~ 14.5 in our first 60 s image (photometric\ncalibration was performed relative to several nearby objects from the\nUSNO-B catalog).  The corresponding decay index is ~ -1.0."}', 'Astronomers at Caltech and Penn State report the detection of the optical afterglow of GRB 071003 using the Palomar 60-inch telescope three minutes after the gamma-ray burst. The source was detected in the g, R, i'', and z'' filters, with an estimated magnitude of R ~ 14.5 and a decay index of ~ -1.0.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6838', 'gcn', 'GRB 071003', '2007-10-03T09:59:17.000Z', '{"measurements":{"dec":"+10:56:51.8","distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":12.8,"other_measurements":{"exposure_time":"5s"},"ra":"20:07:24.12","redshift":null,"tables":[]},"authors":{"affiliations":["University of California, Berkeley","KAIT/LOSS"],"authors":["W. Li"],"institutions":["UC Berkeley","KAIT/LOSS"],"universities":["University of California, Berkeley"]},"telescopes":{"facilities":[],"instruments":[],"observatories":["Lick Observatory"],"telescopes":["Katzman Automatic Imaging Telescope (KAIT)"]},"urls":["http://astro.berkeley.edu/~weidong/grb071003.finder.gif","<http://astro.berkeley.edu/~weidong/grb071003.finder.gif>"],"basic_data":{"author":{"email":"weidong@astron.berkeley.edu","institution":"UC Berkeley KAIT/LOSS","name":"Weidong Li"},"coordinates":{"dec":20.123366666666666},"detectionTime":"2007-10-03T09:59:17.000Z","event":"GRB 071003","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6838\nSUBJECT: GRB 071003: KAIT optical afterglow observations\nDATE: 07/10/03 09:59:17 GMT\nFROM: Weidong Li at UC Berkeley KAIT/LOSS  <weidong@astron.berkeley.edu>\n\nW. Li, University of California, Berkeley, on behalf of the KAIT GRB\nteam, report:\n\nThe robotic 0.76-m Katzman Automatic Imaging Telescope (KAIT) at Lick\nObservatory observed GRB 071003 detected with Swift (Trigger 292934;\nSchady et al. GCN 6837). The automatic sequence started at 07:41:37,\n42 s after the burst. The BAT location has been monitored in V, I,\nand clear filters, with varying exposure times. Our image processing\npipeline found a new object within the BAT error circle, with the\nfollowing position:\n\nR. A. = 20:07:24.12\nDEC.  = +10:56:51.8  (J2000)\n\nThe OA has magnitude of 12.8 (calibrated with USNO B1.0) in a 5s\nunfiltered exposure started at 07:41:37 UT, 42s after the BAT trigger.\nThe new object is close to a bright foreground star. Further Analysis\nis ongoing. A finder chart can be found at \nhttp://astro.berkeley.edu/~weidong/grb071003.finder.gif\n\nThis message may be cited."}', 'The KAIT team at UC Berkeley reported the discovery of an optical afterglow of GRB 071003 using the Katzman Automatic Imaging Telescope at Lick Observatory. The new object, located at R.A. = 20:07:24.12, DEC. = +10:56:51.8 (J2000), was detected 42 seconds after the gamma-ray burst and had a magnitude of 12.8 in a 5s unfiltered exposure.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6837', 'gcn', 'GRB 071003', '2007-10-03T07:53:48.000Z', '{"measurements":{"dec":"+10d 57'' 35\"","distance":null,"duration":"25 sec","energy":null,"fluence":null,"magnitude":null,"other_measurements":{"peak_count_rate":"~16000 counts/sec (15-350 keV)","uncertainty_radius":"3 arcmin"},"ra":"20h 07m 25s","redshift":null,"tables":[]},"authors":{"affiliations":["MSSL-UCL (University of Leicester)","U Leicester","NASA/GSFC","CRESST/USRA/GSFC","PSU","Univ Bicocca&INAF-OAB","LANL"],"authors":["P. Schady","P. A. Evans","N. Gehrels","C. Guidorzi","S. T. Holland","J. A. Kennea","C. B. Markwardt","P. T. O''Brien","K. L. Page","D. M. Palmer","G. Sato","R. L. C. Starling"],"institutions":["MSSL-UCL","U Leicester","NASA/GSFC","CRESST/USRA/GSFC","PSU","Univ Bicocca&INAF-OAB"],"universities":["University of Leicester","University of Maryland","University of California, Los Angeles","University of Sussex","Penn State University","University of Bicocca","Institute of Space and Astronautical Science (ISAS)"]},"telescopes":{"facilities":[],"instruments":[],"observatories":[],"telescopes":["Swift Burst Alert Telescope (BAT)"]},"urls":["http://www.swift.psu.edu/too.html"],"basic_data":{"author":{"email":"palmer@lanl.gov","institution":"LANL","name":"David Palmer"},"coordinates":{"dec":3.0005155555555554},"detectionTime":"2007-10-03T07:53:48.000Z","event":"GRB 071003","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6837\nSUBJECT: GRB 071003: Swift detection of a bright burst\nDATE: 07/10/03 07:53:48 GMT\nFROM: David Palmer at LANL  <palmer@lanl.gov>\n\nP. Schady (MSSL-UCL), P. A. Evans (U Leicester),\nN. Gehrels (NASA/GSFC), C. Guidorzi (Univ Bicocca&INAF-OAB),\nS. T. Holland (CRESST/USRA/GSFC), J. A. Kennea (PSU),\nC. B. Markwardt (CRESST/GSFC/UMD), P. T. O''Brien (U Leicester),\nK. L. Page (U Leicester), D. M. Palmer (LANL), G. Sato (GSFC/ISAS)\nand R. L. C. Starling (U Leicester) report on behalf of the Swift\nTeam:\n\nAt 07:40:55 UT, the Swift Burst Alert Telescope (BAT) triggered and\nlocated GRB 071003 (trigger=292934). The BAT on-board calculated location is \nRA, Dec 301.856, +10.960 which is \n   RA(J2000) = 20h 07m 25s\n   Dec(J2000) = +10d 57'' 35\"\nwith an uncertainty of 3 arcmin (radius, 90% containment, including \nsystematic uncertainty).  The BAT light curve showed a multi-peaked \nstructure with a duration of about 25 sec.  The peak count rate\nwas ~16000 counts/sec (15-350 keV), at ~0 sec after the trigger. \n\nBecause Swift is in the process of returning to normal operations, \nautomatic slewing to GRBs is currently disabled outside of\nbusiness hours (US EDT).  Therefore, there \nare no prompt XRT or UVOT observations of this burst. \n\nBurst Advocate for this burst is P. Schady (ps AT mssl.ucl.ac.uk). \nPlease contact the BA by email if you require additional information\nregarding Swift followup of this burst. In extremely urgent cases, after\ntrying the Burst Advocate, you can contact the Swift PI by phone (see\nSwift TOO web site for information: http://www.swift.psu.edu/too.html.)"}', 'The Swift Burst Alert Telescope (BAT) detected a bright gamma-ray burst (GRB 071003) with a multi-peaked structure and a peak count rate of ~16000 counts/sec (15-350 keV) at 07:40:55 UT. The burst occurred at RA(J2000) = 20h 07m 25s, Dec(J2000) = +10d 57'' 35', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6836', 'gcn', 'GRB 070714B', '2007-10-02T00:36:25.000Z', '{"measurements":{"dec":null,"distance":null,"duration":{"main_component":3,"soft_tail":null},"energy":1.6e+51,"fluence":7.2e-7,"magnitude":null,"other_measurements":{},"ra":null,"redshift":0.92,"tables":[]},"authors":{"affiliations":["STScI/JHU","STScI","U. Warwick","STScI","U. Leicester","STScI","Liverpool John Moores U.","STScI"],"authors":["J. F. Graham","A. S. Fruchter","A. J. Levan","M. Nysewander","N. R. Tanvir","T. Dahlen","D. Bersier","A. Pe''er"],"institutions":["STScI","U. Warwick","STScI/JHU"],"universities":["Johns Hopkins University","University of Leicester","Liverpool John Moores University"]},"telescopes":{"facilities":[],"instruments":["Nod & Shuffle spectroscopy","GMOS","NIRI"],"observatories":[],"telescopes":["Gemini"]},"urls":["https://gcn.gsfc.nasa.gov"],"basic_data":{"author":{"email":"graham@stsci.edu","institution":"STScI","name":"John Graham"},"coordinates":{},"detectionTime":"2007-10-02T00:36:25.000Z","event":"GRB 070714B","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6836\nSUBJECT: GRB 070714B: host galaxy spectroscopic redshift\nDATE: 07/10/02 00:36:25 GMT\nFROM: John Graham at STScI  <graham@stsci.edu>\n\nJ. F. Graham (STScI/JHU), A. S. Fruchter (STScI), A. J. Levan (U. \nWarwick), M. Nysewander (STScI), N. R. Tanvir (U. Leicester), T. Dahlen \n(STScI), D. Bersier (Liverpool John Moores U.), A. Pe''er (STScI) report \non behalf of a larger collaboration:\n\nGemini Nod & Shuffle spectroscopy on the host of GRB 070714B shows a \nsingle emission line at 7165 A.  A photometric redshift based on Gemini \ngrizJHK observations with GMOS and NIRI strongly implies that this is \nthe 3727 A [O II] line.  This places the host at a redshift of z=.92\n\nThe Swift BAT discovery data show the burst to have had a short, hard \nmain component of three seconds duration followed by a soft, longer \nduration tail (Sakamoto et al. GCN 6623).  The main component also shows \na small spectral lag (Norris et al. GCN 6631).  Both of these \nobservations are consistent with GRB 070714B being a short GRB.  This \nthen would be the highest spectroscopically confirmed redshift of a \nshort burst.\n\nThe observed fluence of 7.2 x 10^-7 erg/cm^2 (Barbier et al. GCN 6638) \nat a redshift of z=.92 corresponds to an isotropic energy release of \nEiso = 1.6 x 10^51 erg."}', 'Astronomers report the discovery of a short gamma-ray burst, GRB 070714B, with a spectroscopic redshift of 0.92, making it the highest redshift yet observed for a short burst. The burst is estimated to have released isotropic energy of 1.6 x 10^51 erg.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6835', 'gcn', 'GRB 071001', '2007-10-02T00:32:22.000Z', '{"measurements":{"dec":"-59 46 54.5","distance":null,"duration":37,"energy":null,"fluence":null,"magnitude":null,"other_measurements":{"alpha":3,"alpha_uncertainty":0.2,"break_time":310,"galactic_column_density":7.6e+21,"galactic_column_density_unit":"cm^-2","gamma":2.2,"gamma_uncertainty_negative":0.4,"gamma_uncertainty_positive":0.5,"observed_flux":4.2e-10,"observed_flux_unit":"erg cm^-2 s^-1","unabsorbed_flux":2e-9,"unabsorbed_flux_unit":"erg cm^-2 s^-1"},"ra":"09 58 56.07","redshift":null,"tables":[]},"authors":{"affiliations":["U. of Leicester","UCL-MSSL"],"authors":["K.L. Page","A.P. Beardmore","M. De Pasquale"],"institutions":["U. Leicester","UCL-MSSL"],"universities":["U. of Leicester"]},"telescopes":{"facilities":[],"instruments":["Swift-XRT"],"observatories":[],"telescopes":["Swift"]},"urls":["http://gcn.gsfc.nasa.gov"],"basic_data":{"author":{"email":"kpa@star.le.ac.uk","institution":"U.of Leicester","name":"Kim Page"},"coordinates":{"dec":9.982241666666667},"detectionTime":"2007-10-02T00:32:22.000Z","event":"GRB 071001","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6835\nSUBJECT: GRB 071001: Swift-XRT Team refined analysis\nDATE: 07/10/02 00:32:22 GMT\nFROM: Kim Page at U.of Leicester  <kpa@star.le.ac.uk>\n\nK.L. Page, A.P. Beardmore (U. Leicester) and M. De Pasquale (UCL-MSSL) \nreport on behalf of the Swift-XRT team:\n\nWe have analysed the two orbits of Swift-XRT data obtained for GRB 071001 \n(De Pasquale et al., GCN Circ. 6832), totalling 37 seconds of Windowed \nTiming (WT) data and 1.3 ks of Photon Counting mode data. Because of a \ntemporary problem with the star trackers, we use only the data when the \nattitude can be said to be stable to find a refined position of RA, Dec = \n149.7336, -59.7818, which is equivalent to:\n\nRA(J2000):   09 58 56.07\nDec(J2000): -59 46 54.5\n\nwith an estimated uncertainty of 6 arcsec (radius, 90% containment \nincluding boresight uncertainty). This is 83 arcsec from the \nground-calculated BAT position (Stamatikos et al., GCN Circ. 6834) and 6.2 \narcsec from the initial XRT position quoted in GCN Circ. 6832.\n\nThe X-ray light-curve shows an initial steep decay, with alpha = \n3.0 +/- 0.2, breaking at about 310 seconds after the trigger to a flatter \nslope of 0.2 +/- 0.1.\n\nThe WT spectrum (89-120 seconds after the trigger) can be modelled by a \npower-law of Gamma = 2.2 +0.5/-0.4, absorbed by the Galactic column in \nthis direction of 7.6e21 cm^-2. The 0.3-10 keV observed (unabsorbed) flux \nduring this time is 4.2e-10 (2.0e-9) erg cm^-2 s^-1.\n\nWith only 2 orbits of data, predicting the count rate at 24 hours would \nnot lead to an accurate result. No further Swift observations of this \nburst are planned.\n\nThis circular is an official product of the Swift-XRT team."}', 'The Swift-XRT team analyzed Swift data for GRB 071001, finding a refined position with an uncertainty of 6 arcsec and measuring an initial steep decay with a break time of 310 seconds and a flatter slope afterwards. The X-ray spectrum was modeled by a power-law with an absorption by the Galactic column. The estimated observed flux during the analyzed time was $4.2	imes10^{-10}$ erg cm$^{-2}$ s$^{-1}$. Due to limited data, predicting the count rate at 24 hours was not accurate, and no further Swift observations were planned.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6834', 'gcn', 'GRB 071001', '2007-10-01T22:51:11.000Z', '{"measurements":{"dec":"-59.763","distance":null,"duration":"58.5 +- 1.0 sec","energy":null,"fluence":"7.7 +- 0.8 x 10^-7 erg/cm2","magnitude":null,"other_measurements":{"partial_coding":"85%","peak_photon_flux":"0.9 +- 0.1 ph/cm2/sec","power_law_index":"1.62 +- 0.17"},"ra":"149.707","redshift":null,"tables":[]},"authors":{"affiliations":["GSFC/ORAU","GSFC","GSFC/UMBC","GSFC/UMD","GSFC/USRA","GSFC","GSFC/ISAS","GSFC/UMD","LANL","GSFC","UCL-MSSL","GSFC/UMBC","GSFC/ISAS","GSFC","GWU"],"authors":["M. Stamatikos","L. Barbier","S. D. Barthelmy","J. Cummings","E. Fenimore","N. Gehrels","H. Krimm","C. Markwardt","D. Palmer","A. Parsons","M. De Pasquale","T. Sakamoto","G. Sato","J. Tueller","T. Ukwatta"],"institutions":["NASA/GSFC","ORAU","UMBC","LANL","USRA"],"universities":["University of Maryland, Baltimore County (UMBC)","University of Maryland, College Park (UMD)","George Washington University (GWU)","Los Alamos National Laboratory (LANL)","International Space Science Institute (ISAS)"]},"telescopes":{"facilities":[],"instruments":[],"observatories":[],"telescopes":[]},"urls":["http://gcn.gsfc.nasa.gov"],"basic_data":{"author":{"email":"scott@lheamail.gsfc.nasa.gov","institution":"NASA/GSFC","name":"Scott Barthelmy"},"coordinates":{},"detectionTime":"2007-10-01T22:51:11.000Z","event":"GRB 071001","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6834\nSUBJECT: GRB 071001, Swift-BAT refined analysis\nDATE: 07/10/01 22:51:11 GMT\nFROM: Scott Barthelmy at NASA/GSFC  <scott@lheamail.gsfc.nasa.gov>\n\nM. Stamatikos (GSFC/ORAU), L. Barbier (GSFC), S. D. Barthelmy (GSFC),\nJ. Cummings (GSFC/UMBC), E. Fenimore (LANL), N. Gehrels (GSFC),\nH. Krimm (GSFC/USRA), C. Markwardt (GSFC/UMD), D. Palmer (LANL),\nA. Parsons (GSFC), M. De Pasquale (UCL-MSSL), T. Sakamoto (GSFC/UMBC),\nG. Sato (GSFC/ISAS), J. Tueller (GSFC), T. Ukwatta (GWU)\n(i.e. the Swift-BAT team):\n \nUsing the data set from T-119 to T+183 sec from recent telemetry downlinks,\nwe report further analysis of BAT GRB 071001 (trigger #292826)\n(De Pasquale, et al., GCN Circ. 6832).  The BAT ground-calculated position is\nRA, Dec = 149.707, -59.763 deg which is \n   RA(J2000)  =  09h 58m 49.7s \n   Dec(J2000) = -59d 45'' 48\" \nwith an uncertainty of 2.0 arcmin, (radius, sys+stat, 90% containment).\nThe partial coding was 85%.\n \nThe mask-weighted light curve shows two main peaks: 1) starting/peaking/ending\nat ~T-20/0/+30 sec, resp; 2) T+40/+48/+70; and a much weaker (~3 sigma) peak:\n~T+70/+90/+100 sec.  T90 (15-350 keV) is 58.5 +- 1.0 sec (estimated error\nincluding systematics).\n \nThe time-averaged spectrum from T-1.6 to T+64.7 sec is best fit by a simple\npower-law model.  The power law index of the time-averaged spectrum is\n1.62 +- 0.17.  The fluence in the 15-150 keV band is 7.7 +- 0.8 x 10^-7 erg/cm2.\nThe 1-sec peak photon flux measured from T+48.14 sec in the 15-150 keV band\nis 0.9 +- 0.1 ph/cm2/sec.  All the quoted errors are at the 90% confidence\nlevel."}', 'Astronomers have refined the analysis of GRB 071001 (Swift-BAT trigger #292826) using data from the first 183 seconds after the gamma-ray burst. The ground-calculated position is reported with an uncertainty of 2.0 arcmin, and the light curve shows two main peaks and a weaker peak. The time-averaged spectrum is best fit by a power-law model with a power law index of 1.62 +- 0.17. The fluence in the 15-150 keV band is 7.7 +- 0.8 x 10^-7 erg/cm2, and the 1-sec peak photon flux is 0.9 +- 0.1 ph/cm2/sec.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6833', 'gcn', 'GRB 071001', '2007-10-01T18:05:27.000Z', '{"measurements":{"dec":null,"distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":{"mR":19.5},"other_measurements":{},"ra":null,"redshift":null,"tables":[]},"authors":{"affiliations":["Liverpool JMU","U. Bicocca & INAF-OAB"],"authors":["D. Bersier","C. Guidorzi","R. Smith"],"institutions":["Liverpool John Moores U","U. Bicocca","INAF-OAB"],"universities":["Liverpool JMU","U. Bicocca","INAF-OAB"]},"telescopes":{"facilities":[],"instruments":[],"observatories":[],"telescopes":["Faulkes Telescope South"]},"urls":["http://astro.livjm.ac.uk"],"basic_data":{"author":{"email":"dfb@astro.livjm.ac.uk","institution":"Liverpool John Moores U","name":"David Bersier"},"coordinates":{},"detectionTime":"2007-10-01T18:05:27.000Z","event":"GRB 071001","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6833\nSUBJECT: Faulkes Telescope South observations of GRB 071001\nDATE: 07/10/01 18:05:27 GMT\nFROM: David Bersier at Liverpool John Moores U  <dfb@astro.livjm.ac.uk>\n\nD. Bersier (Liverpool JMU), C. Guidorzi (U. Bicocca & INAF-OAB),\nR. Smith (Liverpool JMU) report on behalf of a larger collaboration:\n\nWe observed the field of GRB 071001 (Swift trigger 292826, GCN 6832)\nwith the Faulkes Telescope South in BVRi filters.  We do not detect\nany variable object within the XRT error circle down to mR=19.5\n(calibrated with respect to USNO-B).\n\nWe note that a fairly bright object within the XRT error circle may\ncomplicate the analysis."}', 'The Faulkes Telescope South team, including researchers from Liverpool John Moores University, U. Bicocca, and INAF-OAB, reported no detection of a variable object within the error circle of GRB 07101 (Swift trigger 292826, GCN 6832) in BVRi filters down to a magnitude of mR=19.5.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6832', 'gcn', 'GRB 071001', '2007-10-01T16:54:59.000Z', '{"measurements":{"dec":"-59d 45'' 02\"","distance":null,"duration":"50 sec","energy":null,"fluence":null,"magnitude":null,"other_measurements":{"initial_flux":"1.5e-09 erg/cm2/s (0.2-10 keV)","peak_count_rate":"~1500 counts/sec (15-350 keV)"},"ra":"09h 59m 04s","redshift":null,"tables":[]},"authors":{"affiliations":["LANL","UCL-MSSL","GSFC","INAF-OAB","NASA/UMBC","U Leicester","CRESST/USRA/GSFC","GSFC/GWU","INAF-IASFPA"],"authors":["M. De Pasquale","S. D. Barthelmy","A. P. Beardmore","S. Campana","J. R. Cummings","P. A. Evans","N. Gehrels","C. Gronwall","C. Guidorzi","S. T. Holland","H. A. Krimm","V. Mangano","C. B. Markwardt","F. E. Marshall","A. Moretti","C. Pagani","K. L. Page","D. M. Palmer","J. L. Racusin","G. Sato","M. Stamatikos","R. L. C. Starling","E. Troja","T. N. Ukwatta","L. Vetere"],"institutions":["LANL","UCL-MSSL","GSFC","INAF-OAB","NASA/UMBC","U Leicester","CRESST/USRA/GSFC","GSFC/GWU","INAF-IASFPA"],"universities":["UCL","PSU","GSFC","UMBC","NASA","UMD","ISAS","ORAU"]},"telescopes":{"facilities":[],"instruments":["Swift X-ray Telescope (XRT)"],"observatories":[],"telescopes":["Swift Burst Alert Telescope (BAT)"]},"urls":["http://www.swift.psu.edu/too.html"],"basic_data":{"author":{"email":"palmer@lanl.gov","institution":"LANL","name":"David Palmer"},"coordinates":{"dec":1.0693794444444444},"detectionTime":"2007-10-01T16:54:59.000Z","event":"GRB 071001","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6832\nSUBJECT: GRB 071001: Swift detection of a burst\nDATE: 07/10/01 16:54:59 GMT\nFROM: David Palmer at LANL  <palmer@lanl.gov>\n\nM. De Pasquale (UCL-MSSL), S. D. Barthelmy (GSFC),\nA. P. Beardmore (U Leicester), S. Campana (INAF-OAB),\nJ. R. Cummings (NASA/UMBC), P. A. Evans (U Leicester),\nN. Gehrels (NASA/GSFC), C. Gronwall (PSU),\nC. Guidorzi (Univ Bicocca&INAF-OAB),\nS. T. Holland (CRESST/USRA/GSFC), H. A. Krimm (GSFC/USRA),\nV. Mangano (INAF-IASFPA), C. B. Markwardt (CRESST/GSFC/UMD),\nF. E. Marshall (NASA/GSFC), A. Moretti (INAF-OAB), C. Pagani (PSU),\nK. L. Page (U Leicester), D. M. Palmer (LANL), J. L. Racusin (PSU),\nG. Sato (GSFC/ISAS), M. Stamatikos (NASA/ORAU),\nR. L. C. Starling (U Leicester), E. Troja (INAF-IASFPA),\nT. N. Ukwatta (GSFC/GWU) and L. Vetere (PSU) report on behalf of the\nSwift Team:\n\nAt 16:31:48 UT, the Swift Burst Alert Telescope (BAT) triggered and\nlocated GRB 071001 (trigger=292826).  Swift slewed immediately to the burst. \nThe BAT on-board calculated location is \nRA, Dec 149.766, -59.751 which is \n   RA(J2000) = 09h 59m 04s\n   Dec(J2000) = -59d 45'' 02\"\nwith an uncertainty of 3 arcmin (radius, 90% containment, including \nsystematic uncertainty).  The BAT light curve shows two isolated peaks\nspanning a duration of about 50 sec.  The peak count rate\nwas ~1500 counts/sec (15-350 keV), at ~0 sec after the trigger. \n\nThe XRT began observing the field at 16:33:10 UT, 83 seconds after the\nBAT trigger. Using prompt downlinked data, we find a bright, variable, \nuncatalogued X-ray source located at RA, Dec 149.7302, -59.7819 which is\n   RA(J2000)  = 09h 58m 55.25s\n   Dec(J2000) = -59d 46'' 54.8\"\nwith an uncertainty of 6.0 arcsec (radius, 90% containment). \nThis location is 129 arcseconds from the BAT on-board position,\nwithin the BAT error circle. The initial flux in the 2.5s image\nwas 1.5e-09 erg/cm2/s (0.2-10 keV). \n\nThe star tracker during the XRT observation has detected and\nidentified three valid stars, however the attitude solution quality\nis worse than normal.  Therefore, there may be some additional \nsystematic error in the quoted positions. \n\nBurst Advocate for this burst is M. De Pasquale (mdp AT mssl.ucl.ac.uk). \nPlease contact the BA by email if you require additional information\nregarding Swift followup of this burst. In extremely urgent cases, after\ntrying the Burst Advocate, you can contact the Swift PI by phone (see\nSwift TOO web site for information: http://www.swift.psu.edu/too.html.)"}', 'The Swift satellite detected a gamma-ray burst (GRB 071001) with a peak count rate of ~1500 counts/sec (15-350 keV) and a duration of about 50 sec. The X-ray Telescope (XRT) identified a bright, variable X-ray source located near the burst position, with an initial flux of 1.5e-09 erg/cm2/s (0.2-10 keV). The precise coordinates of the X-ray source are still being determined.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6831', 'gcn', 'GRB  070923', '2007-09-28T20:55:19.000Z', '{"measurements":{"dec":null,"distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":null,"other_measurements":{"flux_density_upper_limit":"90 microJy","frequency":"8.46 GHz","observation_start_time":"18.70 UT on Sept 28, 2007"},"ra":null,"redshift":null,"tables":[]},"authors":{"affiliations":["UVA/NRAO","NRAO"],"authors":["Poonam Chandra","D. A. Frail"],"institutions":["NRAO","Caltech-NRAO-Carnegie GRB Collaboration"],"universities":["University of Virginia"]},"telescopes":{"facilities":["National Science Foundation"],"instruments":[],"observatories":["National Radio Astronomy Observatory"],"telescopes":["VLA"]},"urls":["https://gcn.gsfc.nasa.gov/gcn3/gcn3_circular_detail.jsp?id=6831"],"basic_data":{"author":{"email":"pc8s@virginia.edu","institution":"U Virginia/NRAO","name":"Poonam Chandra"},"coordinates":{},"detectionTime":"2007-09-28T20:55:19.000Z","event":"GRB  070923","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6831\nSUBJECT: VLA observation of GRB  070923\nDATE: 07/09/28 20:55:19 GMT\nFROM: Poonam Chandra at U Virginia/NRAO  <pc8s@virginia.edu>\n\nP. Chandra (UVA/NRAO) and  D. A. Frail (NRAO) report on behalf of the\nCaltech-NRAO-Carnegie GRB\nCollaboration:\n\n\"We observed the field centered on the BAT position of the Swift short\nhard burst GRB 070923 (GCN#6818) using the VLA at a frequency of 8.46 GHz\nand starting at 18.70 UT on Sept 28, 2007, about 5 days after the burst. \nThere is no detection of the afterglow at the GRB Swift-BAT position\n(GCN#6821 )with 2-sigma upper limit of 90 microJy on its flux density.\n\nThe National Radio Astronomy Observatory is a facility of the National\nScience Foundation operated under cooperative agreement by Associated\nUniversities, Inc.\""}', 'The Caltech-NRAO-Carnegie GRB Collaboration, including Poonam Chandra from UVA/NRAO and D. A. Frail from NRAO, reported no detection of the afterglow of short hard burst GRB 070923 using the VLA radio telescope at a frequency of 8.46 GHz, with a 2-sigma upper limit of 90 microJy on its flux density.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6830', 'gcn', 'Disregard the Swift-XRT Notices today', '2007-09-27T21:44:37.000Z', '{"measurements":{"dec":null,"distance":null,"duration":"40 minutes","energy":null,"fluence":null,"magnitude":null,"other_measurements":{},"ra":null,"redshift":null,"tables":[]},"authors":{"affiliations":["NASA/GSFC"],"authors":["S. Barthelmy"],"institutions":["NASA/GSFC"],"universities":["NASA/GSFC"]},"telescopes":{"facilities":[],"instruments":[],"observatories":[],"telescopes":[]},"urls":["<mailto:scott@lheamail.gsfc.nasa.gov>"],"basic_data":{"author":{"email":"scott@lheamail.gsfc.nasa.gov","institution":"NASA/GSFC","name":"Scott Barthelmy"},"coordinates":{},"detectionTime":"2007-09-27T21:44:37.000Z","event":"Disregard the Swift-XRT Notices today","eventType":"AT","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6830\nSUBJECT: Disregard the Swift-XRT Notices today\nDATE: 07/09/27 21:44:37 GMT\nFROM: Scott Barthelmy at NASA/GSFC  <scott@lheamail.gsfc.nasa.gov>\n\nS. Barthelmy (GSFC)\n\nPlease disregard the series of GCN/Swift-XRT Notices between 19:30 and 20:10 UT.\nThe XRT sience team was conducting a series of calibration pointings.  I was \nsupposed to have instituted the block-to-world filter for the XRT Notices,\nbut I forgot.  My apologies for the everyone''s inconvenience."}', 'An apology was issued for a series of false Swift-XRT Notices sent between 19:30 and 20:10 UT on July 27, 2023 due to a calibration team''s oversight.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-683', 'gcn', 'GRB000528', '2000-05-31T17:34:20.000Z', '{"measurements":{"dec":[-33.975,-33.986],"distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":null,"other_measurements":{"error_radius":"1.5''"},"ra":[161.365,161.287],"redshift":null,"tables":[]},"authors":{"affiliations":["IAS/CNR Frascati"],"authors":["Giangiacomo Gandolfi"],"institutions":["IAS/CNR Frascati"],"universities":[]},"telescopes":{"facilities":[],"instruments":["Narrow Field Instruments","MECS"],"observatories":[],"telescopes":["BeppoSAX"]},"urls":[""],"basic_data":{"author":{"email":"gandolfi@ias.rm.cnr.it","institution":"IAS/CNR Frascati","name":"Giangiacomo Gandolfi"},"coordinates":{"dec":1.1003791666666667},"detectionTime":"2000-05-31T17:34:20.000Z","event":"GRB000528","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 683\nSUBJECT: GRB000528: BeppoSAX NFI follow-up preliminary analysis\nDATE: 00/05/31 17:34:20 GMT\nFROM: Giangiacomo Gandolfi at IAS/CNR Frascati  <gandolfi@ias.rm.cnr.it>\n\nA BeppoSAX follow up of GRB000528 with the Narrow Field Instruments\nstarted around May 28 at 20:50 UT, i.e. about 12 hours after the GRB.\n\nPreliminary analysis of the MECS (1.6-10 keV) data shows\ntwo previously unknown sources inside the field. The preliminary WFC error\nbox (BeppoSAX Mail #10) contains both objects, while the refined one\n(BeppoSAX Mail #11 and GCN 677) only the second.\n\nObject #1:\n\nR.A.(2000)= 161.365\nDEC(2000)= -33.975\n\nObject #2:\n\nR.A.(2000)= 161.287\nDEC(2000)= -33.986\n\nboth with  an error radius of 1.5''.\n\nThe source #1 is possibly fading, while the #2 seems to be consistent with\na constant flux. Further and more detailed analysis are in progress.\n\nG. Gandolfi\non behalf of BeppoSAX Mission Scientist"}', 'A preliminary analysis of BeppoSAX NFI data for GRB000528 reveals the detection of two new sources, one of which may be fading. The sources, located at RA(2000): 161.365, DEC(2000): -33.975 and RA(2000): 161.287, DEC(2000): -33.986, have an error radius of 1.5''. Further analysis is ongoing.', 0.9, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6829', 'gcn', 'GRB 070911', '2007-09-27T20:39:59.000Z', '{"measurements":{"dec":"-33:29:02.5","distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":{"I":[{"time":"2.05 days","uncertainty":0.1,"value":20.9},{"time":"4.03 days","uncertainty":0.2,"value":21.9},{"limit":">22.3","time":"10.98 days","uncertainty":0.1}],"J":[{"time":"2.05 days","uncertainty":0.2,"value":19.8},{"limit":">19.5","time":"4.03 days","uncertainty":0.1},{"limit":">19.7","time":"10.98 days","uncertainty":0.1}]},"other_measurements":{"J_band_detection_limit":{"time":"3 hours","value":16.5},"alpha_decay_rate":"-1.4+/-0.3"},"ra":"01:43:14.4","redshift":null,"tables":[{"I_magnitude_or_limit":["20.9 +/- 0.1","21.9 +/- 0.2",">22.3 +/- 0.1"],"J_magnitude_or_limit":["19.8 +/- 0.2",">19.5 +/- 0.1",">19.7 +/- 0.1"],"days_post_burst":["2.05","4.03","10.98"]}]},"authors":{"affiliations":["Yale U"],"authors":["B. E. Cobb","Krimm et al.","Stratta et al.","Butler et al."],"institutions":["SMARTS consortium"],"universities":["Yale U"]},"telescopes":{"facilities":[],"instruments":["ANDICAM"],"observatories":["CTIO"],"telescopes":["1.3m telescope at CTIO"]},"urls":[],"basic_data":{"author":{"email":"cobb@astro.yale.edu","institution":"Yale U","name":"Bethany Cobb"},"coordinates":{"dec":1.7206666666666668},"detectionTime":"2007-09-27T20:39:59.000Z","event":"GRB 070911","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6829\nSUBJECT: GRB 070911, SMARTS optical/IR afterglow observations\nDATE: 07/09/27 20:39:59 GMT\nFROM: Bethany Cobb at Yale U  <cobb@astro.yale.edu>\n\nB. E. Cobb, part of the larger SMARTS consortium, reports:\n\nUsing the ANDICAM instrument on the 1.3m telescope at CTIO, we\nobtained optical/IR imaging of the error region of GRB 070911\n(Krimm et al. GCN 6777) with the following mid-exposure times:\n         2007-09-13 07:10:30 UT -  2.05 days post-burst\n         2007-09-15 06:42:00 UT -  4.03 days post-burst\n         2007-09-22 05:22:21 UT - 10.98 days post-burst\nFor each observation, total summed exposure times amounted to\n36 minutes in I and 30 minutes in J.\n\nA fading afterglow is detected in both I and J within the X-ray afterglow\nerror region (Stratta et al. 6779). This afterglow has the following \ncoordinates and magnitudes:\n\nRA/DEC: 01:43:14.4 -33:29:02.5\n\ndays post\nburst           I-magnitude (or limit)  J-magnitude (or limit)\n----------------------------------------------------------------\n  2.05           20.9 +/- 0.1            19.8 +/- 0.2\n  4.03           21.9 +/- 0.2           >19.5 +/- 0.1\n10.98          >22.3 +/- 0.1           >19.7 +/- 0.1\n\nThe I-band photometry is calibrated to a number of secondary stars in the\nfield of GRB 070911.  The magnitude of these secondary stars was\nderived using Landolt standard star observations obtained\nduring the first two epochs, which were photometric night at CTIO.\nThe J-band images are calibrated based on several 2MASS stars in the \nfield.\n\nThe afterglow''s behavior between the first two epochs is consistent with a\ndecay rate of alpha = -1.4+/-0.3.  Interestingly, no J-band afterglow was\ndetected by Butler et al. (GCN 6780) to J > 16.5 only 3 hours after\nthe burst. This indicates that a period of rebrightening might have \noccurred between 3 hours and 2 days post-burst, though steady decay\nis only ruled out at the ~1 sigma level."}', 'Astronomical alert: GRB 070911, SMARTS optical/IR afterglow observations', 0.5, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6828', 'gcn', 'GRB070925', '2007-09-27T16:48:43.000Z', '{"measurements":{"dec":null,"distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":null,"other_measurements":{"count_rate_T_plus_72h":"3e-3 counts/s","decay_slope_alpha":"1.2 +/- 0.3","predicted_count_rate_T_plus_96h":"5.6e-4 counts/s","time_range_after_burst":"1.3e4 to 1.4e5 seconds"},"ra":null,"redshift":null,"tables":[]},"authors":{"affiliations":["Penn State University"],"authors":["Loredana Vetere","C. Pagani"],"institutions":["Penn State"],"universities":["Penn State University"]},"telescopes":{"facilities":[],"instruments":["Swift-XRT"],"observatories":[],"telescopes":["Swift"]},"urls":["http://gcn.gsfc.nasa.gov"],"basic_data":{"author":{"email":"vetere@astro.psu.edu","institution":"PSU","name":"Loredana Vetere"},"coordinates":{},"detectionTime":"2007-09-27T16:48:43.000Z","event":"GRB070925","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6828\nSUBJECT: GRB070925: Swift-XRT Afterglow confirmation\nDATE: 07/09/27 16:48:43 GMT\nFROM: Loredana Vetere at PSU  <vetere@astro.psu.edu>\n\nL. Vetere, C. Pagani (PSU) report on behalf of the Swift-XRT team:\n\nAdditional Swift-XRT observations have been performed of the possible\nX-ray afterglow of GRB 070925 (Vetere et al., GCN 6826). The count rate\nat T+72h is ~3e-3 counts/s. Between 1.3e4 and 1.4e5 seconds after the burst,\nthe source has faded following a power-law decay slope of alpha = 1.2 +/- 0.3,\nconfirming that it is, indeed, the afterglow.\nIf the burst keeps decaying at the current rate the predicted count rate at\nT+96h is 5.6e-4 counts/s.\n\nThis circular is an official product of the Swift-XRT team."}', 'Swift-XRT team confirms the identification of the X-ray afterglow of GRB 070925 based on observations showing a count rate of ~3e-3 counts/s at T+72 hours and a power-law decay slope of alpha = 1.2 +/- 0.3 between 1.3e4 and 1.4e5 seconds after the burst. The predicted count rate at T+96 hours is 5.6e-4 counts/s.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6827', 'gcn', 'GRB 070925', '2007-09-26T20:32:08.000Z', '{"measurements":{"dec":["-22:01:41","-22:01:41"],"distance":null,"duration":{"total observation time":"900 sec"},"energy":null,"fluence":null,"magnitude":{"r":24.5},"other_measurements":{},"ra":["16:52:52.5","16:52:52.1"],"redshift":null,"tables":[]},"authors":{"affiliations":["UC Berkeley","UCO/Lick","U Chicago"],"authors":["J.S. Bloom","D. A. Perley","H.-W. Chen","J.X. Prochaska"],"institutions":["UC Berkeley","UCO/Lick"],"universities":["University of Chicago","University of California, Berkeley"]},"telescopes":{"facilities":[],"instruments":[],"observatories":[],"telescopes":["Gemini South 8-m telescope"]},"urls":["https://gcn.gsfc.nasa.gov/gcn3/gcn3_search.msfc?GCN_ID=6823","https://gcn.gsfc.nasa.gov/gcn3/gcn3_search.msfc?GCN_ID=6826"],"basic_data":{"author":{"email":"hchen@oddjob.uchicago.edu","institution":"U Chicago","name":"Hsiao-Wen Chen"},"coordinates":{},"detectionTime":"2007-09-26T20:32:08.000Z","event":"GRB 070925","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6827\nSUBJECT: GRB 070925: Gemini South Imaging\nDATE: 07/09/26 20:32:08 GMT\nFROM: Hsiao-Wen Chen at U Chicago  <hchen@oddjob.uchicago.edu>\n\nJ.S. Bloom (UC Berkeley), D. A. Perley (UC Berkeley), H.-W. Chen (U \nChicago), an d J.X. Prochaska (UCO/Lick) report on behalf of a larger \ncollaboration:\n\n\"We observed the field of GRB 070925 (Mereghetti et al., GCN 6823) in\nr-band with the Gemini South 8-m telescope for a total of 900 sec\nstarting at 2007-09-26 00:00:59 UT.  The stacked image has a mean seeing\nof ~ 1.0 arcsec.  Within the XRT (Vetere et al. GCN 6826) there are two\napparent binary systems, both apparent in DSS imaging (mid-points\n16:52:52.5, -22:01:41 and 16:52:52.1, -22:01:41). We detect no other\nsources in the error circle to r~24.5.\n\nThis message may be cited. \""}', 'Astronomers led by J.S. Bloom (UC Berkeley) and H.-W. Chen (U Chicago) observed the field of GRB 070925 using the Gemini South 8-m telescope in r-band for 900 seconds. They detected two apparent binary systems within the error circle, both previously identified in DSS imaging. No other sources were detected to a magnitude of r~24.5.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6826', 'gcn', 'GRB070925', '2007-09-26T15:00:58.000Z', '{"measurements":{"dec":"-22.02856","distance":null,"duration":"2.5 ks","energy":null,"fluence":null,"magnitude":null,"other_measurements":{"count_rate":"1.6e-2 +/- 0.3e-2 counts s-1","uncertainty":"6.0 arcsec"},"ra":"253.21700","redshift":null,"tables":[]},"authors":{"affiliations":["PSU"],"authors":["Loredana Vetere","J. L. Racusin"],"institutions":["Penn State"],"universities":["Penn State University"]},"telescopes":{"facilities":[],"instruments":["Swift-XRT"],"observatories":[],"telescopes":["Swift"]},"urls":["https://gcn.gsfc.nasa.gov"],"basic_data":{"author":{"email":"vetere@astro.psu.edu","institution":"PSU","name":"Loredana Vetere"},"coordinates":{},"detectionTime":"2007-09-26T15:00:58.000Z","event":"GRB070925","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6826\nSUBJECT: GRB070925: Swift-XRT Position\nDATE: 07/09/26 15:00:58 GMT\nFROM: Loredana Vetere at PSU  <vetere@astro.psu.edu>\n\nL. Vetere, J. L. Racusin (PSU) report on behalf of the Swift-XRT team:\n\nWe have analysed 2.5 ks of Swift XRT data for GRB 070925 (Mereghetti et al.,\nGCN 6823) beginning 12 ks after the IBAS trigger. An uncatalogued X-ray source\nis clearly detected at RA, Dec= 253.21700, -22.02856 degrees, which is\nequivalent to:\n\nRA (J2000) =  16h 52m 52.1s\nDec(J2000) = -22d 01'' 41.0\"\n\nwith an estimated uncertainty of 6.0 arcsec (radius, 90% containment\nincluding boresight uncertainty). This is 8 arcsec from the IBAS\nposition (Mereghetti et al., GCN 6823) within its error circle. The\nsource has a count rate of 1.6e-2 +/- 0.3e-2 counts s-1. At present we\nare unable to determine whether the source is fading, however\nobservations are ongoing.\n\nThis circular is an official product of the Swift-XRT team."}', 'Astronomical alert: GRB070925: Swift-XRT Position', 0.5, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6825', 'gcn', 'Update on Swift Status', '2007-09-26T12:33:10.000Z', '{"measurements":{"dec":null,"distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":null,"other_measurements":{"date":["Sept 24"],"days":["one additional week"],"hours":["normal working hours"],"time_frame":["the end of the year"]},"ra":null,"redshift":null,"tables":[]},"authors":{"affiliations":["NASA-GSFC"],"authors":["Neil Gehrels","Barthelmy et al.","Burrows et al."],"institutions":["Penn State"],"universities":[]},"telescopes":{"facilities":[],"instruments":["BAT","XRT","UVOT"],"observatories":[],"telescopes":[]},"urls":["http://milkyway.gsfc.nasa.gov"],"basic_data":{"author":{"email":"gehrels@milkyway.gsfc.nasa.gov","institution":"GSFC","name":"Neil Gehrels"},"coordinates":{},"detectionTime":"2007-09-26T12:33:10.000Z","event":"Update on Swift Status","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6825\nSUBJECT: Update on Swift Status\nDATE: 07/09/26 12:33:10 GMT\nFROM: Neil Gehrels at GSFC  <gehrels@milkyway.gsfc.nasa.gov>\n\nNeil Gehrels (NASA-GSFC) reports on behalf of the Swift team:\n\nThis is an update on Swift status following earlier Circulars \n(Gehrels 6760; Barthelmy et al. 6781; Burrows et al. 6791).  The \ncurrent instrument status is that BAT is fully turned on with all \ntriggers enabled, XRT is fully turned on and performing science \nobservations and calibrations, and UVOT is turned off for \napproximately one additional week depending on spacecraft slew \nperformance testing this week.\n\nLimited autonomous slewing to new GRBs was reinstated this week (Sept 24).\nInitially the Automated Target (AT) mode is only being enabled during\nnormal working hours of the flight operations team at the Penn State\noperations center.  Several methods for improving the slew accuracy\nof the redundant gyro system now in use are being tested to enable\nfull-time AT slewing.\n\nAn experiment to lower the BAT trigger threshold in order to detect \nweaker bursts was originally planned for the current time frame.  It \nis now delayed and will occur no sooner than the end of the year.\n\nMore information will follow as we continue to recover observatory capability."}', 'Swift spacecraft''s X-ray telescope (XRT) is currently observing and calibrating, while BAT is fully operational and UVOT is off for an additional week due to testing. Limited autonomous slewing to new gamma-ray bursts (GRBs) has been reinstated, with plans to improve accuracy and enable full-time operation. An experiment to detect weaker bursts using a lower BAT trigger threshold has been delayed until the end of the year.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6824', 'gcn', 'GRB 070920B', '2007-09-25T19:11:20.000Z', '{"measurements":{"dec":null,"distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":[15.7,16.7,17.8],"other_measurements":{"individual_image_limiting_magnitudes":"12.8-17.8","initial_exposure_time_seconds":5,"longest_exposure_time_seconds":60,"subsequent_exposure_time_seconds":20,"time_after_burst_for_first_image_seconds":44.1,"total_number_of_20_second_exposures":10,"total_number_of_5_second_exposures":10,"total_number_of_60_second_exposures":386},"ra":null,"redshift":null,"tables":[{"Coadd?":"N","end UT":"21:05:21.5","mlim":15.7,"start UT":"21:05:16.5","t_exp(s)":5,"t_start-tGRB(s)":44.1},{"Coadd?":"Y","end UT":"21:06:34.5","mlim":16.7,"start UT":"21:05:16.5","t_exp(s)":78,"t_start-tGRB(s)":44.1},{"Coadd?":"Y","end UT":"21:34:44.6","mlim":17.8,"start UT":"21:29:06.7","t_exp(s)":337,"t_start-tGRB(s)":1474.3}]},"authors":{"affiliations":["U Mich","UCSB","ROTSE","H.E.S.S."],"authors":["H. Swan","E.S. Rykoff","F. Yuan"],"institutions":["ROTSE","H.E.S.S."],"universities":["U. of Michigan","UCSB"]},"telescopes":{"facilities":[],"instruments":[],"observatories":["H.E.S.S. site at Mt. Gamsberg, Namibia"],"telescopes":["ROTSE-IIIc"]},"urls":["https://gcn.gsfc.nasa.gov"],"basic_data":{"author":{"email":"hflewell@umich.edu","institution":"U.of Michigan/ROTSE","name":"Heather Swan"},"coordinates":{},"detectionTime":"2007-09-25T19:11:20.000Z","event":"GRB 070920B","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6824\nSUBJECT: GRB 070920B: ROTSE-III Early Optical Limits\nDATE: 07/09/25 19:11:20 GMT\nFROM: Heather Swan at U.of Michigan/ROTSE  <hflewell@umich.edu>\n\nH. Swan (U Mich), E.S. Rykoff (UCSB), F. Yuan (U Mich), report on\nbehalf of the ROTSE collaboration:\n\nROTSE-IIIc, located at the H.E.S.S. site at Mt. Gamsberg, Namibia,\nresponded to GRB 070920B (Swift trigger 291728; J. L. Racusin, GCN\n6808), producing images beginning 8.5 s after the GCN notice time. An\nautomated response took the first image at 21:05:16.5 UT, 44.1 s after\nthe burst, under partly cloudy conditions. We took 10 5-sec, 10 20-sec\nand 386 60-sec exposures. These unfiltered images are calibrated\nrelative to USNO A2.0 (R).  We lost internet contact with ROTSE-IIIc\nshortly after the GCN trigger, thus we were unable to retrieve the burst\ndata until Sept. 25.\n\nComparison to the DSS (second epoch) reveals no new sources within the\n3-sigma Swift/BAT error circle or the XRT error circle , (J. L. Racusin,\nGCN 6820) for both single images and coadding into sets of 10; the field\nis not crowded. Individual images have limiting magnitudes ranging from\n12.8-17.8; we set the following specific limits.\n\nstart UT       end UT      t_exp(s)   mlim   t_start-tGRB(s)  Coadd?\n--------------------------------------------------------------------\n21:05:16.5   21:05:21.5         5     15.7           44.1       N\n21:05:16.5   21:06:34.5        78     16.7           44.1       Y\n21:29:06.7   21:34:44.6       337     17.8         1474.3       Y"}', 'The ROTSE-III collaboration reported early optical limits for GRB 070920B using the ROTSE-IIIc telescope at the H.E.S.S. site in Namibia. Three sets of observations were taken, with the first image obtained 44.1 seconds after the burst. No new sources were detected within the error circles, and limiting magnitudes ranged from 12.8 to 17.8. The team lost internet connection shortly after the trigger and was unable to retrieve the data until September 25.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6823', 'gcn', 'GRB 070925', '2007-09-25T17:26:59.000Z', '{"measurements":{"dec":-22.0355,"distance":null,"duration":30,"energy":null,"fluence":"2e-6 erg/cm^2","magnitude":null,"other_measurements":{"integration_time":"1 s","peak_flux":"2 ph/cm^2/s"},"ra":253.218,"redshift":null,"tables":[]},"authors":{"affiliations":["IASF-Milano, Institute for Space Astrophysics and Cosmic Physics of the National Research Council of Italy","CEA-Saclay, Commissariat à l''Énergie Atomique et aux Énergies Alternatives","ISDC, International Scientific Data Centre","CAMK, Cardinal Stefan Wyszyński University"],"authors":["S.Mereghetti","A.Paizis","D.Gotz","D.Petry","V.Beckmann","M. Beck","J. Borkowski"],"institutions":["IASF-Milano, Institute for Space Astrophysics and Cosmic Physics of the National Research Council of Italy","CEA-Saclay, Commissariat à l''Énergie Atomique et aux Énergies Alternatives","ISDC, International Scientific Data Centre","CAMK, Cardinal Stefan Wyszyński University"],"universities":["IASF-Milano","CEA-Saclay","INAF","ISDC","CAMK"]},"telescopes":{"facilities":["IBAS"],"instruments":["IBIS/ISGRI"],"observatories":[],"telescopes":["IBIS/ISGRI"]},"urls":["http://ibas.iasf-milano.inaf.it/IBAS_Results.html"],"basic_data":{"author":{"email":"sandro@iasf-milano.inaf.it","institution":"IASF/CNR","name":"Sandro Mereghetti"},"coordinates":{"ra":2.0842272222222222},"detectionTime":"2007-09-25T17:26:59.000Z","event":"GRB 070925","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6823\nSUBJECT: GRB 070925: a long GRB detected by INTEGRAL\nDATE: 07/09/25 17:26:59 GMT\nFROM: Sandro Mereghetti at IASF/CNR  <sandro@iasf-milano.inaf.it>\n\nS.Mereghetti, A.Paizis (IASF-Milano), D.Gotz (CEA-Saclay), D.Petry, \nV.Beckmann, M. Beck (ISDC, Versoix), and J. Borkowski (CAMK, Torun) \non behalf of the IBAS Localization Team report:\n\nA  GRB lasting about 30 s has been detected by IBAS in IBIS/ISGRI \ndata at 15:52:32 UT of September 25.\nThe coordinates (J2000)  are:\n\nRA:  253.218 [degrees] \nDEC: -22.0355 [degrees]\n\nwith an uncertainty of 2 arcmin (90% c.l.).\n\nThe light curve is affected by gaps due to telemetry saturation. The peak \nflux in the 20-200 keV range is 2 ph/cmq/s (1-s integration time) and the \nfluence over the same energy range is larger than 2x10e-6 erg/cmq.\n\nA plot of the light curve will be posted at\n\nhttp://ibas.iasf-milano.inaf.it/IBAS_Results.html\n\nThis message can be cited."}', 'A long gamma-ray burst (GRB) with a duration of approximately 30 seconds was detected by the IBIS/ISGRI instrument on the INTEGRAL spacecraft at around 15:52:32 UT on September 25, 2007. The burst occurred in the direction of RA: 253.218 degrees, DEC: -22.0355 degrees, with an uncertainty of 2 arcmin. The peak flux in the 20-200 keV range was 2 ph/cmq/s (1-s integration time), and the fluence in the same energy range was larger than 2x10e-6 erg/cmq. A light curve plot will be available at http://ibas.iasf-milano.inaf.it/IBAS_Results.html.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6822', 'gcn', 'Recent SGR1806-20 Activity', '2007-09-24T20:45:04.000Z', '{"measurements":[8.2e-7,0.000016,0.000001,0.0000028,4.5e-7,6.5e-7,0.000001,6.5e-7,0.000016,0.0000015,6.5e-7,0.0000024,9.6e-7,9e-7,"?",0.0000019,0.0000014,4e-7,0.0000026],"authors":{"affiliations":["UCBerkeley/SSL","Konus-Wind and Konus-A teams","INTEGRAL GRB team","AGILE team","Suzaku WAM GRB team"],"authors":["S. Golenetskii","R. Aptekar","E. Mazets","V. Pal''shin","D. Frederiks","P. Oleynik","M. Ulanov","T. Cline","D. Palmer","S. Barthelmy","J. Cummings","N. Gehrels","H. Krimm","M. Feroci","P. Soffitta","Y. Evangelista","K. Yamaoka","M. Ohno","Y.E. Nakagawa","Y. Fukazawa","T. Takahashi","M. Tashiro","Y. Terada","T. Murakami","K. Makishima"],"institutions":["SSL","Konus-Wind","Konus-A","INTEGRAL GRB team","AGILE team","Suzaku WAM GRB team"],"universities":["UCBerkeley"]},"telescopes":{"facilities":[],"instruments":[],"observatories":["INTEGRAL","Chandra"],"telescopes":["BAT","IBIS","KW","SA","SPI-ACS","SUZ"]},"urls":[],"basic_data":{"author":{"email":"khurley@ssl.berkeley.edu","institution":"UCBerkeley/SSL","name":"Kevin Hurley"},"coordinates":{},"detectionTime":"2007-09-24T20:45:04.000Z","event":"Recent SGR1806-20 Activity","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6822\nSUBJECT: Recent SGR1806-20 Activity\nDATE: 07/09/24 20:45:04 GMT\nFROM: Kevin Hurley at UCBerkeley/SSL  <khurley@ssl.berkeley.edu>\n\nS. Golenetskii, R. Aptekar, E. Mazets, V. Pal''shin, D. Frederiks, P.\nOleynik, M. Ulanov and T. Cline, on behalf of the Konus-Wind and\nKonus-A teams,\n\nD. Palmer, S. Barthelmy, J. Cummings, N. Gehrels, and H. Krimm, on behalf\nof the Swift-BAT team,\n\nK. Hurley, A. von Kienlin, G. Lichti, A. Rau, D. Gotz, and S.\nMereghetti, on behalf of the INTEGRAL GRB team,\n\nM. Feroci, P. Soffitta and Y. Evangelista, on behalf of the AGILE team,\n\nK. Yamaoka, M. Ohno, Y.E. Nakagawa, Y. Fukazawa, T. Takahashi, M.\nTashiro, Y. Terada, T. Murakami, and K. Makishima, on behalf of the\nSuzaku WAM GRB team,\n\nreport:\n\nSGR1806-20 has become very active since September 14 (Barthelmy et al.\nGCN 6804).  The following is a partial list of bursts observed by some\nof the IPN spacecraft (some weaker IBIS events did not trigger the INTEGRAL\nBurst Alert Service).   \"Loc\" means that the burst was localized by\ntriangulation to at least a relatively narrow annulus, or by the Swift\nBAT or by IBIS.  A \"no\" in this column means that the event has only\nbeen localized to a relatively wide ecliptic latitude band.\n\nINTEGRAL (GCN 6815) and Chandra target of opportunity observations of\nthis source are planned, and we encourage supporting observations at\nall wavelengths.\n\nDate\t\tTime\t\tFluence\tObserved by \t\tLoc\n                                20-200  (at least)\n                                 keV\n-------------------------------------------------------------------\n20070914\t10:46:02\t8.2E-7\tBAT,IBIS,KW\t\ty\n20070914\t14:54:47\t1.6E-5\tKW,KA,SA\t\ty\n20070914\t14:58:44\t1.0E-6\tKW\t\t\tno\n20070914\t19:57:57\t2.8E-6\tBAT,KA\t\t\ty\n20070914\t21:03:36\t4.5E-7\tKW\t\t\tno\n20070916\t07:08:38\t6.5E-7\tIBIS,KW\t\t\ty\n20070916\t09:48:08\t1.0E-6\tIBIS,KW\t\t\ty\n20070918\t17:08:50\t1.6E-5\tKW,SA,SPI-ACS,SUZ\ty\n20070919\t10:01:51\t1.5E-6\tIBIS,KW\t\t\ty\n20070919\t15:13:04\t6.5E-7\tKW\t\t\tno\n20070919\t16:01:13\t2.4E-6\tBAT,KA,KW\t\ty\n20070919\t16:54:44\t9.6E-7\tKW\t\t\tno\n20070919\t19:34:50\t9.0E-7\tIBIS,KW\t\t\ty\n20070919\t20:45:10\t?\tBAT,IBIS\t\ty\n20070920\t04:30:11\t1.9E-6\tIBIS,KW \t\ty\n20070921\t07:11:59\t1.4E-6\tIBIS,KW\t\t\ty\n20070921\t11:45:35\t4.0E-7\tKW\t\t\tno\n20070923\t12:46:15\t2.6E-6\tKW,KA\t\t\tno\n------------------------------------------------------------------\n\nSome Abbreviations:\n\nBAT: Swift Burst Alert Telescope\nIBIS: Imager on Board the INTEGRAL Satellite\nKA: Konus-A (Cosmos 2421)\nKW: Konus-Wind\nSA: Super-AGILE\nSPI-ACS: Anticoincidence System of the INTEGRAL Spectrometer\nSUZ: Suzaku WAM"}', 'SGR1806-20, a magnetar located in the constellation Sagittarius, has shown increased activity since September 14, 2007. Several bursts have been detected by various spacecraft, including Swift Burst Alert Telescope (BAT), Imager on Board the INTEGRAL Satellite (IBIS), Konus-Wind (KW), Super-AGILE (SA), Suzaku WAM, and Chandra. The events were localized to narrow annuli or determined by Swift-BAT or IBIS. The authors encourage supporting observations at all wavelengths.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6821', 'gcn', 'GRB 070923', '2007-09-24T10:33:31.000Z', '{"measurements":{"dec":-38.294,"distance":null,"duration":0.05,"energy":null,"fluence":5e-8,"magnitude":null,"other_measurements":{"duration_error":0.01,"duration_unit":"sec","fluence_band":"15-150 keV","fluence_error":9e-9,"fluence_unit":"erg/cm2","partial_coding":75,"peak_duration":50,"peak_photon_flux":2.4,"peak_photon_flux_band":"15-150 keV","peak_photon_flux_error":0.4,"peak_photon_flux_unit":"ph/cm2/sec"},"ra":184.623,"redshift":null,"tables":[]},"authors":{"affiliations":["GSFC/UMBC","GSFC","GSFC","GSFC/UMD","LANL","GSFC/ORAU","PSU","GWU"],"authors":["J. Cummings","L. Barbier","S. D. Barthelmy","E. Fenimore","N. Gehrels","H. Krimm","C. Markwardt","D. Palmer","A. Parsons","T. Sakamoto","G. Sato","M. Stamatikos","M. C. Stroh","J. Tueller","T. Ukwatta"],"institutions":["NASA-GSFC","UMBC","GSFC","GSFC/UMD","LANL","GSFC/ORAU","PSU","GWU"],"universities":["GSFC","UMBC","UMD","LANL","PSU","ORAU","ISAS"]},"telescopes":{"facilities":[],"instruments":[],"observatories":[],"telescopes":[]},"urls":["https://gcn.gsfc.nasa.gov"],"basic_data":{"author":{"email":"krimm@milkyway.gsfc.nasa.gov","institution":"NASA-GSFC","name":"Hans Krimm"},"coordinates":{},"detectionTime":"2007-09-24T10:33:31.000Z","event":"GRB 070923","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6821\nSUBJECT: GRB 070923, Swift-BAT refined analysis\nDATE: 07/09/24 10:33:31 GMT\nFROM: Hans Krimm at NASA-GSFC  <krimm@milkyway.gsfc.nasa.gov>\n\nJ. Cummings (GSFC/UMBC), L. Barbier (GSFC), S. D. Barthelmy (GSFC),\nE. Fenimore (LANL), N. Gehrels (GSFC), H. Krimm (GSFC/USRA),\nC. Markwardt (GSFC/UMD), D. Palmer (LANL), A. Parsons (GSFC),\nT. Sakamoto (GSFC/ORAU), G. Sato (GSFC/ISAS), M. Stamatikos (GSFC/ORAU),\nM. C. Stroh (PSU), J. Tueller (GSFC), T. Ukwatta (GWU)\n(i.e. the Swift-BAT team):\n\nUsing the data set from T-240 to T+230 sec from the recent telemetry downlink,\nwe report further analysis of BAT GRB 070923 (trigger #292004)\n(Stroh, et al., GCN Circ. 6818).  The BAT ground-calculated position is\nRA, Dec = 184.623, -38.294 deg which is\n    RA(J2000)  = 12h 18m 29.5s\n    Dec(J2000) = -38d 17'' 38\"\nwith an uncertainty of 2.1 arcmin, (radius, sys+stat, 90% containment).\nThe partial coding was 75%.\n\nThe mask weighted light curve shows a single peak of duration ~50 msec.\nT90 (15-350 keV) is 0.05 +- 0.01 sec (estimated error including systematics).\n\nThe time-averaged spectrum from T+0.16 to T+0.37 sec is best fit by a simple\npower-law model.  The power law index of the time-averaged spectrum is\n1.02 +- 0.29.  The fluence in the 15-150 keV band is 5.0 +- 0.9 x \n10^-8 erg/cm2.\nThe 1-sec peak photon flux measured from T-0.40 sec in the 15-150 keV band\nis 2.4 +- 0.4 ph/cm2/sec.  All the quoted errors are at the 90% confidence\nlevel."}', 'Swift-BAT team reports refined analysis of GRB 070923 (trigger #292004), identifying a single peak of duration ~50 ms and a time-averaged power-law spectrum with an index of 1.02 +- 0.29. The event occurred at RA, Dec = 184.623, -38.294 deg, with a fluence of 5.0 +- 0.9 x 10^-8 erg/cm2 in the 15-150 keV band.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6820', 'gcn', 'GRB 070920B', '2007-09-23T21:13:45.000Z', '{"measurements":{"dec":null,"distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":null,"other_measurements":{},"ra":null,"redshift":null},"authors":{"affiliations":["Swift-XRT team, Penn State University"],"authors":["J. L. Racusin"],"institutions":["Penn State University"],"universities":["Penn State University"]},"telescopes":{"facilities":[],"instruments":["Swift-XRT"],"observatories":[],"telescopes":["Swift"]},"urls":["https://gcn.gsfc.nasa.gov"],"basic_data":{"author":{"email":"racusin@astro.psu.edu","institution":"PSU","name":"Judith Racusin"},"coordinates":{},"detectionTime":"2007-09-23T21:13:45.000Z","event":"GRB 070920B","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6820\nSUBJECT: GRB 070920B: XRT observations\nDATE: 07/09/23 21:13:45 GMT\nFROM: Judith Racusin at PSU  <racusin@astro.psu.edu>\n\nJ. L. Racusin (PSU) reports on behalf of the Swift-XRT team:\n\nWe have analysed 9.7 ks of Swift XRT data for GRB 070920B (Racusin et al.,\nGCN 6808) beginning 64 ks after the BAT trigger. The data are entirely in\nPhoton Counting mode, and reveal a faint uncatalogued X-ray source at RA,\nDec= 0.13029, -34.85284 degrees, which is equivalent to:\n\nRA (J2000) =  00h 00m 31.27s\nDec(J2000) = -34d 51'' 10.2\"\n\nwith an estimated uncertainty of 8.0 arcsec (radius, 90% containment\nincluding boresight uncertainty). This is 33 arcsec from the refined BAT\nposition (Barthelmy et al. GCN 6811). The source has a count rate of\n2.1e-3 +/- 0.6e-3 counts s-1. At present we are unable to determine\nwhether the source is fading, however observations are ongoing.\n\nThis circular is an official product of the Swift-XRT team."}', 'The Swift-XRT team has detected a faint X-ray source, 33 arcsec from the refined BAT position of GRB 070920B, with a count rate of 2.1e-3 +/- 0.6e-3 counts s-1. The source''s position and count rate are being further analyzed.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-682', 'gcn', 'GRB000529', '2000-05-31T06:27:15.000Z', '{"measurements":{"dec":null,"distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":19.75,"other_measurements":{"exposure_time":"3 x 300s","observation_start_time":"May 30.74 UT"},"ra":null,"redshift":null,"tables":[]},"authors":{"affiliations":["Mount Stromlo Observatory"],"authors":["Paul Price","Tim Axelrod","Brian Schmidt"],"institutions":["Res. School of Astro.and Astrophysics"],"universities":["The Australian National University"]},"telescopes":{"facilities":[],"instruments":[],"observatories":["Mount Stromlo Observatory"],"telescopes":["50-inch telescope"]},"urls":["<pap@mso.anu.edu.au>"],"basic_data":{"author":{"email":"pap@mso.anu.edu.au","institution":"Res. School of Astro.and Astrophysics (Mpap@mso.anu.edu.au","name":"Paul Price"},"coordinates":{},"detectionTime":"2000-05-31T06:27:15.000Z","event":"GRB000529","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 682\nSUBJECT: GRB000529: Optical Observations\nDATE: 00/05/31 06:27:15 GMT\nFROM: Paul Price at Res. School of Astro.and Astrophysics (Mpap@mso.anu.edu.au  <pap@mso.anu.edu.au>\n\nPaul Price, Tim Axelrod and Brian Schmidt report:\n\nWe have observed the error circle of GRB000529 (BeppoSAX mail 00/13) with the\n50-inch telescope at Mount Stromlo Observatory.  Exposure was 3 x 300s, starting\nat May 30.74 UT, with a limiting magnitude of R_M ~ 19.75 (where R_M refers to\nthe MACHO red band).  We find no OT candidate on comparison with the DSS."}', 'A team led by Paul Price at The Australian National University observed the error circle of GRB000529 using the 50-inch telescope at Mount Stromlo Observatory. They reported no optical transient detection with a limiting magnitude of R_M ~ 19.75.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6819', 'gcn', 'GRB 070923', '2007-09-23T20:46:26.000Z', '{"measurements":{"dec":["-38:16:44.1","-38:18:24.0"],"distance":[0.7,2.8],"duration":null,"energy":null,"fluence":null,"magnitude":{"H":[14.77,14.44],"J":[15.01,15.35],"Ks":[13.73,13.88]},"other_measurements":{"Distant Galaxy 1 Distance":5.4,"Distant Galaxy 2 Distance":7.2,"Redshift of Distant Galaxies":0.076},"ra":["12:18:29.35","12:18:21.87"],"redshift":[null,null],"tables":[{"D":0.7,"Dec (J2000)":"-38:16:44.1","H":14.77,"J":15.01,"Ks":13.73,"RA (J2000)":"12:18:29.35"},{"D":2.8,"Dec (J2000)":"-38:18:24.0","H":14.44,"J":15.35,"Ks":13.88,"RA (J2000)":"12:18:21.87"}]},"authors":{"affiliations":["Penn State","Caltech"],"authors":["D.B. Fox","E. Ofek"],"institutions":["Penn State","Caltech"],"universities":["Penn State","Caltech"]},"telescopes":{"facilities":["NASA/IPAC Extragalactic Database"],"instruments":[],"observatories":[],"telescopes":[]},"urls":["https://ned.ipac.caltech.edu/"],"basic_data":{"author":{"email":"dfox@astro.psu.edu","institution":"PSU","name":"Derek Fox"},"coordinates":{},"detectionTime":"2007-09-23T20:46:26.000Z","event":"GRB 070923","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6819\nSUBJECT: GRB 070923: Galaxies within BAT localization\nDATE: 07/09/23 20:46:26 GMT\nFROM: Derek Fox at PSU  <dfox@astro.psu.edu>\n\nD.B. Fox (Penn State) and E. Ofek (Caltech) report:\n\n\"We note the presence of two 2MASS-cataloged galaxies within the BAT\nlocalization region for the short-hard burst GRB 070923 (Stroh et al.,\nGCN 6818).  The galaxy coordinates, distances (D) from the center of\nthe BAT error circle in arcmin, and total broadband magnitudes (J, H,\nKs) as given by the NASA/IPAC Extragalactic Database* are:\n\n            RA (J2000)   Dec (J2000)   D      J      H     Ks\n   =================================================================\n   2MASS-A  12:18:29.35  -38:16:44.1  0.7   15.01  14.77  13.73\n   2MASS-B  12:18:21.87  -38:18:24.0  2.8   15.35  14.44  13.88\n   =================================================================\n\nAlthough neither galaxy has a measured redshift, the somewhat more\ndistant galaxy 2MASX J12180474-3818108 (D=5.4 arcmin) and 2MASX\nJ12175556-3818208 (D=7.2 arcmin) both have z~0.076 according to the\n6dF redshift survey (Jones et al. 2004).\"\n\n\n*This research has made use of the NASA/IPAC Extragalactic Database\n(NED) which is operated by the Jet Propulsion Laboratory, California\nInstitute of Technology, under contract with the National Aeronautics\nand Space Administration."}', 'Two nearby galaxies, 2MASS-A and 2MASS-B, have been identified within the error circle of the short-hard gamma-ray burst GRB 070923. Their distances and magnitudes are provided, and two more distant galaxies with redshift ~0.076 are mentioned.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6818', 'gcn', 'GRB 070923', '2007-09-23T19:26:48.000Z', '{"measurements":{"dec":null,"distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":null,"other_measurements":{},"ra":null,"redshift":null},"authors":{"affiliations":["NASA/GSFC (Swift Team)","PSU (Swift Team)","PSU","NASA/GSFC","PSU","GSFC/USRA","LANL","GSFC","PSU","U Leicester","GSFC/GWU"],"authors":["M. C. Stroh","S. D. Barthelmy","D. N. Burrows","N. Gehrels","D. Grupe","H. A. Krimm","D. M. Palmer","A. M. Parsons","J. L. Racusin","R. L. C. Starling","T. N. Ukwatta"],"institutions":["NASA/GSFC","PSU","LANL"],"universities":["Penn State University","University of Leicester","Los Alamos National Laboratory","GSFC/George Washington University"]},"telescopes":{"facilities":[],"instruments":[],"observatories":[],"telescopes":["Swift Burst Alert Telescope (BAT)"]},"urls":["http://www.swift.psu.edu/too.html"],"basic_data":{"author":{"email":"scott@lheamail.gsfc.nasa.gov","institution":"NASA/GSFC","name":"Scott Barthelmy"},"coordinates":{"dec":1.1346183333333333},"detectionTime":"2007-09-23T19:26:48.000Z","event":"GRB 070923","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6818\nSUBJECT: GRB 070923: Swift detection of a short hard burst\nDATE: 07/09/23 19:26:48 GMT\nFROM: Scott Barthelmy at NASA/GSFC  <scott@lheamail.gsfc.nasa.gov>\n\nM. C. Stroh (PSU), S. D. Barthelmy (GSFC), D. N. Burrows (PSU),\nN. Gehrels (NASA/GSFC), D. Grupe (PSU), H. A. Krimm (GSFC/USRA),\nD. M. Palmer (LANL), A. M. Parsons (GSFC), J. L. Racusin (PSU),\nR. L. C. Starling (U Leicester) and T. N. Ukwatta (GSFC/GWU) report\non behalf of the Swift Team:\n\nAt 19:15:23 UT, the Swift Burst Alert Telescope (BAT) triggered and\nlocated GRB 070923 (trigger=292004). \nThe BAT on-board calculated location is \nRA, Dec 184.626, -38.268 which is \n   RA(J2000)  =  12h 18m 30s\n   Dec(J2000) = -38d 16'' 03\"\nwith an uncertainty of 3 arcmin (radius, 90% containment, including \nsystematic uncertainty).  The BAT light curve shows a single spike\nwith a duration of about 100 msec.  The peak count rate\nwas ~8000 counts/sec (15-350 keV), at ~0.0 sec after the trigger. \n\nBecause Swift is in the process of returning to normal operations, \nautomatic slewing to GRBs is currently disabled.  Therefore, there \nare no prompt XRT or UVOT observations of this burst.  This burst is\n38 deg from the Sun and so is too close for later XRT observations. \n\nBurst Advocate for this burst is M. C. Stroh (stroh AT astroh.org). \nPlease contact the BA by email if you require additional information\nregarding Swift followup of this burst. In extremely urgent cases, after\ntrying the Burst Advocate, you can contact the Swift PI by phone (see\nSwift TOO web site for information: http://www.swift.psu.edu/too.html.)"}', 'Astronomical alert: GRB 070923: Swift detection of a short hard burst', 0.5, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6817', 'gcn', 'GRB 070917', '2007-09-23T14:17:44.000Z', '{"measurements":{"dec":null,"distance":null,"duration":2.5,"energy":{"lower_bound":50,"upper_bound":5000},"fluence":0.0000024,"magnitude":null,"other_measurements":{"peak_flux":3.1,"photon_index":1.6},"ra":null,"redshift":null,"tables":[]},"authors":{"affiliations":[],"authors":[],"institutions":[],"universities":[]},"telescopes":{"facilities":[],"instruments":[],"observatories":[],"telescopes":[]},"urls":[],"basic_data":{"author":{"email":"tashiro@phy.saitama-u.ac.jp","institution":"Saitama U/Swift","name":"Makoto Tashiro"},"coordinates":{},"detectionTime":"2007-09-23T14:17:44.000Z","event":"GRB 070917","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6817\nSUBJECT: GRB 070917: Suzaku/WAM observation of the prompt emission\nDATE: 07/09/23 14:17:44 GMT\nFROM: Makoto Tashiro at Saitama U/Swift  <tashiro@phy.saitama-u.ac.jp>\n\nGRB 070917: Suzaku WAM observation of the prompt emission\n\nA. Endo, M. Tashiro, Y. Urata, K. Onda, M. Suzuki, N. Kodaka,\nK. Morigami (Saitama U.), Y. Terada, T. Tamagawa (RIKEN),\nM. Ohno, T. Uehara, T. Takahashi, Y. Fukazawa, C. Kira (Hiroshima U.),\nK. Yamaoka, Y. E. Nakagawa, S. Sugita (Aoyama Gakuin U.),\nT. Enoto, R. Miyawaki, K. Nakawaza, K. Makishima (Univ. of Tokyo),\nE. Sonoda, M.Yamauchi, S. Maeno, H. Tanaka, R. Hara (Univ. of\nMiyazaki),\nM. Kokubun, M. Suzuki, T. Takahashi (ISAS/JAXA), S. Hong (Nihon U.),\non behalf of the Suzaku WAM team, report:\n\nThe long GRB 070917 (Swift/BAT trigger #291292 ; Cummings et al.,\nGCN 6791) triggered the Suzaku Wide-band  All-sky Monitor (WAM)\nwhich covers an energy range of 50 keV - 5 MeV\nat 2007-09-17 07:33:56.500 UT (=T0).\n\nThe observed light curve shows a single peak starting at T0+0s, ending\nat T0+3s with a duration (T90) of about 2.5 seconds. The fluence in\n100 - 1000 keV was 2.4 (+0.2, -0.2) * 10^(-6) erg/cm2. The 1-s peak flux\nmeasured from T0+0s was 3.1 (+0.3, -0.3) photons/cm2/s in the\nsame energy range.\n\nPreliminary result shows that the time-averaged spectrum from T0+0s to\nT0+3s is well fitted by a single power-law with a photon index\nof 1.6 (+0.2, -0.2) (chi2/d.o.f. = 9.6/11).\n\nAll the quoted errors are at statistical 90% confidence level,\nin which the systematic uncertainties are not included.\n\nThe light curves for this burst are available at:\nhttp://www.astro.isas.jaxa.jp/suzaku/HXD-WAM/WAM-GRB/grb/trig/grb_table.html"}', 'The long gamma-ray burst GRB 070917, detected by Swift/BAT, was observed by the Suzaku Wide-band All-sky Monitor (WAM) between 50 keV and 5 MeV. The burst had a duration of approximately 2.5 seconds and a fluence of 2.4x10^-6 erg/cm2 in the 100-1000 keV range. The peak flux was 3.1 photons/cm2/s, and the time-averaged spectrum was found to be well-fit by a single power-law with a photon index of 1.6.', 0.9, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6816', 'gcn', 'GRB 070920B', '2007-09-22T06:09:32.000Z', '{"measurements":{"dec":null,"distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":18.2,"other_measurements":{"elevation_of_field":"27 degrees","moon_distance_from_field":"68 degrees","moon_phase":0.58,"weather_conditions":"good"},"ra":null,"redshift":null,"tables":[{"exposure_time_per_image":"180s","number_of_images":8,"time_after_trigger":"2.7h","total_exposure_time":"1440s"}]},"authors":{"affiliations":["CESR-OMP","OHP","LATT-OMP"],"authors":["Alain.Klotz@free.fr","Klotz, A.","Boer, M.","Atteia, J.L."],"institutions":["CESR-CNRS","OHP","LATT-OMP"],"universities":["CNRS","OMP"]},"telescopes":{"facilities":[],"instruments":[],"observatories":["European Southern Observatory","La Silla observatory"],"telescopes":["TAROT"]},"urls":[],"basic_data":{"author":{"email":"Alain.Klotz@free.fr","institution":"CESR-CNRS","name":"Alain Klotz"},"coordinates":{},"detectionTime":"2007-09-22T06:09:32.000Z","event":"GRB 070920B","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6816\nSUBJECT: GRB 070920B: TAROT La Silla observatory optical observations\nDATE: 07/09/22 06:09:32 GMT\nFROM: Alain Klotz at CESR-CNRS  <Alain.Klotz@free.fr>\n\nKlotz, A. (CESR-OMP), Boer M. (OHP), Atteia J.L. (LATT-OMP) report:\n\nWe imaged the field of GRB 070920B detected by SWIFT\n(trigger 291728) with the TAROT robotic telescope (D=25cm)\nlocated at the European Southern Observatory,\nLa Silla observatory, Chile.\n\nThe observations started 2.7h after the GRB trigger\n(beginning of the night). The elevation of the field increased from\nfrom 27 degrees above horizon and weather conditions\nwere good but the moon (phase=0.58) was only at 68 degrees\nof the field, limiting the detectivity.\n\nWe co-added a series of 8 x 180s unfiltered exposures.\nWe do not detect any OT in the refined position\nprovided by Barthelmy et al. (GCNC 6811) nor the source\nreported by de Ugarte Postigo et al. (GCNC 6809):\n\nt0+2.7h to t0+3.6h : R > 18.2\n\nMagnitudes were estimated with the nearby USNO-B1 stars\nand are not corrected for galactic dust extinction\n(which is very low along the line of sight).\n\nThis message may be cited."}', 'The TAROT team at the European Southern Observatory used the 25cm TAROT robotic telescope to observe the field of GRB 070920B, which was detected by SWIFT, 2.7 hours after the trigger. They did not detect any optical transient at the reported position nor the source reported by other teams. The observations were limited by the presence of the moon and good but not ideal weather conditions.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6815', 'gcn', 'INTEGRAL ToO observations of SGR1806-20', '2007-09-21T23:23:49.000Z', '{"measurements":{"dec":null,"distance":null,"duration":[106299,48006,24003,27432],"energy":null,"fluence":null,"magnitude":null,"other_measurements":{},"ra":null,"redshift":null,"tables":[{"Duration (s)":106299,"Start time":"2007-09-30 00:06:42.0"},{"Duration (s)":48006,"Start time":"2007-10-01 07:04:45.0"},{"Duration (s)":24003,"Start time":"2007-10-01 21:20:21.0"},{"Duration (s)":27432,"Start time":"2007-10-02 04:42:45.0"}]},"authors":{"affiliations":["UCBerkeley/SSL"],"authors":["K. Hurley"],"institutions":["SSL (Space Sciences Laboratory)"],"universities":["UCBerkeley"]},"telescopes":{"facilities":[],"instruments":[],"observatories":[],"telescopes":["INTEGRAL"]},"urls":["<khurley@ssl.berkeley.edu>"],"basic_data":{"author":{"email":"khurley@ssl.berkeley.edu","institution":"UCBerkeley/SSL","name":"Kevin Hurley"},"coordinates":{},"detectionTime":"2007-09-21T23:23:49.000Z","event":"INTEGRAL ToO observations of SGR1806-20","eventType":"EP","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6815\nSUBJECT: INTEGRAL ToO observations of SGR1806-20\nDATE: 07/09/21 23:23:49 GMT\nFROM: Kevin Hurley at UCBerkeley/SSL  <khurley@ssl.berkeley.edu>\n\nK. Hurley, on behalf of the INTEGRAL Cycle 4 SGR ToO team, reports:\n\nIn view of the continued activity of SGR1806-20, a 206 ks INTEGRAL Target\nof Opportunity observation of this source has been scheduled.  The tentative\nobservation times are:\n\n     Start time           Duration (s)   \n2007-09-30 00:06:42.0       106299  \n2007-10-01 07:04:45.0        48006  \n2007-10-01 21:20:21.0        24003  \n2007-10-02 04:42:45.0        27432  \n\nAny major changes to these times will be reported in a future GCN.\n\nSupporting observations at all wavelengths are encouraged."}', 'An INTEGRAL Target of Opportunity observation of the magnetar SGR1806-20 has been scheduled for a duration of approximately 170,000 seconds, starting from September 30, 2007. The observation is a response to the continued activity of this source.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6814', 'gcn', 'GRB 070920b', '2007-09-21T18:11:29.000Z', '{"measurements":{"dec":null,"distance":null,"duration":4.4,"energy":null,"fluence":null,"magnitude":20.8,"other_measurements":{"mid_exposure_time_post_burst":"~4.4 hours","total_summed_exposure_time":"36 minutes"},"ra":null,"redshift":null,"tables":[]},"authors":{"affiliations":["Yale U"],"authors":["B. E. Cobb"],"institutions":["SMARTS consortium"],"universities":["Yale"]},"telescopes":{"facilities":[],"instruments":["ANDICAM"],"observatories":["CTIO"],"telescopes":["1.3m telescope at CTIO"]},"urls":["https://gcn.gsfc.nasa.gov"],"basic_data":{"author":{"email":"cobb@astro.yale.edu","institution":"Yale U","name":"Bethany Cobb"},"coordinates":{},"detectionTime":"2007-09-21T18:11:29.000Z","event":"GRB 070920b","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6814\nSUBJECT: GRB 070920b, SMARTS optical observation\nDATE: 07/09/21 18:11:29 GMT\nFROM: Bethany Cobb at Yale U  <cobb@astro.yale.edu>\n\nB. E. Cobb, part of the larger SMARTS consortium, reports:\n\nUsing the ANDICAM instrument on the 1.3m telescope at CTIO, we\nobtained optical imaging of the error region of GRB 070920b\n(Racusin et al. GCN 6808) with a mid-exposure time of ~4.4 hours\npost-burst (2007-09-21 01:29 UT).  The total summed exposure\ntime amounted to 36 minutes in I, but images were taken under poor\nweather conditions.\n\nComparison to the DSS reveals no new sources in the\nrefined GRB error region (Barthelmy et al. GCN 6811).\nOur I-band limiting magnitude is I~20.8 (calibrated using\nseveral USNO-B1.0 stars)."}', 'Astronomer B. E. Cobb of Yale University, as part of the SMARTS consortium, conducted optical observations of GRB 070920b using the 1.3m telescope at CTIO with the ANDICAM instrument. The team obtained a total summed exposure time of 36 minutes in I-band, but the images were taken under poor weather conditions. No new sources were detected in the refined GRB error region, and the team reported an I-band limiting magnitude of I~20.8.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6813', 'gcn', 'GRB 070917', '2007-09-21T14:12:52.000Z', '{"measurements":{"dec":2.410555555555556,"distance":null,"duration":35000,"energy":null,"fluence":null,"magnitude":null,"other_measurements":{"alpha":1.1,"alpha_error":0.3,"observation_duration":14000,"position_uncertainty":6,"time_range_seconds":[35000,350000],"uncertainty_unit":"arcsec"},"ra":19.594597222222223,"redshift":null,"tables":[]},"authors":{"affiliations":["U. Leicester","NASA/UMBC","Swift-XRT team"],"authors":["K.L. Page","J.R. Cummings"],"institutions":["NASA/UMBC"],"universities":["U. of Leicester"]},"telescopes":{"facilities":[],"instruments":["Swift-XRT"],"observatories":[],"telescopes":[]},"urls":["https://gcn.gsfc.nasa.gov"],"basic_data":{"author":{"email":"kpa@star.le.ac.uk","institution":"U.of Leicester","name":"Kim Page"},"coordinates":{"dec":19.59459722222222},"detectionTime":"2007-09-21T14:12:52.000Z","event":"GRB 070917","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6813\nSUBJECT: GRB 070917: Confirmation of the X-ray afterglow\nDATE: 07/09/21 14:12:52 GMT\nFROM: Kim Page at U.of Leicester  <kpa@star.le.ac.uk>\n\nK.L. Page (U. Leicester) and J.R. Cummings (NASA/UMBC) report on behalf of \nthe Swift-XRT team:\n\nAdditional Swift-XRT observations have been performed of the possible \nX-ray afterglow of GRB 070917 (Evans et al., GCN Circ. 6796). Between \n~3.5e4 and 3.5e5 seconds after the burst, the source has faded following a \npower-law decay slope of alpha = 1.1 +/- 0.3, confirming that it is, \nindeed, the afterglow. Using ~14 ks of data, we find a refined position of \nRA, Dec = 293.91897, 2.41104 degrees, which is equivalent to:\n\nRA(J2000) =  19 35 40.55\nDec(J2000)= +02 24 39.8\n\nwith an estimated uncertainty of 6.0 arcsec (radius, 90% containment \nincluding boresight uncertainty). This source is 0.7\" from the optical \ncounterpart discussed by Cenko (GCN Circ. 6800) and Fynbo et al. (GCN Circ \n6803).\n\nThis circular is an official product of the Swift-XRT team."}', 'The Swift-XRT team confirms the detection of an X-ray afterglow from GRB 070917, which occurred on July 9, 2021. The afterglow has a power-law decay slope of 1.1 +/- 0.3 and a refined position of RA(J2000) = 19 35 40.55, Dec(J2000) = +02 24 39.8 with an uncertainty of 6.0 arcsec.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6812', 'gcn', 'GRB 070920b', '2007-09-21T13:40:32.000Z', '{"measurements":{"dec":null,"distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":null,"other_measurements":{"exposure_time":"30 minutes","observation_time":"2007 Sep. 21.22 UT","seeing_conditions":"~1.5\"","time_after_burst":"8.2 hours"},"ra":null,"redshift":null,"tables":[]},"authors":{"affiliations":["Carnegie Obs (eberger@ociw.edu)","LCO (W. Krzeminski)"],"authors":["Edo Berger","W. Krzeminski"],"institutions":["OCIW","Las Campanas Observatory"],"universities":["Princeton"]},"telescopes":{"facilities":[],"instruments":[],"observatories":["Las Campanas Observatory"],"telescopes":["Swope 40-inch telescope"]},"urls":[],"basic_data":{"author":{"email":"eberger@ociw.edu","institution":"Carnegie Obs","name":"Edo Berger"},"coordinates":{},"detectionTime":"2007-09-21T13:40:32.000Z","event":"GRB 070920b","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6812\nSUBJECT: GRB 070920b: LCO optical observations\nDATE: 07/09/21 13:40:32 GMT\nFROM: Edo Berger at Carnegie Obs  <eberger@ociw.edu>\n\nE. Berger (Princeton,OCIW) and W. Krzeminski (LCO) report:\n\n\"We observed the BAT error circle of GRB 070920b (GCN 6808) with the Swope \n40-inch telescope at Las Campanas Observatory starting on 2007 Sep. 21.22 \nUT (8.2 hours after the burst).  A total of 30 minutes were obtained in \nR-band in mediocre seeing conditions (~1.5\").  A comparison to DSS reveals \nno new objects within the revised BAT error circle (GCN 6811).\""}', 'Astronomers Edo Berger from Princeton and W. Krzeminski from Las Campanas Observatory observed the error circle of GRB 070920b using the Swope 40-inch telescope 8.2 hours after the gamma-ray burst. No new objects were detected within the circle.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6811', 'gcn', 'GRB 070920B', '2007-09-21T13:22:10.000Z', '{"measurements":{"dec":-34.844,"distance":null,"duration":20.2,"energy":41.3,"fluence":6.6e-7,"magnitude":null,"other_measurements":{"chi_squared_exponential_cutoff":45.21,"chi_squared_power_law":67.16,"degrees_of_freedom":56,"duration_end":"+17 sec","duration_peak":"+1 sec","duration_start":"-20 sec","epeak":41.3,"fluence_band":"15-150 keV","fluence_value":"6.6 +- 0.5 x 10^-7 erg/cm2","peak_flux":0.8,"peak_flux_band":"15-150 keV","peak_flux_value":"0.8 +- 0.1 ph/cm2/sec","photon_index_exponential_cutoff":0.67,"photon_index_power_law":2},"ra":0.127,"redshift":null,"tables":[]},"authors":{"affiliations":["NASA/GSFC","GSFC/UMBC","GSFC","LANL","PSU","GSFC/ORAU","GSFC/ISAS","GSFC/ORAU"],"authors":["S.D. Barthelmy","L. Barbier","J. Cummings","E. Fenimore","N. Gehrels","H. Krimm","C. Markwardt","D. Palmer","J.L. Racusin","T. Sakamoto","G. Sato","M. Stamatikos","J. Tueller","T. Ukwatta"],"institutions":["NASA/GSFC","UMBC","LANL","PSU"],"universities":["GSFC","UMBC","LANL","PSU","ORAU","ISAS"]},"telescopes":{"facilities":[],"instruments":[],"observatories":[],"telescopes":[]},"urls":["https://gcn.gsfc.nasa.gov/gcn3/gcn3_circular_detail.msf?id=6811"],"basic_data":{"author":{"email":"scott@lheamail.gsfc.nasa.gov","institution":"NASA/GSFC","name":"Scott Barthelmy"},"coordinates":{},"detectionTime":"2007-09-21T13:22:10.000Z","event":"GRB 070920B","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6811\nSUBJECT: GRB 070920B, Swift-BAT refined analysis\nDATE: 07/09/21 13:22:10 GMT\nFROM: Scott Barthelmy at NASA/GSFC  <scott@lheamail.gsfc.nasa.gov>\n\nS.D. Barthelmy (GSFC), L. Barbier (GSFC), J. Cummings (GSFC/UMBC),\nE. Fenimore (LANL), N. Gehrels (GSFC), H. Krimm (GSFC/USRA),\nC. Markwardt (GSFC/UMD), D. Palmer (LANL), J.L. Racusin (PSU),\nT. Sakamoto (GSFC/ORAU), G. Sato (GSFC/ISAS), M. Stamatikos (GSFC/ORAU),\nJ. Tueller (GSFC), T. Ukwatta (GWU)\n(i.e. the Swift-BAT team):\n \nUsing the data set from T-240 to T+962 sec from recent telemetry downlinks,\nwe report further analysis of BAT GRB 070920B (trigger #291728)\n(Racusin, et al., GCN Circ. 6808).  The BAT ground-calculated position is\nRA, Dec = 0.127, -34.844 deg  which is \n   RA(J2000)  =  00h 0m 30.5s \n   Dec(J2000) = -34d 50'' 39\" \nwith an uncertainty of 1.0 arcmin, (radius, sys+stat, 90% containment).\nThe partial coding was 100%.\n \nThe mask-weighted lightcurve shows a symmetrical peak starting at ~T-20 sec,\npeaking at ~T+1 sec, and ending at ~T+17 sec.  T90 (15-350 keV) is\n20.2 +- 0.2 sec (estimated error including systematics).\n \nThe time-averaged spectrum from T-11.2 to T+13.4 sec is best fit by a power law\nwith an exponential cutoff.  This fit gives a photon index 0.67 +- 0.58, \nand Epeak of 41.3 +- 4.5 keV (chi squared 45.21 for 56 d.o.f.).  For this\nmodel the total fluence in the 15-150 keV band is 6.6 +- 0.5 x 10^-7 erg/cm2\nand the 1-sec peak flux measured from T-0.49 sec in the 15-150 keV band is\n0.8 +- 0.1 ph/cm2/sec.  A fit to a simple power law gives a photon index\nof 2.00 +- 0.10 (chi squared 67.16 for 57 d.o.f.).  All the quoted errors\nare at the 90% confidence level.\n\n[GCN OPS NOTE(21sep07): Per author''s request, the ''B'' was added to the GRB\nname in the first sentence.]"}', 'Astronomers from NASA and various institutions have released a refined analysis of GRB 070920B (Swift-BAT trigger #291728), reporting a symmetrical gamma-ray burst peaking at approximately 1 second with a duration of 20.2 seconds and a total fluence of 6.6e-07 erg/cm2 in the 15-150 keV band. The light curve and time-averaged spectrum were found to be best fit by a power law with an exponential cutoff.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6810', 'gcn', 'GRB 070911', '2007-09-21T13:14:44.000Z', '{"measurements":{"dec":null,"distance":null,"duration":205,"energy":{"Epeak":170,"Epeak_max":450,"Epeak_min":120,"alpha":-1.6,"alpha_error":0.1,"unit":"keV"},"fluence":{"max":0.000025,"min":0.000019,"unit":"erg/cm^2","value":0.000021},"magnitude":null,"other_measurements":{},"ra":null,"redshift":null,"tables":[]},"authors":{"affiliations":[],"authors":[],"institutions":[],"universities":[]},"telescopes":{"facilities":[],"instruments":[],"observatories":[],"telescopes":[]},"urls":[],"basic_data":{"author":{"email":"takanori@milkyway.gsfc.nasa.gov","institution":"NASA/GSFC","name":"Takanori Sakamoto"},"coordinates":{},"detectionTime":"2007-09-21T13:14:44.000Z","event":"GRB 070911","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6810\nSUBJECT: GRB 070911: Swift/BAT and Suzaku/WAM joint spectral analysis\nDATE: 07/09/21 13:14:44 GMT\nFROM: Takanori Sakamoto at NASA/GSFC  <takanori@milkyway.gsfc.nasa.gov>\n\nL. Barbier (GSFC), S. D. Barthelmy (GSFC), J. Cummings (GSFC/UMBC),\nE. Fenimore (LANL), N. Gehrels (GSFC), H. Krimm (GSFC/USRA),\nC. Markwardt (GSFC/UMD), D. Palmer (LANL), A. Parsons (GSFC),\nT. Sakamoto (GSFC/ORAU), G. Sato (GSFC/ISAS), M. Stamatikos (GSFC/ORAU),\nJ. Tueller (GSFC), T. Ukwatta (GWU)\non behalf of the Swift-BAT team,\n\nM. Ohno, T. Uehara, T. Takahashi, Y. Fukazawa, C. Kira (Hiroshima U.),\nY. E. Nakagawa, K. Yamaoka, S. Sugita (Aoyama Gakuin U.),\nY. Terada, T. Tamagawa (RIKEN), K. Morigami, N. Kodaka, K. Onda,\nM. Tashiro, M. Suzuki, Y. Urata, A. Endo (Saitama U.), T. Enoto,\nR. Miyawaki, K. Nakawaza, K. Makishima (Univ. of Tokyo), E. Sonoda,\nM. Yamauchi, S. Maeno, H. Tanaka, R. Hara (Univ. of Miyazaki),\nM. Kokubun, M. Suzuki, T. Takahashi (ISAS/JAXA), S. Hong (Nihon U.),\non behalf of the Suzaku-WAM team,\n\nreport:\n\nWe performed the Swift/BAT, and Suzaku/WAM joint fit spectral\nanalysis of GRB 070911 (Swift-BAT trigger #290624; Krimm, et al.,\nGCN Circ. 6777).  The time interval of the spectral data for each\ninstrument is chosen from T0(WAM)-56 to T0(WAM)+149 sec where\nT0(WAM) is the trigger time of WAM at 05:58:20.069 UTC.\nThe energy ranges which we used in the joint spectral analysis\nare 14-150 keV and 100-1000 keV for Swift/BAT and Suzaku/WAM\nrespectively.  The spectral data of two instruments are fit\nwith the spectral model multiplied by the constant factor to\ntake into account the systematic uncertainties in the response\nmatrices of each instrument.\n\nThe spectrum is well fit with a power-law with exponential cutoff\nmodel (dN/dE ~ E^{alpha} * exp(-(2+alpha)*E/Epeak)).  The constant\nfactors of each instrument agree within 10%.  No systematic residual\nfrom the best fit model is seen in the spectral data of each instrument.\nThe best fit spectral parameters are: alpha = -1.6 +- 0.1 and\nEpeak = 170 (-50/+280) keV (chi2/dof = 59/74).  The energy fluence\nin the 15-1000 keV band calculated by a power-law with exponential\ncutoff model for this 205 sec interval is 2.1 (-0.2/+0.4) x 10^-5 erg/cm2\n(assuming the constant factor of the BAT is fixed to 1).\n\nAll the quoted errors are at the 90% confidence level."}', 'Astronomers from NASA, Hiroshima University, Aoyama Gakuin University, RIKEN, Saitama University, ISAS/JAXA, Nihon University, and other institutions have performed a joint spectral analysis of GRB 070911 using Swift/BAT and Suzaku/WAM data. The gamma-ray burst, which occurred on September 11, 2007, was found to be well fit by a power-law with exponential cutoff model. The best-fit parameters include a power-law index of -1.6 ± 0.1 and a peak energy of 170 (-50/+280) keV. The energy fluence in the 15-1000 keV band was calculated to be 2.1 (-0.2/+0.4) x 10^-5 erg/cm2.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-681', 'gcn', 'GRB000528', '2000-05-30T20:51:09.000Z', '{"measurements":{"dec":-33.15,"distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":null,"other_measurements":{"annulus_radius":26.478,"annulus_radius_error":0.111,"second_emission_duration":600,"second_emission_intensity_ratio":1},"ra":129.532,"redshift":null,"tables":[]},"authors":{"affiliations":["UCBerkeley/SSL"],"authors":["K. Hurley","T. Cline","E. Mazets","F. Frontera","C. Guidorzi","E. Montanari"],"institutions":["Ulysses GRB team","Konus-Wind GRB team","BeppoSAX GRBM team"],"universities":["University of California, Berkeley"]},"telescopes":{"facilities":[],"instruments":[],"observatories":["ssl.berkeley.edu"],"telescopes":["Ulysses","Konus","BeppoSAX"]},"urls":["http://ssl.berkeley.edu/ipn3/000528"],"basic_data":{"author":{"email":"khurley@sunspot.ssl.berkeley.edu","institution":"UCBerkeley/SSL","name":"Kevin Hurley"},"coordinates":{},"detectionTime":"2000-05-30T20:51:09.000Z","event":"GRB000528","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 681\nSUBJECT: IPN localization and time history of GRB000528\nDATE: 00/05/30 20:51:09 GMT\nFROM: Kevin Hurley at UCBerkeley/SSL  <khurley@sunspot.ssl.berkeley.edu>\n\nK. Hurley, on behalf of the Ulysses GRB team, T. Cline and\nE. Mazets, on behalf of the Konus-Wind GRB team, and F. Frontera,\nC. Guidorzi, and E. Montanari, on behalf of the BeppoSAX GRBM\nteam, report:\n\nUlysses, Konus, and the BeppoSAX GRBM observed this burst (GCN #677).\nTriangulation gives a preliminary annulus centered at RA(2000)=129.532,\nDecl.(2000)=-33.150, with radius 26.478 +/- 0.111 degr. (3 sigma).\nThis annulus intersects the BeppoSAX WFC error circle at two points\n(RA, Decl.=161.292, -34.013, and RA, Decl.=161.283, -33.950), reducing\nits area by over a factor of two.  A map has been posted at\nssl.berkeley.edu/ipn3/000528.  This localization can be improved.\n\nIn addition, we call attention to the fact that the Ulysses data\nclearly show a second episode of emission which follows the burst by\n~600 seconds, with intensity approximately as great as that in the\nburst itself.  It is possible that this is from the same source as the\nburst; we are investigating whether the Konus or GRBM data can be used\nto verify this.  The time history has been posted at the same site."}', 'The Ulysses, Konus-Wind, and BeppoSAX teams have localized the position of gamma-ray burst GRB000528 with a preliminary annulus of radius 26.478 ± 0.111 degrees, centered at RA(2000) = 129.532, Dec(2000) = -33.150. A second episode of emission was detected approximately 600 seconds after the initial burst, with similar intensity. The teams are investigating if this second emission is from the same source.', 0.8, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6809', 'gcn', 'GRB 070920B', '2007-09-21T10:54:32.000Z', '{"measurements":{"dec":"-34:49:08.4","distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":null,"other_measurements":{"exposure_time_per_band":"180 s","observation_time":"21.0486 Sep. 2007 (UT)","time_after_burst":"~4.1 hours"},"ra":"00:00:34.56","redshift":null,"tables":[]},"authors":{"affiliations":["IAA-CSIC, Granada","U. Jaen","ING, La Palma","ING, La Palma and Tartuu Obs."],"authors":["A. de Ugarte Postigo","J. Gorosabel","M. Jelinek","A.J. Castro-Tirado","D. Perez-Ramirez","R. Corradi","T. Liimets"],"institutions":["IAA-CSIC","U. Jaen","ING"],"universities":["IAA-CSIC","U. Jaen"]},"telescopes":{"facilities":[],"instruments":["ALFOSC"],"observatories":["Roque de los Muchachos Observatory"],"telescopes":["2.5m NOT telescope"]},"urls":["www.iaa.es/~deugarte/GRBs/070920B/GRB070920B.jpg"],"basic_data":{"author":{"email":"deugarte@iaa.es","institution":"IAA-CSIC","name":"Antonio Deugarte"},"coordinates":{"dec":0.009600000000000001},"detectionTime":"2007-09-21T10:54:32.000Z","event":"GRB 070920B","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6809\nSUBJECT: GRB 070920B: NOT optical observations\nDATE: 07/09/21 10:54:32 GMT\nFROM: Antonio Deugarte at IAA-CSIC  <deugarte@iaa.es>\n\nA. de Ugarte Postigo, J. Gorosabel, M. Jelinek,\nA.J. Castro-Tirado (IAA-CSIC, Granada),\nD. Perez-Ramirez (U. Jaen), R. Corradi (ING, La Palma),\nT. Liimets (ING, La Palma and Tartuu Obs.) report:\n\nWe have observed the field of GRB070920B (Racusin et al.,\nGCNC 6808) using the 2.5m NOT telescope (+ALFOSC) at\nRoque de los Muchachos Observatory in V, R and I bands\n(180 s each) at high airmass. The mean time of the\nobservations was 21.0486 Sep. 2007 (UT), ~4.1 hours after\nthe burst.  We do not detect any bright afterglow candidate\nwithin the Swift/BAT error box.\nHowever, we do see a red, stationary object (detected in R\nand I bands) slightly over the DSS2 limit that does not seem\nto have its correspondent in the DSS2 images. The\ncoordinates of this object are (J2000 +/- 0.5\"):\n\nR.A.: 00:00:34.56\nDec.: -34:49:08.4\n\nFurther observations are needed to confirm wether this could\nbe the optical afterglow of GRB 070920B.\n\nA finding chart comparing with the DSS2 can be found at:\n\nwww.iaa.es/~deugarte/GRBs/070920B/GRB070920B.jpg\n\nThis message can be quoted."}', 'A team of astronomers led by A. de Ugarte Postigo et al. report non-detection of an optical afterglow for GRB 070920B using the 2.5m NOT telescope at Roque de los Muchachos Observatory. They did, however, detect a red, stationary object slightly over the DSS2 limit that may be the optical afterglow, but further observations are needed for confirmation.', 0.8, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6808', 'gcn', 'GRB 070920B', '2007-09-20T21:13:46.000Z', '{"measurements":{"dec":"-34d 49'' 06\"","distance":null,"duration":"35 sec","energy":null,"fluence":null,"magnitude":null,"other_measurements":{"peak_count_rate":"~2000 counts/sec (15-350 keV)"},"ra":"00h 00m 35s","redshift":null,"tables":[]},"authors":{"affiliations":["PSU","NASA/UMBC","NASA/GSFC","CRESST/GSFC/USRA","GSFC/USRA","GSFC/UMD","NASA/GSFC"],"authors":["J. L. Racusin","S. D. Barthelmy","J. R. Cummings","N. Gehrels","S. T. Holland","H. A. Krimm","C. B. Markwardt","F. E. Marshall","C. Pagani","D. M. Palmer","M. Stamatikos","T. N. Ukwatta","L. Vetere"],"institutions":["NASA/GSFC","CRESST/GSFC/USRA","NASA/ORAU","GSFC/GWU"],"universities":["Penn State University","NASA/UMBC","LANL","University of Maryland"]},"telescopes":{"facilities":[],"instruments":[],"observatories":[],"telescopes":["Swift Burst Alert Telescope (BAT)"]},"urls":["http://www.swift.psu.edu/too.html"],"basic_data":{"author":{"email":"scott@lheamail.gsfc.nasa.gov","institution":"NASA/GSFC","name":"Scott Barthelmy"},"coordinates":{},"detectionTime":"2007-09-20T21:13:46.000Z","event":"GRB 070920B","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6808\nSUBJECT: GRB 070920B: Swift detection of a burst\nDATE: 07/09/20 21:13:46 GMT\nFROM: Scott Barthelmy at NASA/GSFC  <scott@lheamail.gsfc.nasa.gov>\n\nJ. L. Racusin (PSU), S. D. Barthelmy (GSFC),\nJ. R. Cummings (NASA/UMBC), N. Gehrels (NASA/GSFC),\nS. T. Holland (CRESST/GSFC/USRA), H. A. Krimm (GSFC/USRA),\nC. B. Markwardt (CRESST/GSFC/UMD), F. E. Marshall (NASA/GSFC),\nC. Pagani (PSU), D. M. Palmer (LANL), M. Stamatikos (NASA/ORAU),\nT. N. Ukwatta (GSFC/GWU) and L. Vetere (PSU) report on behalf of the\nSwift Team:\n\nAt 21:04:32 UT, the Swift Burst Alert Telescope (BAT) triggered and\nlocated GRB 070920B (trigger=291728). \nThe BAT on-board calculated location is \nRA, Dec 0.144, -34.819 which is \n   RA(J2000)  = 00h 00m 35s\n   Dec(J2000) = -34d 49'' 06\"\nwith an uncertainty of 3 arcmin (radius, 90% containment, including \nsystematic uncertainty).  The BAT light curve shows a single peak\nwith a duration of about 35 sec.  The peak count rate\nwas ~2000 counts/sec (15-350 keV), at ~0 sec after the trigger. \n\nBecause Swift is in the process of returning to normal operations, \nautomatic slewing to GRBs is currently disabled.  Therefore, there \nare no prompt XRT or UVOT observations of this burst. \n\nBurst Advocate for this burst is J. L. Racusin (racusin AT astro.psu.edu). \nPlease contact the BA by email if you require additional information\nregarding Swift followup of this burst. In extremely urgent cases, after\ntrying the Burst Advocate, you can contact the Swift PI by phone (see\nSwift TOO web site for information: http://www.swift.psu.edu/too.html.)"}', 'The Swift Burst Alert Telescope (BAT) detected a gamma-ray burst (GRB 070920B) at 21:04:32 UT with a location of RA: 00h 00m 35s, Dec: -34d 49'' 06', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6807', 'gcn', 'GRB 070920', '2007-09-20T15:29:46.000Z', '{"measurements":{"dec":"72d 14'' 59\"","distance":null,"duration":"56 +- 1 sec","energy":null,"fluence":"5.1 +- 0.7 x 10^-7 erg/cm2","magnitude":null,"other_measurements":{"partial_coding":"100%","peak_photon_flux":"0.3 +- 0.1 ph/cm2/sec","power_law_index":"1.69 +- 0.21"},"ra":"06h 43m 52.2s","redshift":null,"tables":[]},"authors":{"affiliations":["GSFC","GSFC/UMBC","GSFC/UMD","LANL","PSU","GWU","GSFC/ORAU","ISAS/USRA"],"authors":["L. Barbier","S. D. Barthelmy","J. Cummings","E. Fenimore","N. Gehrels","D. Grupe","H. Krimm","C. Markwardt","D. Palmer","T. Sakamoto","G. Sato","M. Stamatikos","J. Tueller","T. Ukwatta"],"institutions":["NASA/GSFC","UMBC","GSFC/UMD","LANL","PSU","GWU","GSFC/ORAU","ISAS/USRA"],"universities":["GSFC","UMBC","UMD","LANL","PSU","ORAU","ISAS"]},"telescopes":{"facilities":[],"instruments":[],"observatories":[],"telescopes":[]},"urls":["https://gcn.gsfc.nasa.gov"],"basic_data":{"author":{"email":"scott@lheamail.gsfc.nasa.gov","institution":"NASA/GSFC","name":"Scott Barthelmy"},"coordinates":{},"detectionTime":"2007-09-20T15:29:46.000Z","event":"GRB 070920","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6807\nSUBJECT: GRB 070920, Swift-BAT refined analysis\nDATE: 07/09/20 15:29:46 GMT\nFROM: Scott Barthelmy at NASA/GSFC  <scott@lheamail.gsfc.nasa.gov>\n\nL. Barbier (GSFC), S. D. Barthelmy (GSFC), J. Cummings (GSFC/UMBC),\nE. Fenimore (LANL), N. Gehrels (GSFC), D. Grupe (PSU),\nH. Krimm (GSFC/USRA), C. Markwardt (GSFC/UMD), D. Palmer (LANL),\nT. Sakamoto (GSFC/ORAU), G. Sato (GSFC/ISAS), M. Stamatikos (GSFC/ORAU),\nJ. Tueller (GSFC), T. Ukwatta (GWU)\n(i.e. the Swift-BAT team):\n \nUsing the data set from T-119 to T+300 sec from recent telemetry downlinks,\nwe report further analysis of BAT GRB 070920 (trigger #291614)\n(Grupe, et al., GCN Circ. 6805).  The BAT ground-calculated position is\nRA, Dec = 100.968, 72.250 deg which is \n   RA(J2000) =  06h 43m 52.2s \n   Dec(J2000) = 72d 14'' 59\" \nwith an uncertainty of 2.1 arcmin, (radius, sys+stat, 90% containment).\nThe partial coding was 100%.\n \nThe mask-weighted lightcurve shows a single peak (with structure) starting\nat ~T-15 sec, broadly peaking at ~T+25 sec, and ending at ~T+140 sec.\nT90 (15-350 keV) is 56 +- 1 sec (estimated error including systematics).\n \nThe time-averaged spectrum from T+15.1 to T+75.0 sec is best fit by a simple\npower-law model.  The power law index of the time-averaged spectrum is\n1.69 +- 0.21.  The fluence in the 15-150 keV band is 5.1 +- 0.7 x 10^-7 erg/cm2.\nThe 1-sec peak photon flux measured from T+30.45 sec in the 15-150 keV band\nis 0.3 +- 0.1 ph/cm2/sec.  All the quoted errors are at the 90% confidence\nlevel."}', 'The Swift-BAT team has provided a refined analysis of GRB 070920 (trigger #291614), reporting a position with an uncertainty of 2.1 arcmin, a duration of 56 ± 1 sec, a time-averaged power-law index of 1.69 ± 0.21, and a fluence of 5.1 ± 0.7 x 10^-7 erg/cm2 in the 15-150 keV band. The peak photon flux was measured to be 0.3 ± 0.1 ph/cm2/sec.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6806', 'gcn', 'GRB 070920', '2007-09-20T05:04:31.000Z', '{"measurements":{"dec":null,"distance":null,"duration":90,"energy":null,"fluence":null,"magnitude":18.2,"other_measurements":{"elevation_of_field":57,"galactic_coordinates_lat":25.156,"galactic_coordinates_lon":142.6283,"galactic_extinction_in_R_band":0.3,"observation_duration":90,"observation_start_time_after_trigger":544.7,"weather_conditions":"excellents"},"ra":null,"redshift":null,"tables":[]},"authors":{"affiliations":["CESR-OMP","OHP","LATT-OMP"],"authors":["Alain.Klotz@free.fr","Klotz, A.","Boer, M.","Atteia, J.L."],"institutions":["CESR-CNRS","OHP","LATT-OMP"],"universities":["CNRS","OMP"]},"telescopes":{"facilities":[],"instruments":[],"observatories":["Calern observatory"],"telescopes":["TAROT"]},"urls":["http://gcn.gsfc.nasa.gov/gcn3/gcn3_circulars.html?id=6806"],"basic_data":{"author":{"email":"Alain.Klotz@free.fr","institution":"CESR-CNRS","name":"Alain Klotz"},"coordinates":{},"detectionTime":"2007-09-20T05:04:31.000Z","event":"GRB 070920","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6806\nSUBJECT: GRB 070920: TAROT Calern observatory optical observations\nDATE: 07/09/20 05:04:31 GMT\nFROM: Alain Klotz at CESR-CNRS  <Alain.Klotz@free.fr>\n\nKlotz, A. (CESR-OMP), Boer M. (OHP), Atteia J.L. (LATT-OMP) report:\n\nWe imaged the field of GRB 070920 detected by SWIFT\n(trigger 291614) with the TAROT robotic telescope (D=25cm)\nlocated at the Calern observatory, France.\n\nThe observations started 544.7s after the GRB trigger\n(6.8s after the notice). The elevation of the field increased from\nfrom 57 degrees above horizon and weather conditions\nwere excellents.\n\nThe date of trigger : t0 = 2007-09-20T04:00:14.112\n\nThe first image is 90.0s exposure in tracking mode:\nt0+544.7s to t0+634.7s : R > 18.2\n\nMagnitudes were estimated with the nearby USNO-B1 stars\nand are not corrected for galactic dust extinction.\n\nN.B. Galactic coordinates are lon=142.6283 lat=+25.1560\nand the galactic extinction in R band is 0.3 magnitudes\nestimated from D. Schlegel et al. 1998ApJ...500..525S.\n\nThis message may be cited."}', 'The TAROT robotic telescope at Calern observatory in France imaged the field of GRB 070920, a gamma-ray burst detected by SWIFT, 544.7 seconds after the trigger. The observations, which started with excellent weather conditions and an elevation of 57 degrees above the horizon, yielded a magnitude of 18.2 for the first image, a 90-second exposure. The galactic extinction in the R band is estimated to be 0.3 magnitudes.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6805', 'gcn', 'GRB 070920', '2007-09-20T04:19:07.000Z', '{"measurements":{"dec":"+72d 13'' 38\"","distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":null,"other_measurements":{"time_since_trigger":"64 seconds","trigger_number":291614,"trigger_time":"04:00:13 UT","uncertainty":"3 arcmin"},"ra":"06h 43m 44s","redshift":null,"tables":[]},"authors":{"affiliations":["astro.psu.edu","LANL","NASA/GSFC","GSFC/ISAS","NASA/ORAU"],"authors":["D. Grupe","N. Gehrels","F. E. Marshall","C. Pagani","D. M. Palmer","J. L. Racusin","G. Sato","M. Stamatikos","M. C. Stroh","T. N. Ukwatta","L. Vetere"],"institutions":["Swift Team","PSU","NASA/GSFC","GSFC/ISAS","NASA/ORAU"],"universities":["Penn State University","Los Alamos National Laboratory","NASA/Goddard Space Flight Center","GSFC/Isas","George Washington University"]},"telescopes":{"facilities":[],"instruments":[],"observatories":[],"telescopes":["Swift Burst Alert Telescope (BAT)"]},"urls":["http://www.swift.psu.edu/too.html"],"basic_data":{"author":{"email":"palmer@lanl.gov","institution":"LANL","name":"David Palmer"},"coordinates":{"dec":1.0002588888888888},"detectionTime":"2007-09-20T04:19:07.000Z","event":"GRB 070920","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6805\nSUBJECT: GRB 070920: Swift detection of a burst\nDATE: 07/09/20 04:19:07 GMT\nFROM: David Palmer at LANL  <palmer@lanl.gov>\n\nD. Grupe (PSU), N. Gehrels (NASA/GSFC), F. E. Marshall (NASA/GSFC),\nC. Pagani (PSU), D. M. Palmer (LANL), J. L. Racusin (PSU),\nG. Sato (GSFC/ISAS), M. Stamatikos (NASA/ORAU), M. C. Stroh (PSU),\nT. N. Ukwatta (GSFC/GWU) and L. Vetere (PSU) report on behalf of the\nSwift Team:\n\nAt 04:00:13 UT, the Swift Burst Alert Telescope (BAT) triggered and\nlocated GRB 070920 (trigger=291614). \nThe BAT on-board calculated location is \nRA, Dec 100.932, +72.227 which is \n   RA(J2000) = 06h 43m 44s\n   Dec(J2000) = +72d 13'' 38\"\nwith an uncertainty of 3 arcmin (radius, 90% containment, including \nsystematic uncertainty).  As is often the case with 64-second\nimage triggers, the BAT light curve shows no obvious\nvariation in the count rate. \n\nBecause Swift is in the process of returning to normal operations, \nautomatic slewing to GRBs is currently disabled.  Therefore, there \nare no prompt XRT or UVOT observations of this burst. \n\nBurst Advocate for this burst is D. Grupe (grupe AT astro.psu.edu). \nPlease contact the BA by email if you require additional information\nregarding Swift followup of this burst. In extremely urgent cases, after\ntrying the Burst Advocate, you can contact the Swift PI by phone (see\nSwift TOO web site for information: http://www.swift.psu.edu/too.html.)"}', 'The Swift Burst Alert Telescope (BAT) detected a gamma-ray burst (GRB 070920) at 04:00:13 UT with a calculated location of RA: 06h 43m 44s, Dec: +72d 13'' 38'''' and an uncertainty of 3 arcmin. The burst occurred while Swift was returning to normal operations, preventing prompt X-ray and ultraviolet observations. The Burst Advocate for follow-up information is D. Grupe (grupe@astro.psu.edu).', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6804', 'gcn', 'SGR1806-20', '2007-09-19T21:29:28.000Z', '{"measurements":{"dec":null,"distance":null,"duration":2,"energy":null,"fluence":null,"magnitude":null,"other_measurements":{"counts_per_second":[{"time":"~T+0 sec","value":190000},{"time":"~T+3 sec","value":2000},{"time":"~T+5 sec","value":10000},{"time":"~T+14 sec","value":50000},{"time":"~T+18 sec","value":30000}],"flux_ratio_to_crab":250,"previous_counts_per_second":50000},"ra":null,"redshift":null,"tables":[]},"authors":{"affiliations":["NASA/GSFC","LANL","NASA/ORAU","GSFC/ISAS"],"authors":["S. D. Barthelmy","D. M. Palmer","T. Sakamoto","G. Sato","M. Stamatikos"],"institutions":["NASA/GSFC","LANL","NASA/ORAU","GSFC/ISAS"],"universities":["NASA/GSFC"]},"telescopes":{"facilities":[],"instruments":["Swift-BAT","Konus-WIND and Konus-A","Suzaku-WAM","IBAS","SuperAGILE"],"observatories":[],"telescopes":["Swift Burst Alert Telescope (BAT)"]},"urls":["https://gcn.gsfc.nasa.gov/gcn3/gcn3_latest.html"],"basic_data":{"author":{"email":"scott@lheamail.gsfc.nasa.gov","institution":"NASA/GSFC","name":"Scott Barthelmy"},"coordinates":{},"detectionTime":"2007-09-19T21:29:28.000Z","event":"SGR1806-20","eventType":"EP","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6804\nSUBJECT: SGR1806-20: Swift-BAT detection of enhanced activity\nDATE: 07/09/19 21:29:28 GMT\nFROM: Scott Barthelmy at NASA/GSFC  <scott@lheamail.gsfc.nasa.gov>\n\nS. D. Barthelmy (GSFC), D. M. Palmer (LANL), T. Sakamoto (NASA/ORAU),\nG. Sato (GSFC/ISAS) and M. Stamatikos (NASA/ORAU) report on behalf of\nthe Swift Team:\n\nAt 20:45:10 UT, the Swift Burst Alert Telescope (BAT) triggered and\nlocated the SGR 1806-20 (trigger=291587).  We note that the initial\nGCN Notice went out with a dual identification of this source (both\nSGR 1900+14 and SGR 1806-20).  This is due to a mismatch error\nin the catalog numbers used between the on-board and ground catalogs\nfor this source.  The real identification is SGR 1806-20.  We also\nnote that because of a star tracker loss-of-lock error, the flight\nposition is 10 arcmin off the true position. \nThe BAT light curve shows a large initial spike of ~190,000 counts/sec\nwith an ~2 sec FWZM, followed by 4 smaller spikes: ~2000 cnts/sec\nat ~T+3 sec, 10,000 cnts/sec at ~T+5 sec, 50,000 cnts/sec at ~T+14 sec,\nand 30,000 cnts/sec at ~T+18 sec. \n\nSwift-BAT, and other space instruments (e.g. Konus-WIND\nand Konus-A, Suzaku-WAM, IBAS, and SuperAGILE) have been\ndetecting elevated activity from this source over the\npast few days. \n\nNotably, earlier today (at 16:01:12 UT, Trigger #291566)\na 50,000 counts/second burst (250 times the flux of \nthe Crab) was detected by BAT,  which made it the \nthird largest SGR ''baby'' burst (excluding activity \nrelated to the superburst) imaged by the Swift mission.  \nThe new Trigger #291587 burst reported here is much larger."}', 'The Swift Burst Alert Telescope (BAT) detected a large X-ray burst from SGR 1806-20, with an initial peak of ~190,000 counts/sec and subsequent smaller spikes. This is the fourth largest burst detected by Swift, excluding superbursts. The source has been exhibiting enhanced activity over the past few days, as observed by multiple space instruments.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6803', 'gcn', 'GRB070917', '2007-09-19T19:12:30.000Z', '{"measurements":{"dec":null,"distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":{"R-band":23.1},"other_measurements":{"observation_time":"2007 Sep. 17.89 UT","time_after_grb":"14 hr"},"ra":null,"redshift":null,"tables":[]},"authors":{"affiliations":["U.Copenhagen","Univ. Oslo","DARK/NBI"],"authors":["J.P.U. Fynbo","M.D. Stritzinger","C. Gall","A.O. Jaunsen","C.C. Thoene","D. Malesani","P. Vreeswijk","J. Hjorth","J. Sollerman"],"institutions":["DARK/NBI"],"universities":["University of Copenhagen","University of Oslo"]},"telescopes":{"facilities":[],"instruments":[],"observatories":[],"telescopes":["Nordic Optical Telescope"]},"urls":["https://gcn.gsfc.nasa.gov/gcn3/gcn3_circulars.html?id=6800","https://gcn.gsfc.nasa.gov/gcn3/gcn3_circulars.html?id=6791"],"basic_data":{"author":{"email":"jfynbo@astro.ku.dk","institution":"U.Copenhagen","name":"Johan U. Fynbo"},"coordinates":{},"detectionTime":"2007-09-19T19:12:30.000Z","event":"GRB070917","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6803\nSUBJECT: GRB070917: Confirmation of optical afterglow\nDATE: 07/09/19 19:12:30 GMT\nFROM: Johan U. Fynbo at U.Copenhagen  <jfynbo@astro.ku.dk>\n\nJ.P.U. Fynbo, M.D. Stritzinger, C. Gall (DARK/NBI), A.O. Jaunsen (Univ.\nOslo), C.C. Thoene, D. Malesani, P. Vreeswijk, J. Hjorth (DARK/NBI), J.\nSollerman (DARK and Univ. Stockholm) report on behalf of a larger\ncollaboration.\n\nWe observed the optical afterglow of GRB 070917 (Cummings et al., GCN\n6791; Cenko, GCN 6800) with the Nordic Optical Telescope. Observations\nstarted on 2007 Sep. 17.89 UT (14 hr after the GRB) in the V, R and I\nbands. We detect the candidate optical afterglow reported by Cenko (GCN\n6800) in all three bands. Assuming R=18.1 for the star USNO0900_15777166\nwe derive an R-band magnitude of 23.1. Compared to the magnitudes reported\nby Cenko (GCN 6800) the source appears to be fading and we hence confirm\nthis source as the likely optical afterglow of GRB 070917."}', 'A team of astronomers led by J.P.U. Fynbo from the University of Copenhagen and the Dark Cosmology Centre (DARK/NBI) report the confirmation of the optical afterglow of GRB 070917 using the Nordic Optical Telescope. The detection was made 14 hours after the gamma-ray burst in the V, R, and I bands, with an R-band magnitude of 23.1.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6802', 'gcn', 'GRB920925C', '2007-09-19T18:49:30.000Z', '{"measurements":{"dec":"+25 24 51.2","distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":25.4,"other_measurements":{},"ra":"22 03 31.04","redshift":null,"tables":[{"column_name":"R filter exposure time","value":"3540 s"},{"column_name":"R filter individual exposure time","value":"60 s"},{"column_name":"Number of exposures","value":"59"},{"column_name":"Limiting magnitude (2 sigma)","value":"25.4 mag"},{"column_name":"Photometry of S1","value":"23.2 +/-0.1 mag"}]},"authors":{"affiliations":["IKI, Moscow","CrAO","SAI MSU"],"authors":["V. Rumyantsev","A. Pozanenko","A. Volnova","A. Shulga"],"institutions":["CrAO","SAI MSU"],"universities":["IKI","MSU"]},"telescopes":{"facilities":[],"instruments":[],"observatories":["CrAO"],"telescopes":["Shajn 2.6m telescope of CrAO"]},"urls":["<http://grb.rssi.ru/GRB920925c/GRB920925C_20070710_ZTSh.gif>","http://grb.rssi.ru/GRB920925c/GRB920925C_20070710_ZTSh.gif"],"basic_data":{"author":{"email":"apozanen@iki.rssi.ru","institution":"IKI, Moscow","name":"Alexei Pozanenko"},"coordinates":{"dec":22.058622222222223},"detectionTime":"2007-09-19T18:49:30.000Z","event":"GRB920925C","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6802\nSUBJECT: GRB920925C: search for host galaxy\nDATE: 07/09/19 18:49:30 GMT\nFROM: Alexei Pozanenko at IKI, Moscow  <apozanen@iki.rssi.ru>\n\nV. Rumyantsev (CrAO),  A. Pozanenko (IKI),  A. Volnova, A. Shulga (SAI MSU) \nreport on behalf of larger GRB follow-up collaboration:\n\nWe observed  the region of probable optical afterglow of GRB 920925C \n(Denisenko et al., GCN 6155) with Shajn 2.6m telescope of CrAO on Jul. 10. \nSeries of images were obtained between (UT) 2007-07-10 21:05:34 and 22:13:36 \nin R filter. The limiting magnitude (2 sigma) of the combined image of a \ntotal exposure of 3540 s (59x60 s) is R=25.4 mag. No object is detected in a \nplace of the proposed optical afterglow (Denisenko et al., GCN 6155).   The \nnearest object to the position of proposed afterglow  is an extended object \nS1 at  (J2000) RA = 22 03 31.04 Dec= +25 24 51.2 which is ~ 9.5\" South from \nproposed afterglow. The photometry of the S1 is R=23.2 +/-0.1. Photometry \nand astrometry reductions are performed against USNO A2.0 catalog.\n\nThe combined image can be found in \nhttp://grb.rssi.ru/GRB920925c/GRB920925C_20070710_ZTSh.gif\n\nThe message may be cited."}', 'Astronomical alert: GRB920925C: search for host galaxy', 0.5, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6801', 'gcn', 'GRB070917', '2007-09-19T18:25:37.000Z', '{"measurements":{"dec":null,"distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":21.1,"other_measurements":{"exposure_time_per_image":"300 seconds","number_of_images":6,"observation_duration":"27 minutes"},"ra":null,"redshift":null,"tables":[]},"authors":{"affiliations":["CrAO","IKI"],"authors":["K. Antonyuk","V. Rumyantsev","A. Pozanenko"],"institutions":["CrAO","IKI"],"universities":["IKI","CrAO"]},"telescopes":{"facilities":[],"instruments":[],"observatories":["CrAO"],"telescopes":["AZT-11"]},"urls":["<http://grb.rssi.ru/GRB070917/GRB070917_AZT-11.gif>","http://grb.rssi.ru/GRB070917/GRB070917_AZT-11.gif"],"basic_data":{"author":{"email":"apozanen@iki.rssi.ru","institution":"IKI, Moscow","name":"Alexei Pozanenko"},"coordinates":{},"detectionTime":"2007-09-19T18:25:37.000Z","event":"GRB070917","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6801\nSUBJECT: GRB070917: optical observations\nDATE: 07/09/19 18:25:37 GMT\nFROM: Alexei Pozanenko at IKI, Moscow  <apozanen@iki.rssi.ru>\n\nK. Antonyuk, V. Rumyantsev (CrAO), A. Pozanenko (IKI) report on behalf of \nlarger GRB follow-up collaboration:\n\nWe observed the error box of  GRB070917  (Cummings  et al., GCN 6743) with \nAZT-11 telescope of CrAO on Sep. 17.  Series of images were obtained between \n(UT) 2007-09-17 18:58:08 and 19:25:37 in R filter. In a combined image of \n6x300 s within the XRT error circle (Evans et al., GCN 6796) we do not \ndetect any new sources in comparison with DSS2 up to the limiting magnitude \n(3 sigma) R=21.1. Photometry calibration is performed against USNO-A2.0. The \ncombined image can be found in \nhttp://grb.rssi.ru/GRB070917/GRB070917_AZT-11.gif.\n\nThis message may be cited."}', 'A team of astronomers led by K. Antonyuk, V. Rumyantsev, and A. Pozanenko reported no new sources detected within the error box of GRB070917 using the AZT-11 telescope at CrAO. The combined image obtained in the R filter between September 17, 2007, 18:58:08 and 19:25:37 did not reveal any sources above the limiting magnitude of R=21.1.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6800', 'gcn', 'GRB 070917', '2007-09-19T00:08:45.000Z', '{"measurements":{"dec":"+02:24:40.4","distance":null,"duration":"2.65 minutes","energy":null,"fluence":null,"magnitude":{"R":"~ 22.0 mag","i''":"~ 21.6 mag"},"other_measurements":{},"ra":"19:35:40.53","redshift":null,"tables":[]},"authors":{"affiliations":["Caltech"],"authors":["S. B. Cenko"],"institutions":["Caltech, larger collaboration"],"universities":["Caltech"]},"telescopes":{"facilities":[],"instruments":[],"observatories":[],"telescopes":["Palomar 60-inch telescope"]},"urls":["https://gcn.gsfc.nasa.gov/gcn3/gcn3_circulars.cfm?id=6800"],"basic_data":{"author":{"email":"cenko@srl.caltech.edu","institution":"Caltech","name":"S. Bradley Cenko"},"coordinates":{"dec":2.411222222222222,"ra":19.594591666666666},"detectionTime":"2007-09-19T00:08:45.000Z","event":"GRB 070917","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6800\nSUBJECT: GRB 070917: P60 Observations\nDATE: 07/09/19 00:08:45 GMT\nFROM: S. Bradley Cenko at Caltech  <cenko@srl.caltech.edu>\n\nS. B. Cenko (Caltech) reports on behalf of a larger collaboration:\n\nWe have imaged the field of GRB070917 (Cummings et al., GCN 6791) with the\nautomated Palomar 60-inch telescope.  Images were obtained in the Kron R\nand Sloan i'' filters beginning 2.65 minutes after the burst trigger under\npoor seeing conditions.\n\nInside the XRT error circle (Evans et al., GCN 6796), we marginally detect\nin both filters a single faint source not clearly visible in the DSS-II\nplate at the location (J2000.0)\n\n\tRA: 19:35:40.53\n\tDec: +02:24:40.4\n\nUsing several nearby stars from the USNO-B catalog for reference, and the\nempirical filter transformations from Jordi, Grebel, and Ammon (A&A 460,\n2006), we measure magnitudes of R ~ 22.0 mag, i'' ~ 21.6 mag, with the\nlarge uncertainties (~ 0.4 mag) due to both photometric calibration and\nthe faintness of object.\n\nGiven the faintness, we cannot determine at this time if this object is\nvariable.  Furthermore, as it likely lies below the detection limit of the\nDSS-II survey, further observations are required to establish if it is\nindeed the optical afterglow of GRB 070917."}', 'A team led by S.B. Cenko at Caltech reported the detection of a faint optical source, likely the afterglow of GRB 070917, using the Palomar 60-inch telescope. The source was measured to have magnitudes of R ~ 22.0 mag and i'' ~ 21.6 mag, with large uncertainties. Further observations are required to confirm its identification and variability.', 0.85, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-680', 'gcn', 'GRB000529', '2000-05-30T18:26:57.000Z', '{"measurements":{"dec":-33.077,"distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":null,"other_measurements":{"radius":76.204,"radius_uncertainty":0.054,"reduction_percentage":30},"ra":129.603,"redshift":null,"tables":[]},"authors":{"affiliations":["UCBerkeley/SSL","NEAR","KONUS"],"authors":["K. Hurley","T. Cline","F. Frontera","C. Guidorzi","E. Montanari","E. Mazets","S. Golenetskii"],"institutions":["Ulysses GRB team","NEAR GRB team","KONUS GRB team","BeppoSAX GRBM teams","KONUS-WIND GRB teams"],"universities":["UC Berkeley"]},"telescopes":{"facilities":[],"instruments":[],"observatories":["ssl.berkeley.edu"],"telescopes":["Ulysses","BeppoSAX","KONUS-WIND"]},"urls":["http://ssl.berkeley.edu/ipn3/000529"],"basic_data":{"author":{"email":"khurley@sunspot.ssl.berkeley.edu","institution":"UCBerkeley/SSL","name":"Kevin Hurley"},"coordinates":{},"detectionTime":"2000-05-30T18:26:57.000Z","event":"GRB000529","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 680\nSUBJECT: New IPN localization of GRB000529\nDATE: 00/05/30 18:26:57 GMT\nFROM: Kevin Hurley at UCBerkeley/SSL  <khurley@sunspot.ssl.berkeley.edu>\n\nK. Hurley, on behalf of the Ulysses GRB team, T. Cline,  on behalf\nof the NEAR and KONUS GRB teams, F. Frontera, C. Guidorzi, and E.\nMontanari, on behalf of the BeppoSAX GRBM teams, and E. Mazets and\nS. Golenetskii, on behalf of the KONUS-WIND GRB teams, report:\n\nThe Ulysses data for this burst (GCN #676) have been processed, and the\ntriangulation has been completed (GCN #678).  The Ulysses/ Earth\nannulus is centered at RA(2000)=129.603, Decl.(2000)=-33.077, and has a\nradius 76.204 +/- 0.054 deg.  This annulus intersects the BeppoSAX WFC\nerror circle at two points (RA, Decl.= 2.217, -61.555 and RA,\nDecl.=2.406,-61.470) and reduces its area by ~30%.  A map has been\nposted at ssl.berkeley.edu/ipn3/000529.  Further refinement to this\nannulus is possible."}', 'A new localization for the gamma-ray burst GRB000529 has been determined using data from Ulysses, BeppoSAX, NEAR, KONUS, and KONUS-WIND. The Ulysses data processing and triangulation have been completed, resulting in an annulus with a radius of 76.204 ± 0.054 deg and a reduction of approximately 30% in area. The annulus intersects the BeppoSAX error circle at two points.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6799', 'gcn', 'GRB 070917', '2007-09-18T13:58:34.000Z', '{"measurements":{"dec":null,"distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":null,"other_measurements":{"pseudo-redshift":{"uncertainty":1.2,"value":2.4}},"ra":null,"redshift":2.4,"tables":[]},"authors":{"affiliations":["LATT-OMP","AST (Observatoire Midi-Pyrénées)"],"authors":["A. Pelangeon","J-L. Atteia","Golenetskii et al."],"institutions":["LATT-OMP","AST (Observatoire Midi-Pyrénées)","GCN"],"universities":["LATT-OMP","AST (Observatoire Midi-Pyrénées)"]},"telescopes":{"facilities":[],"instruments":[],"observatories":["GCN"],"telescopes":["SWIFT-BAT"]},"urls":["http://www.ast.obs-mip.fr/grb/pz"],"basic_data":{"author":{"email":"alexandre.pelangeon@ast.obs-mip.fr","institution":"LATT,OMP,Toulouse","name":"Alexandre Pelangeon"},"coordinates":{},"detectionTime":"2007-09-18T13:58:34.000Z","event":"GRB 070917","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6799\nSUBJECT: GRB 070917: pseudo-z= 2.40 from prompt emission spectrum\nDATE: 07/09/18 13:58:34 GMT\nFROM: Alexandre Pelangeon at LATT,OMP,Toulouse  <alexandre.pelangeon@ast.obs-mip.fr>\n\nA. Pelangeon & J-L. Atteia (LATT-OMP) report:\n\nWe have used the spectral parameters of the most intense\npart of GRB 070917 provided by Golenetskii et al. (GCNC 6798)\nto compute the spectral pseudo-redshift(**)  of this burst\ndetected by SWIFT-BAT (Cummings et al., GCNC 6791).\n\nWe find a pseudo-redshift pz= 2.40 +/- 1.20\n\n\n(**) cf. http://www.ast.obs-mip.fr/grb/pz"}', 'Astronomers using spectral data from the GRB 070917 event detected by SWIFT-BAT have estimated a pseudo-redshift of 2.40 +/- 1.20.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6798', 'gcn', 'GRB 070917', '2007-09-18T11:56:48.000Z', '{"measurements":{"dec":null,"distance":null,"duration":6,"energy":{"max":306,"min":163,"unit":"keV","value":211},"fluence":{"max":5.16,"min":2.14,"unit":"x10^-6 erg/cm2","value":4.9},"magnitude":null,"other_measurements":{"alpha":{"max":1.57,"min":1.11,"value":1.36},"chi2":58.9,"dof":60,"peak_flux":{"max":5.35,"min":1.79,"unit":"x10^-6 erg/cm2/s","value":4.44}},"ra":null,"redshift":null,"tables":[]},"authors":{"affiliations":["Ioffe Inst, on behalf of the Konus-Wind team"],"authors":["S. Golenetskii","R. Aptekar","E. Mazets","V. Pal''shin","D. Frederiks","T. Cline"],"institutions":["Ioffe Inst"],"universities":["Ioffe Inst"]},"telescopes":{"facilities":[],"instruments":[],"observatories":[],"telescopes":["Konus-Wind"]},"urls":["http://www.ioffe.rssi.ru/LEA/GRBs/GRB070917_T27239/"],"basic_data":{"author":{"email":"val@mail.ioffe.ru","institution":"Ioffe Inst","name":"Valentin Pal''shin"},"coordinates":{},"detectionTime":"2007-09-18T11:56:48.000Z","event":"GRB 070917","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6798\nSUBJECT: Konus-Wind observation of GRB 070917\nDATE: 07/09/18 11:56:48 GMT\nFROM: Valentin Pal''shin at Ioffe Inst  <val@mail.ioffe.ru>\n\nS. Golenetskii, R.Aptekar, E. Mazets, V. Pal''shin, D. Frederiks,\nand T. Cline on behalf of the Konus-Wind team report:\n\nThe long GRB 070917 (Swift-BAT trigger #291292:\nCummings et al., GCN 6791; Tueller et al., GCN 6792) triggered\nKonus-Wind at T0=27239.542 s UT (07:33:59.542).\n\nThe burst light curve shows a single pulse with a duration of ~6 s.\nAs observed by Konus-Wind the burst\nhad a fluence of 4.90(-2.76, +0.26)x10^-6 erg/cm2,\nand a 64-ms peak flux measured from T0-0.016 s\nof 4.44(-2.65, +0.91)x10^-6 erg/cm2/s\n(both in the 20 keV - 1 MeV energy range).\n\nThe time-integrated spectrum of the burst\n(from T0 to T0+8.448 s) is well fitted\n(in the 20 keV - 1 MeV range)\nby a power law with exponential cutoff model:\ndN/dE ~ E^(-alpha)*exp(-E*(2-alpha)/Ep)\nwith alpha = 1.36(-0.25, +0.21)\nand Ep = 211(-48, +95) keV (chi2 = 58.9/60 dof).\n\nAll the quoted errors are at the 90% confidence level.\n\nThe Konus-Wind light curve of this GRB is available\nat http://www.ioffe.rssi.ru/LEA/GRBs/GRB070917_T27239/"}', 'The Konus-Wind team reports the observation of a long gamma-ray burst (GRB 070917) triggered at T0=27239.542 s UT. The burst had a duration of approximately 6 seconds and a fluence of (4.90 ± 0.26)x10^-6 erg/cm2 in the 20 keV - 1 MeV energy range. The time-integrated spectrum was well fitted by a power law with exponential cutoff model, with a photon index of 1.36±0.21 and a cutoff energy of 211±95 keV.', 0.9, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6797', 'gcn', 'Swift Status and XRT Calibration Uncertainties', '2007-09-18T10:57:59.000Z', '{"measurements":{"dec":null,"distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":null,"other_measurements":{"gain_change":"5%","position_uncertainty":"6-8 arcseconds","qe_change":"10% for E>6 keV"},"ra":null,"redshift":null,"tables":[]},"authors":{"affiliations":["PSU","U. Leicester","OAB","NASA/GSFC"],"authors":["D. N. Burrows","J. P. Osborne","G. Chincarini","N. Gehrels"],"institutions":["PSU/Swift","U. Leicester"],"universities":["PSU","U. Leicester"]},"telescopes":{"facilities":[],"instruments":["BAT","XRT","UVOT"],"observatories":["Swift"],"telescopes":["Swift"]},"urls":["https://gcn.gsfc.nasa.gov"],"basic_data":{"author":{"email":"dnburrows@gmail.com","institution":"PSU/Swift","name":"David Burrows"},"coordinates":{},"detectionTime":"2007-09-18T10:57:59.000Z","event":"Swift Status and XRT Calibration Uncertainties","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6797\nSUBJECT: Swift Status and XRT Calibration Uncertainties\nDATE: 07/09/18 10:57:59 GMT\nFROM: David Burrows at PSU/Swift  <dnburrows@gmail.com>\n\nD. N. Burrows (PSU), J. P. Osborne (U. Leicester), G. Chincarini \n(OAB), and N. Gehrels (NASA/GSFC) report on behalf of the Swift XRT team:\n\nThe Swift observatory continues to progress toward full operations. \nCurrently BAT and XRT are turned on and operating.  BAT is detecting \nGRBs and distributing Notices in real time (Barthelmy et al. GCN \n6781).  UVOT remains off and autonomous GRB slewing remains disabled \nuntil completion of the spacecraft gyro calibrations, which are still \non-going.  XRT is performing some delayed observations of GRBs and \nposting results by manually generated Circulars (such as GCN Circular \n6796).  XRT Notices are not yet enabled for automatic distribution.\n\nWe would like to issue the following general caveats for performance \nof the XRT following the observatory safe-hold recovery operations:\n\n1) Position determination: The safe-hold event resulted in all 3 \nSwift instruments being turned off and the observatory cooling down \nto survival temperatures.  The observatory is now operating at its \nnormal operating temperature once again, but there is a possibility \nthat the thermal cycle caused by the safe-hold may have resulted in a \nshift to the XRT boresight.  There is also a known boresight shift \nintroduced into the ACS software during the recovery operations as \npart of the change to a redundant gryo.  Initial indications suggest \nthat the XRT boresight shift is small, but until XRT boresight \nrecalibrations are complete, we cannot guarantee the same level of \naccuracy in XRT positions obtained prior to the \nsafehold.  Recalibration of the XRT boresight is our top priority and \nwe will provide updates on the results as they become available.  In \nthe meantime, we are increasing XRT position uncertainties (to 6-8 \narcseconds) to account for the uncertainty introduced by this event.\n\n2) Spectroscopy: the XRT team has been working for many months \ntowards a change in the CCD substrate voltage in order to reduce dark \ncurrent and minimize the effects of the elevated operating \ntemperatures of the XRT CCD.  This voltage change has now been \nimplemented and we are recalibrating the instrument.  Until the \nrecalibration is completed, there may be small gain changes (of order \n5%) and QE changes (of order 10% for E>6 keV) that are not correctly \naccounted for by the current CALDB files.  We will update the CALDB \nfiles as soon as possible.  Meanwhile, we urge caution in the \ninterpretation of spectral data, and we urge all users to process \ndata through xrtpipeline themselves using the latest available CALDB \nfiles until the changes have worked their way into the standard \nproduction pipelines at the Swift Data Center.  In particular, we \nnote that small gain errors can introduce spurious spectral features \nassociated with the Oxygen K edge, the Si K edge, and the Gold M edge \nin the instrument response.  These can be handled during spectral \nfits by allowing a gain adjustment in XSPEC to minimize these features."}', 'Swift observatory is recovering from a safe-hold event and experiencing uncertainties with XRT position determination and spectroscopy. Position uncertainties have increased to 6-8 arcseconds, and there may be gain and QE changes in XRT spectroscopy until recalibration is complete. Users are urged to process data through xrtpipeline using the latest CALDB files.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6796', 'gcn', 'GRB 070917', '2007-09-18T08:53:44.000Z', '{"measurements":{"dec":2.41055,"distance":null,"duration":2.3,"energy":null,"fluence":null,"magnitude":null,"other_measurements":{"Data duration":"2.3 ks","Distance from BAT position":"37 arcsec","Observation period":"T0+35000-42000 s","Time since trigger":"35 ks","Uncertainty":"8.0 arcsec"},"ra":293.91913,"redshift":null,"tables":[{"Column1":"Count rate","Column2":"0.016 counts s^-1"},{"Column1":"Absorption","Column2":"1.73e21 cm^-2"},{"Column1":"Spectral slope","Column2":"1.17 (+0.44/-0.45)"},{"Column1":"Observed flux","Column2":"1.31e-12 erg/cm^2/s"},{"Column1":"Unabsorbed flux","Column2":"1.44e-12 erg/cm^2/s"}]},"authors":{"affiliations":["U. Leicester","NASA/UMBC"],"authors":["P.A. Evans","A.P. Beardmore","K.L. Page","R.L.C. Starling","J.R. Cummings"],"institutions":["U of Leicester","NASA/UMBC"],"universities":["University of Leicester"]},"telescopes":{"facilities":[],"instruments":["Swift-XRT"],"observatories":[],"telescopes":["Swift"]},"urls":["https://gcn.gsfc.nasa.gov"],"basic_data":{"author":{"email":"pae9@star.le.ac.uk","institution":"U of Leicester","name":"Phil Evans"},"coordinates":{},"detectionTime":"2007-09-18T08:53:44.000Z","event":"GRB 070917","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6796\nSUBJECT: GRB 070917: Swift-XRT observations\nDATE: 07/09/18 08:53:44 GMT\nFROM: Phil Evans at U of Leicester  <pae9@star.le.ac.uk>\n\nP.A. Evans, A.P. Beardmore, K.L. Page, R.L.C. Starling (U. Leicester)\nand J.R. Cummings (NASA/UMBC) report on behalf of the Swift-XRT team:\n\nWe have analysed 2.3 ks of Swift XRT data for GRB 070917 (Cummings et\nal. GCN Circ 6791) beginning 35 ks after the trigger. The data are\nentirely in Photon Counting mode. An uncatalogued X-ray source is\nclearly detected at RA, Dec= 293.91913, +2.41055 degrees, which is\nequivalent to:\n\nRA (J2000) =  19h 35m 40.59s\nDec(J2000) = +02d 24'' 38.0\"\n\nwith an estimated uncertainty of 8.0 arcsec (radius, 90% containment\nincluding boresight uncertainty). This is 37 arcsec from the BAT refined\nposition  (Tueller et al. GCN Circ 6792). The source has a count rate of\n0.016 counts s^-1. At present we are unable to determine whether the\nsource is fading, however observations are ongoing.\n\nUsing the C-statistic in xspec we fit the PC mode spectrum from\nT0+35000-42000 s with an absorbed power-law. The absorption is\nconsistant with the Galactic value of 1.73e21 cm^-2 (Kalberla et al.\n2005). The spectral slope is gamma=1.17 (+0.44/-0.45), which is\nconsistent with the BAT value of 1.52 +/- 0.04. The observed\n(unabsorbed) flux is 1.31e-12 (1.44e-12) erg/cm^2/s.\n\nThis circular is an official product of the Swift team."}', 'Swift-XRT team reports the detection of an uncatalogued X-ray source, 37 arcsec from the BAT position of GRB 070917, with a count rate of 0.016 counts s^-1 and spectral slope of gamma=1.17 (+0.44/-0.45). The observed and unabsorbed fluxes are 1.31e-12 and 1.44e-12 erg/cm^2/s, respectively.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6795', 'gcn', 'GRB 070917', '2007-09-17T23:05:15.000Z', '{"measurements":[16.8,16.7,16.8,16.7,16.9,16.2,17.3,17.9],"authors":{"affiliations":["University of California, Berkeley","KAIT/LOSS"],"authors":["W. Li"],"institutions":["UC Berkeley","KAIT/LOSS"],"universities":["University of California, Berkeley"]},"telescopes":{"facilities":[],"instruments":[],"observatories":["Lick Observatory"],"telescopes":["Katzman Automatic Imaging Telescope (KAIT)"]},"urls":["<https://gcn.gsfc.nasa.gov/>"],"basic_data":{"author":{"email":"weidong@astron.berkeley.edu","institution":"UC Berkeley KAIT/LOSS","name":"Weidong Li"},"coordinates":{},"detectionTime":"2007-09-17T23:05:15.000Z","event":"GRB 070917","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6795\nSUBJECT: GRB 070917: KAIT optical limits\nDATE: 07/09/17 23:05:15 GMT\nFROM: Weidong Li at UC Berkeley KAIT/LOSS  <weidong@astron.berkeley.edu>\n\nW. Li, University of California, Berkeley, on behalf of the KAIT GRB\nteam, report:\n\nThe robotic 0.76-m Katzman Automatic Imaging Telescope (KAIT)\nat Lick Observatory observed GRB 070917 detected with Swift\n(Trigger 291292; Cummings et al. GCN 6791, Tueller et al. GCN \n6792). The automatic sequence started at 07:34:52, 56 s after\nthe burst. The BAT location has been monitored in V, I, and\nclear filters, with varying exposure times. Our image processing\npipeline did not find any new objects within the BAT error circle,\nwith the following photometry limits (calibrated with USNO B1.0).\nThese magnitudes have not been corrected for Galactic extinction\n(E(B - V) = 0.45 mag; Misra et al. GCN 6793).  \n\n======================================================================\n\nStart UT   t(GRB)   Filter    Exp(s)  3sigma-limit      \n\n07:34:52     56s    clear      5.0      16.8 \n07:34:58     62s    clear      5.0      16.7 \n07:35:04     68s    clear      5.0      16.8 \n07:35:10     74s    clear      5.0      16.7 \n07:35:17     81s    clear      5.0      16.9 \n07:35:48    112s    V         20.0      16.2\n07:36:19    143s    I         20.0      17.3\n07:36:49    173s    clear     20.0      17.9\n========================================================================\n\nMore images, mostly 20 s exposures in the I and clear filters,\nhave been obtained. No obvious OA was found in the BAT error\ncircle to a limiting magnitude of 16.9 - 18.0 mag, at \nt= 204 s to 2204 s after the burst. \n\nThis message may be cited."}', 'The KAIT team at UC Berkeley reported no detection of an optical afterglow within the error circle of GRB 070917 using the Katzman Automatic Imaging Telescope at Lick Observatory. The team obtained images in various filters and exposure times, with limiting magnitudes ranging from 16.2 to 17.9. No obvious afterglow was found between 204 seconds and 2204 seconds post-burst.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6794', 'gcn', 'GRB 070917', '2007-09-17T19:10:51.000Z', '{"measurements":{"dec":null,"distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":17.8,"other_measurements":{},"ra":null,"redshift":null,"tables":[{"Exposure":"13 x 60s","Filter":"Ic","Mag (3-sigma UL)":17.8,"end time":"10:08:08","start time":"09:46:58"}]},"authors":{"affiliations":["Tokyo Tech"],"authors":["T. Ishimura","T. Shimokawabe","N. Vasquez","Y. Yatsu","Y. Kudou","N. Kawai"],"institutions":["MITSuME collaboration"],"universities":["Tokyo Tech"]},"telescopes":{"facilities":[],"instruments":[],"observatories":["Akeno, Japan"],"telescopes":["3-color 50cm MITSuME Telescope"]},"urls":[],"basic_data":{"author":{"email":"nkawai@hp.phys.titech.ac.jp","institution":"Tokyo Tech","name":"Nobuyuki Kawai"},"coordinates":{},"detectionTime":"2007-09-17T19:10:51.000Z","event":"GRB 070917","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6794\nSUBJECT: GRB 070917: MITSuME Akeno Ic upper limit\nDATE: 07/09/17 19:10:51 GMT\nFROM: Nobuyuki Kawai at Tokyo Tech  <nkawai@hp.phys.titech.ac.jp>\n\nT. Ishimura, T. Shimokawabe, N. Vasquez, Y. Yatsu, Y. Kudou and\nN. Kawai (Tokyo Tech) report on behalf of the MITSuME collaboration:\n \nWe observed the field of GRB070917 (Cummings et al. GCN 6791)\nwith the 3-color 50cm MITSuME Telescope at Akeno, Japan starting \nat 09:46:58 UT, 2.2 hours after the trigger.\nAlthough the observation was performed in three bands (Ic, Rc, and g''),\nonly the data in Ic band are usable for reliable comparison to \ncatalogued sources because of the poor sky condition in the dusk \nwith thin clouds.\n\nWe did not detect a new source in the BAT error circle.  The 3-sigma\nlimiting magnitude based on USNO-B1.0 (I-band) stars is following.\n\nFilter   start time   end time    Exposure   Mag (3-sigma UL)  \n-----------------------------------------------------------\n Ic      09:46:58\u001b$B!!\u001b(B   10:08:08\u001b$B!!!!\u001b(B13 x 60s    17.8\n-----------------------------------------------------------"}', 'The MITSuME collaboration at Tokyo Tech reported no detection of a new source in the error circle of GRB070917 using the 3-color 50cm MITSuME Telescope at Akeno, Japan. The team obtained usable data only in the Ic band due to poor sky conditions. The 3-sigma limiting magnitude in the Ic band was measured to be 17.8.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6793', 'gcn', 'GRB 070917', '2007-09-17T16:47:00.000Z', '{"measurements":{"dec":null,"distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":20.5,"other_measurements":{"exposure_time_seconds":1500,"extinction_value":0.45,"nearby_star_magnitude":16.6,"observation_time_hours":7.5},"ra":null,"redshift":null,"tables":[]},"authors":{"affiliations":["ARIES, Nainital, India","on behalf of larger Indian GRB collaboration"],"authors":["K. Misra","S. B. Pandey","Rupak Roy"],"institutions":["ARIES"],"universities":["ARIES, Nainital, India"]},"telescopes":{"facilities":[],"instruments":[],"observatories":["NainiTal"],"telescopes":["1.04m telescope"]},"urls":["https://gcn.gsfc.nasa.gov/gcn3/gcn3_circular_detail.msfc?id=6791","https://gcn.gsfc.nasa.gov/gcn3/gcn3_circular_detail.msfc?id=6792"],"basic_data":{"author":{"email":"kuntal@aries.ernet.in","institution":"ARIES,Nainital,India","name":"Kuntal Mishra"},"coordinates":{},"detectionTime":"2007-09-17T16:47:00.000Z","event":"GRB 070917","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6793\nSUBJECT: GRB 070917: R band observations\nDATE: 07/09/17 16:47:00 GMT\nFROM: Kuntal Mishra at ARIES,Nainital,India  <kuntal@aries.ernet.in>\n\nK. Misra, S. B. Pandey and Rupak Roy (ARIES, NainiTal, India, on bahalf \nof larger Indian GRB collaboration)\n\nWe have imaged the field of Swift GRB 070917 with the 1.04m telescope at \nNainiTal ~ 7.5 hours after the burst (Cummings et al. GCN 6791). \nObservations were performed in R band (5*300 sec) in poor sky conditions.\n\nWe notice that the field is crowded and a considerable amount of \nextinction (E(B - V) = 0.45 mag) is there in the burst direction. Visual \ncomparison with DSS-II plate does not show any new source within the \nrefined error-box (Tueller et al. GCN 6792). Photometry of the co-added \nframe put a 3 sigma upper limit of ~20.5 mag in comparison to the nearby \nUSNO A2.0 star 0900-15768267 (R mag 16.6)\n\nThis message may be cited."}', 'The ARIES team at Nainital, India, observed the field of Swift GRB 070917 using the 1.04m telescope 7.5 hours after the burst. The observations were carried out in R band with a total exposure time of 1500 seconds. No new source was detected within the error box, and a 3 sigma upper limit of ~20.5 mag was obtained for the burst. The team noted poor sky conditions and considerable extinction (E(B - V) = 0.45 mag) in the burst direction.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6792', 'gcn', 'GRB 070917', '2007-09-17T14:34:18.000Z', '{"measurements":{"dec":"02d 25'' 12\"","distance":null,"duration":"7.3 +- 0.2 sec","energy":null,"fluence":"2.0 +- 0.1 x 10^-6 erg/cm2","magnitude":null,"other_measurements":{"partial_coding":"79%","peak_photon_flux":"8.5 +- 0.3 ph/cm2/sec","power_law_index":"1.52 +- 0.05"},"ra":"19h 35m 41.5s","redshift":null,"tables":[]},"authors":{"affiliations":["GSFC (Goddard Space Flight Center)","UMBC (University of Maryland, Baltimore County)","UMD (University of Maryland, College Park)","LANL (Los Alamos National Laboratory)","ORAU (Oak Ridge Associated Universities)","ISAS (Institute of Space and Astronautical Science)"],"authors":["J. Tueller","L. Barbier","S. D. Barthelmy","J. Cummings","E. Fenimore","N. Gehrels","H. Krimm","C. Markwardt","D. Palmer","T. Sakamoto","G. Sato","M. Stamatikos","T. Ukwatta"],"institutions":["NASA/GSFC (Goddard Space Flight Center)","ORAU (Oak Ridge Associated Universities)"],"universities":["University of Maryland, Baltimore County (UMBC)","University of Maryland, College Park (UMD)","George Washington University (GWU)","Los Alamos National Laboratory (LANL)","ISAS (Institute of Space and Astronautical Science)"]},"telescopes":{"facilities":[],"instruments":[],"observatories":[],"telescopes":[]},"urls":["http://gcn.gsfc.nasa.gov"],"basic_data":{"author":{"email":"scott@lheamail.gsfc.nasa.gov","institution":"NASA/GSFC","name":"Scott Barthelmy"},"coordinates":{},"detectionTime":"2007-09-17T14:34:18.000Z","event":"GRB 070917","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6792\nSUBJECT: GRB 070917, Swift-BAT refined analysis\nDATE: 07/09/17 14:34:18 GMT\nFROM: Scott Barthelmy at NASA/GSFC  <scott@lheamail.gsfc.nasa.gov>\n\nJ. Tueller (GSFC), L. Barbier (GSFC), S. D. Barthelmy (GSFC),\nJ. Cummings (GSFC/UMBC), E. Fenimore (LANL), N. Gehrels (GSFC),\nH. Krimm (GSFC/USRA), C. Markwardt (GSFC/UMD), D. Palmer (LANL),\nT. Sakamoto (GSFC/ORAU), G. Sato (GSFC/ISAS), M. Stamatikos (GSFC/ORAU),\nT. Ukwatta (GWU)\n(i.e. the Swift-BAT team):\n \nUsing the data set from T-120 to T+129 sec from the recent telemetry downlink,\nwe report further analysis of BAT GRB 070917 (trigger #291292)\n(Cummings, et al., GCN Circ. 6791).  The BAT ground-calculated position is\nRA, Dec = 293.923, 2.420 deg which is \n   RA(J2000)  = 19h 35m 41.5s \n   Dec(J2000) = 02d 25'' 12\" \nwith an uncertainty of 1.0 arcmin, (radius, sys+stat, 90% containment).\nThe partial coding was 79%.\n \nThe mask-weighted lightcurve starts at ~T-5 sec, has a sharp rise from\nT-0.1 sec to ~T+0.3 sec, peaks at ~T+0.4 sec, and then approximately\nexponentially decays to background at ~T+30 sec.\nT90 (15-350 keV) is 7.3 +- 0.2 sec (estimated error including systematics).\n \nThe time-averaged spectrum from T-0.1 to T+11.4 sec is best fit by a simple\npower-law model.  The power law index of the time-averaged spectrum is\n1.52 +- 0.05.  The fluence in the 15-150 keV band is 2.0 +- 0.1 x 10^-6 erg/cm2.\nThe 1-sec peak photon flux measured from T+0.21 sec in the 15-150 keV band\nis 8.5 +- 0.3 ph/cm2/sec.  All the quoted errors are at the 90% confidence\nlevel."}', 'Swift-BAT team reports refined analysis of GRB 070917 (trigger #291292), identifying a position, duration, and spectral properties. The gamma-ray burst, which occurred on 07/09/17, has a duration of 7.3 ± 0.2 seconds, a peak photon flux of 8.5 ± 0.3 ph/cm2/sec, and a time-averaged power-law index of 1.52 ± 0.05. The position is RA(J2000) = 19h 35m 41.5s, Dec(J2000) = 02d 25'' 12'''' with an uncertainty of 1.0 arcmin.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6791', 'gcn', 'GRB 070917', '2007-09-17T07:48:46.000Z', '{"measurements":{"dec":2.4131,"distance":null,"duration":5,"energy":null,"fluence":null,"magnitude":null,"other_measurements":{"energy_range":"15-350 keV","peak_count_rate":22000,"time_of_peak_count_rate":0},"ra":19.895,"redshift":null,"tables":[]},"authors":{"affiliations":["NASA/UMBC","U Leicester","U Leicester","NASA/GSFC","CRESST/GSFC/UMD","U Leicester","U Leicester","LANL","NASA/ORAU","NASA/ORAU"],"authors":["J. R. Cummings","A. P. Beardmore","P. A. Evans","N. Gehrels","C. B. Markwardt","P. T. O''Brien","K. L. Page","D. M. Palmer","T. Sakamoto","M. Stamatikos"],"institutions":["NASA/GSFC","CRESST/GSFC"],"universities":["U Leicester","NASA/UMBC","UMD","NASA/ORAU","LANL"]},"telescopes":{"facilities":[],"instruments":[],"observatories":[],"telescopes":["Swift Burst Alert Telescope (BAT)"]},"urls":["http://www.swift.psu.edu/too.html"],"basic_data":{"author":{"email":"jayc@milkyway.gsfc.nasa.gov","institution":"NASA/GSFC/Swift","name":"Jay R. Cummings"},"coordinates":{"dec":2.1510902777777776},"detectionTime":"2007-09-17T07:48:46.000Z","event":"GRB 070917","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6791\nSUBJECT: GRB 070917: Swift detection of a bright burst\nDATE: 07/09/17 07:48:46 GMT\nFROM: Jay R. Cummings at NASA/GSFC/Swift  <jayc@milkyway.gsfc.nasa.gov>\n\nJ. R. Cummings (NASA/UMBC), A. P. Beardmore (U Leicester),\nP. A. Evans (U Leicester), N. Gehrels (NASA/GSFC),\nC. B. Markwardt (CRESST/GSFC/UMD), P. T. O''Brien (U Leicester),\nK. L. Page (U Leicester), D. M. Palmer (LANL),\nT. Sakamoto (NASA/ORAU) and M. Stamatikos (NASA/ORAU) report on\nbehalf of the Swift Team:\n\nAt 07:33:56 UT, the Swift Burst Alert Telescope (BAT) triggered and\nlocated GRB 070917 (trigger=291292). \nThe BAT on-board calculated location is RA, Dec 293.925, +2.413 which is \n   RA(J2000) = 19h 35m 42s\n   Dec(J2000) = +02d 24'' 47\"\nwith an uncertainty of 3 arcmin (radius, 90% containment, including \nsystematic uncertainty).  The BAT light curve showed a FRED\nstructure with a duration of about 5 sec.  The peak count rate\nwas ~22000 counts/sec (15-350 keV), at ~0 sec after the trigger. \n\nBecause Swift is in the process of returning to normal operations, \nautomatic slewing to GRBs is currently disabled.  Therefore, there \nare no prompt XRT or UVOT observations of this burst. \n\nBurst Advocate for this burst is J. R. Cummings (jayc AT milkyway.gsfc.nasa.gov). \nPlease contact the BA by email if you require additional information\nregarding Swift followup of this burst. In extremely urgent cases, after\ntrying the Burst Advocate, you can contact the Swift PI by phone (see\nSwift TOO web site for information: http://www.swift.psu.edu/too.html.)"}', 'The Swift Burst Alert Telescope (BAT) detected a bright gamma-ray burst (GRB 070917) at 07:33:56 UT with a peak count rate of ~22000 counts/sec and a duration of about 5 seconds. The burst occurred at RA(J2000) = 19h 35m 42s, Dec(J2000) = +02d 24'' 47', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6790', 'gcn', 'GRB 070911', '2007-09-15T05:02:46.000Z', '{"measurements":{"dec":null,"distance":null,"duration":182,"energy":{"lower_bound":50,"upper_bound":5000},"fluence":0.000014,"magnitude":null,"other_measurements":{"energy_range_peak_flux":"100 - 2000 keV","fluence_energy_range":"100 - 2000 keV","peak_flux":1.1,"photon_index":1.9},"ra":null,"redshift":null,"tables":[]},"authors":{"affiliations":[],"authors":[],"institutions":[],"universities":[]},"telescopes":{"facilities":[],"instruments":[],"observatories":[],"telescopes":[]},"urls":[],"basic_data":{"author":{"email":"yujin@phys.aoyama.ac.jp","institution":"Aoyama Gakuin U","name":"Yujin E. Nakagawa"},"coordinates":{},"detectionTime":"2007-09-15T05:02:46.000Z","event":"GRB 070911","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6790\nSUBJECT: GRB 070911: Suzaku WAM observation of the prompt emission\nDATE: 07/09/15 05:02:46 GMT\nFROM: Yujin E. Nakagawa at Aoyama Gakuin U  <yujin@phys.aoyama.ac.jp>\n\nY. E. Nakagawa, K. Yamaoka, S. Sugita (Aoyama Gakuin U.), Y. Terada,\nT. Tamagawa (RIKEN), M. Ohno, T. Uehara, T. Takahashi, Y. Fukazawa,\nC. Kira (Hiroshima U.),  M. Tashiro, Y. Urata, A. Endo, K. Onda,\nM. Suzuki, N. Kodaka, K. Morigami (Saitama U.), T. Enoto, R. Miyawaki,\nK. Nakawaza, K. Makishima (Univ. of Tokyo), E. Sonoda, M.Yamauchi,\nS. Maeno, H. Tanaka, R. Hara (Univ. of Miyazaki), M. Kokubun, M. Suzuki,\nT. Takahashi (ISAS/JAXA), S. Hong (Nihon U.),\non behalf of the Suzaku WAM team, report:\n\nThe long GRB 070911 (Swift/BAT trigger #290624 ; Krimm et al., GCN 6777;\nPalmer et al., GCN 6778) triggered the Suzaku Wide-band  All-sky Monitor (WAM)\nwhich covers an energy range of 50 keV - 5 MeV at 2007-09-11 05:58:20 UT (=T0).\n\nThe observed light curve shows a multi-peaked structure lasting from T0-160s\nto T0+120s, with a duration (T90) of about 182 seconds. The fluence in\n100 - 2000 keV was 1.4 (+0.3, -0.3) * 10^-5 erg/cm^2. The 1-s peak flux\nmeasured from T0+0s was 1.1 (+0.3, -0.2) photons/cm^2/s in the same energy\nrange.\n\nPreliminary result shows that the time-averaged spectrum from T0-160s to \nT0+120s is well fitted by a single power-law with a photon index of\n1.9 (+0.3, -0.4) (chi^2/d.o.f = 8.7/16).\n\nAll the quoted errors are at statistical 90% confidence level,\nin which the systematic uncertainties are not included.\n\nThe light curves for this burst are available at:\n\nhttp://www.astro.isas.jaxa.jp/suzaku/HXD-WAM/WAM-GRB/grb/trig/grb_table.html"}', 'The long gamma-ray burst GRB 070911, detected by Swift/BAT, triggered the Suzaku WAM monitor, which observed a multi-peaked emission lasting 182 seconds with a fluence of 1.4e-5 erg/cm^2 in the 100-2000 keV energy range. The time-averaged spectrum was found to be well-fit by a single power-law with a photon index of 1.9.', 0.9, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-679', 'gcn', 'GRB000519', '2000-05-30T13:25:21.000Z', '{"measurements":{"dec":null,"distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":{"R":[20.8,21]},"other_measurements":{"error_box_area":"100 sq. arcmin"},"ra":null,"redshift":null,"tables":[{"Date":"2000 May 20.17 UT (t+20h)","FWHM":"1.5\"","Filter/Exp":"R: 180-360 s","Telescope":"NOT"},{"Date":"2000 May 20.39 UT (t+25h)","FWHM":"1.7\"","Filter/Exp":"R: 4x240 s","Telescope":"DK-1.54m"},{"Date":"2000 May 25.37 UT (t+6d)","FWHM":"3.5\"","Filter/Exp":"R: 3x300 s","Telescope":"DK-1.54m"}]},"authors":{"affiliations":["U. of Copenhagen","DSRI, Copenhagen","U. of Aarhus"],"authors":["B. L. Jensen","H. Pedersen","J. Hjorth","J. Gorosabel","T. H. Dall","J. P. U. Fynbo","S. O''Toole"],"institutions":["DSRI, Copenhagen"],"universities":["University of Copenhagen","University of Aarhus"]},"telescopes":{"facilities":[],"instruments":["ALFOSC","DFOSC"],"observatories":["La Palma","La Silla"],"telescopes":["2.56-m Nordic Optical Telescope (NOT)","1.54-m Danish Telescope (DK-1.54m)"]},"urls":["https://gcn.gsfc.nasa.gov/gcn3/gcn3_circulars.html?id=672","https://gcn.gsfc.nasa.gov/gcn3/gcn3_circulars.html?id=673"],"basic_data":{"author":{"email":"brian_j@astro.ku.dk","institution":"U.of Copenhagen","name":"Brian Lindgren Jensen"},"coordinates":{},"detectionTime":"2000-05-30T13:25:21.000Z","event":"GRB000519","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 679\nSUBJECT: GRB000519: Optical observations\nDATE: 00/05/30 13:25:21 GMT\nFROM: Brian Lindgren Jensen at U.of Copenhagen  <brian_j@astro.ku.dk>\n\nB. L. Jensen, H. Pedersen, J. Hjorth (U. of Copenhagen),\nJ. Gorosabel (DSRI, Copenhagen),\nT. H. Dall, J. P. U. Fynbo (U. of Aarhus) and\nS. O''Toole (U. of Sydney), report on \nbehalf of a larger European collaboration:\n\n\"We have obtained images covering about 95% of the 100\nsq. arcmin error  box reported by Hurley et al. (GCN #672)\nwith the 2.56-m Nordic Optical Telescope (+ALFOSC, mosaic\nof 5 pointings) on La Palma, and the 1.54-m Danish\nTelescope (+DFOSC) at La Silla, as follows:\n\nTelescope   Date                       Filter/Exp     FWHM\n\nNOT\t    2000 May 20.17 UT (t+20h)  R: 180-360 s   1.5\"\nDK-1.54m    2000 May 20.39 UT (t+25h)  R: 4x240 s     1.7\"\nDK-1.54m    2000 May 25.37 UT (t+6d)   R: 3x300 s     3.5\"\n\nObservations were hampered by moonlight. Using the photometry \nprovided by Henden (GCN #673), we obtain limiting magnitudes \nof R~20.8 for the NOT, and R~21.0 for the DK-1.5m May 20\nimage. \n\nThe exposures have been compared internally, and with the \nDSS-II (red) exposure. No candidate counterpart was found.\""}', 'A team of astronomers led by the University of Copenhagen reported optical observations of the gamma-ray burst GRB000519 using the Nordic Optical Telescope and the Danish Telescope. No counterpart was detected in the images obtained, with limiting magnitudes of R~20.8 for NOT and R~21.0 for DK-1.5m May 20 image. The team compared their observations with previous data and the DSS-II (red) exposure.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6789', 'gcn', 'GRB 070913', '2007-09-14T15:05:49.000Z', '{"measurements":[{"Count Rate":"(1.4+/-0.5)e-3 count/s","Dec(J2000)":"-24d 17'' 34.9\"","RA(J2000)":"15h 15m 01.7s","Uncertainty":"6.5 arcsec"},{"Count Rate":"(1.3+/-0.5)e-3 count/s","Dec(J2000)":"-24d 12'' 37.9\"","RA(J2000)":"15h 14m 49.2s","Uncertainty":"6.6 arcsec"}],"authors":{"affiliations":["U. Leicester","CRESST/GSFC/UMD"],"authors":["A.P. Beardmore","K.L. Page","C. B. Markwardt"],"institutions":["U. Leicester","CRESST/GSFC/UMD"],"universities":["University of Leicester"]},"telescopes":{"facilities":[],"instruments":[],"observatories":[],"telescopes":[]},"urls":["https://gcn.gsfc.nasa.gov"],"basic_data":{"author":{"email":"apb@star.le.ac.uk","institution":"U Leicester","name":"Andy Beardmore"},"coordinates":{},"detectionTime":"2007-09-14T15:05:49.000Z","event":"GRB 070913","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6789\nSUBJECT: GRB 070913: Swift-XRT detection of the possible X-ray afterglow\nDATE: 07/09/14 15:05:49 GMT\nFROM: Andy Beardmore at U Leicester  <apb@star.le.ac.uk>\n\nA.P. Beardmore, K.L. Page (U. Leicester) and C. B. Markwardt \n(CRESST/GSFC/UMD) report on behalf of the Swift-XRT team.\n\nThe Swift-XRT began observing the field of the BAT GRB 070913 (trigger\n#290843) at 2007-09-13T21:30, 75.2 ks after the BAT trigger (Markwardt\net al., GCN 6782). In 8 orbits of photon counting mode data totalling\n7.8 ks we find a faint, uncatalogued source inside the refined\nBAT error circle (Sato et al., GCN 6786) at RA, Dec (J2000)\n228.75715, -24.29302, which is\n\nRA(J2000)  =  15h 15m 01.7s\nDec(J2000) = -24d 17'' 34.9\"\n\nwith an uncertainty of 6.5 arcsec (radius, 90 percent confidence,\nincluding boresight uncertainties). The source is 5.7 arcsec away\nfrom the TAROT optical afterglow candidate reported by Klotz et al.\n(GCN 6787). The source has an observed 0.3-10.0 keV count rate of \n(1.4+/-0.5)e-3 count/s.\n\nWe note the presence of a second faint X-ray source with a count rate of \n(1.3+/-0.5)e-3 count/s at RA, Dec (J2000) 228.70481, -24.21053, i.e.\n\nRA(J2000)  =  15h 14m 49.2s\nDec(J2000) = -24d 12'' 37.9\"\n\nwith an uncertainty of 6.6 arcsec (radius, 90 percent confidence,\nincluding boresight uncertainties). This is 4.4 arcmin from the\nrefined BAT position, and outside its 1.7 arcmin error radius.\n\nIt is impossible to say whether either of the sources are fading at\nthis stage, though the association of the first one with the fading \noptical object makes it the most likely candidate for the GRB X-ray \nafterglow.\n\nThis circular is an official product of the Swift-XRT team."}', 'The Swift-XRT team reports the detection of a possible X-ray afterglow for GRB 070913, located at RA(J2000) = 15h 15m 01.7s, Dec(J2000) = -24d 17'' 34.9', 0.8, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6788', 'gcn', 'GRB 070809', '2007-09-13T21:00:38.000Z', '{"measurements":{"dec":null,"distance":null,"duration":"1.3 +- 0.1 sec","energy":null,"fluence":null,"magnitude":null,"other_measurements":{"fluence_hardness_ratio":"1.24 +- 0.27","spectral_lag":"+11 ms +38-61 ms"},"ra":null,"redshift":null,"tables":[]},"authors":{"affiliations":["NASA Goddard Space Flight Center (GSFC)","SLAC"],"authors":["S.D. Barthelmy","T. Sakamoto","J. Norris","N. Gehrels"],"institutions":["NASA Goddard Space Flight Center (GSFC)","SLAC"],"universities":["NASA/GSFC"]},"telescopes":{"facilities":[],"instruments":[],"observatories":[],"telescopes":[]},"urls":["arXiv:0707.4626"],"basic_data":{"author":{"email":"scott@lheamail.gsfc.nasa.gov","institution":"NASA/GSFC","name":"Scott Barthelmy"},"coordinates":{},"detectionTime":"2007-09-13T21:00:38.000Z","event":"GRB 070809","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6788\nSUBJECT: GRB 070809: The Swift evidence for the SHB nature of this burst\nDATE: 07/09/13 21:00:38 GMT\nFROM: Scott Barthelmy at NASA/GSFC  <scott@lheamail.gsfc.nasa.gov>\n\nS.D. Barthelmy (GSFC), T. Sakamoto (GSFC), J. Norris (SLAC), N. Gehrels (GSFC)\nreport:\n\nGRB 070809 (Marshall GCN 6728 and Krimm GCN 6732) is very likely\na short burst.  We base this on four results:\n\n1) The spectral lag in 25-50 to 100-350 keV bands is consistent with zero:\n+11 ms +38-61 ms for 8 ms binning.\n\n2) The T90 was 1.3 +- 0.1 sec which is in the ''short'' range\nof BAT burst durations (see figure 9 of the BAT1 catalog paper; Sakamoto et al.,\naccepted in ApJS, arXiv:0707.4626)\n\n3) The fluence hardness ratio S(50-100 keV)/S(25-50 keV) is \n1.24 +- 0.27 (90% error), which is consistent with the BAT short GRB\npopulation (see figure 10 of the BAT1 catalog paper; Sakamoto et al., \naccepted in ApJS, arXiv:0707.4626).   \n\n4) The XRT light curve showed a flat phase often seen with long bursts. \nHowever, some short bursts also have such a phase (GRB 050724 and 051221A)."}', 'GRB 070809, detected by Swift, is a short gamma-ray burst with a duration of 1.3 ± 0.1 sec. The spectral lag and fluence hardness ratio are consistent with other short bursts, supporting its classification.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6787', 'gcn', 'GRB 070913', '2007-09-13T20:07:45.000Z', '{"measurements":{"dec":"-24d 17'' 35\"","distance":null,"duration":{"t0+124s to t0+154s":30,"t0+288s to t0+378s":90,"t0+87s to t0+117s":30},"energy":null,"fluence":null,"magnitude":{"t0+124s":18,"t0+288s":"> 18","t0+87s":17.5},"other_measurements":{},"ra":"15h 15m 01.3s","redshift":null,"tables":[]},"authors":{"affiliations":["CESR-OMP"],"authors":["Alain.Klotz"],"institutions":["CESR-OMP","OHP","LATT-OMP"],"universities":["CESR-CNRS"]},"telescopes":{"facilities":[],"instruments":[],"observatories":["La Silla observatory"],"telescopes":["TAROT"]},"urls":["http://www.cesr.fr/~klotz/grb070913"],"basic_data":{"author":{"email":"Alain.Klotz@free.fr","institution":"CESR-CNRS","name":"Alain Klotz"},"coordinates":{},"detectionTime":"2007-09-13T20:07:45.000Z","event":"GRB 070913","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6787\nSUBJECT: GRB 070913: Afterglow candidate detected by TAROT La Silla observatory\nDATE: 07/09/13 20:07:45 GMT\nFROM: Alain Klotz at CESR-CNRS  <Alain.Klotz@free.fr>\n\nKlotz, A. (CESR-OMP), Boer M. (OHP), Atteia J.L. (LATT-OMP) report:\n\nWe analyzed our set of unfiltered images described\nin GCNC 6783 taking account for the new position provided\nby Sato et al. (GCNC 6786). On the two first images,\nwe find a fading optical transcient candidate for the\nGRB 070913 afterglow at 1.29 arcmin from the BAT position\n(which is within the 1.7 arcmin radius of BAT).\n\nTAROT afterglow candidate position:\n\nRA(J2000) = 15h 15m 01.3s\nDec(J2000) = -24d 17'' 35\"\n\nwith an uncertainty of 1 arcsec radius.\n\nt0+87s  to t0+117s : R ~ 17.5\nt0+124s to t0+154s : R ~ 18\nt0+288s to t0+378s : R > 18\n\nMagnitudes were estimated with the nearby USNO-B1 stars\nand are not corrected for galactic dust extinction.\n\nScreen copies are available at URL:\nhttp://www.cesr.fr/~klotz/grb070913\n\nThis message may be cited."}', 'The TAROT La Silla observatory has detected a fading optical transient, potentially the afterglow of GRB 070913, located 1.29 arcmin from the BAT position with an uncertainty of 1 arcsec. The candidate''s magnitudes were estimated to be around 17.5 at 87 seconds and 18 at 124 seconds post-burst, while it was too faint to detect beyond 288 seconds. The coordinates and magnitudes are provided.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6786', 'gcn', 'GRB 070913', '2007-09-13T15:08:58.000Z', '{"measurements":{"dec":-24.278,"distance":null,"duration":3.2,"energy":null,"fluence":2.5e-7,"magnitude":null,"other_measurements":{"fluence_band":"15-150 keV","fluence_error":3e-8,"partial_coding":51,"peak_photon_flux":1.4,"peak_photon_flux_band":"15-150 keV","peak_photon_flux_error":0.2,"power_law_index":1.61,"t90_duration":3.2,"t90_duration_error":0.3,"time_averaged_spectrum_end":"+1.2 sec","time_averaged_spectrum_start":"-2.4 sec"},"ra":228.737,"redshift":null,"tables":[]},"authors":{"affiliations":["GSFC/ISAS","GSFC","GSFC","GSFC/UMBC","LANL","GSFC","GSFC/USRA","GSFC/UMD","LANL","GSFC","GSFC/ORAU","GSFC","GSFC"],"authors":["G. Sato","L. Barbier","S. D. Barthelmy","J. Cummings","E. Fenimore","N. Gehrels","H. Krimm","C. Markwardt","D. Palmer","A. Parsons","T. Sakamoto","M. Stamatikos","J. Tueller","T. Ukwatta"],"institutions":["NASA-GSFC","ISAS","GSFC/ISAS","GSFC","GSFC/UMBC","GSFC/UMD","GSFC/ORAU","LANL","GWU"],"universities":["GSFC","UMBC","UMD","ORAU","LANL","GWU"]},"telescopes":{"facilities":[],"instruments":[],"observatories":[],"telescopes":[]},"urls":["http://gcn.gsfc.nasa.gov"],"basic_data":{"author":{"email":"krimm@milkyway.gsfc.nasa.gov","institution":"NASA-GSFC","name":"Hans Krimm"},"coordinates":{},"detectionTime":"2007-09-13T15:08:58.000Z","event":"GRB 070913","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6786\nSUBJECT: GRB 070913:  Swift-BAT refined analysis\nDATE: 07/09/13 15:08:58 GMT\nFROM: Hans Krimm at NASA-GSFC  <krimm@milkyway.gsfc.nasa.gov>\n\nG. Sato (GSFC/ISAS), L. Barbier (GSFC), S. D. Barthelmy (GSFC),\nJ. Cummings (GSFC/UMBC), E. Fenimore (LANL), N. Gehrels (GSFC),\nH. Krimm (GSFC/USRA), C. Markwardt (GSFC/UMD), D. Palmer (LANL),\nA. Parsons (GSFC), T. Sakamoto (GSFC/ORAU), M. Stamatikos (GSFC/ORAU),\nJ. Tueller (GSFC), T. Ukwatta (GWU) (i.e. the Swift-BAT team):\n\nUsing the data set from T-239 to T+523 sec from the recent telemetry downlink,\nwe report further analysis of BAT GRB 070913 (trigger #290843)\n(Markwardt, et al., GCN Circ. 6782, 6785).  The BAT ground-calculated \nposition is\nRA, Dec = 228.737 -24.278 deg which is\n    RA(J2000) = 15h 14m 57s\n    Dec(J2000) = -24d 16'' 42\"\nwith an uncertainty of 1.7 arcmin, (radius, sys+stat, 90% containment).\nThe partial coding was 51%.\n\nThe mask-weighted light curve shows a single peak of about 4 seconds duration.\nT90 (15-350 keV) is 3.2 +- 0.3 sec (estimated error including systematics).\n\nThe time-averaged spectrum from T-2.4 to T+1.2 sec is best fit by a simple\npower-law model.  The power law index of the time-averaged spectrum is\n1.61 +- 0.19.  The fluence in the 15-150 keV band is 2.5 +- 0.3 x \n10^-07 erg/cm2.\nThe 1-sec peak photon flux measured from T-0.34 sec in the 15-150 keV band\nis 1.4 +- 0.2 ph/cm2/sec.  All the quoted errors are at the 90% confidence\nlevel."}', 'The Swift-BAT team has refined their analysis of GRB 070913 (trigger #290843), reporting a position with an uncertainty of 1.7 arcmin, a single peak duration of 4 seconds, a time-averaged power-law index of 1.61 +- 0.19, and a fluence of 2.5e-07 erg/cm2 in the 15-150 keV band.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6785', 'gcn', 'GRB 070913', '2007-09-13T02:33:41.000Z', '{"measurements":{"dec":-24.29,"distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":null,"other_measurements":{"shift_from_previous_position":6.2,"shift_unit":"arcmin","uncertainty_radius":3,"uncertainty_unit":"arcmin"},"ra":228.734,"redshift":null,"tables":[]},"authors":{"affiliations":["CRESST","NASA/GSFC"],"authors":["C. B. Markwardt","S. D. Barthelmy"],"institutions":["NASA/GSFC","UMD"],"universities":["NASA/GSFC"]},"telescopes":{"facilities":[],"instruments":["Swift BAT"],"observatories":[],"telescopes":[]},"urls":["http://milkyway.gsfc.nasa.gov"],"basic_data":{"author":{"email":"craigm@milkyway.gsfc.nasa.gov","institution":"NASA/GSFC/UMD","name":"Craig Markwardt"},"coordinates":{"dec":2.0357594444444445},"detectionTime":"2007-09-13T02:33:41.000Z","event":"GRB 070913","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6785\nSUBJECT: GRB 070913: Corrected BAT position\nDATE: 07/09/13 02:33:41 GMT\nFROM: Craig Markwardt at NASA/GSFC/UMD  <craigm@milkyway.gsfc.nasa.gov>\n\nC. B. Markwardt (CRESST & NASA/GSFC), S. D. Barthelmy (NASA/GSFC),\non behalf of the Swift BAT Team, report:\n\nAs noted in GCN #6781, currently Swift is calibrating\nits new gyroscope configuration for the roll axis.\n\nIn GCN Circ #6782, we quoted an error circle radius of 3 arcminutes\nfor the BAT position for GRB 070913.  This radius was incorrect.  The\ncorrect value was distributed in the Notice (radius ~9.97 arcmin).\nWe apologize for this error and any inconvenience this may have caused.\n\nIn ground analysis, we have now applied the roll axis correction, and\nthe new best position is, RA, Dec 228.734, -24.290, which is:\n   RA(J2000)  =  15h 14m 56s\n   Dec(J2000) = -24d 17'' 23\"\nwith an uncertainty of 3 arcmin radius, 90% containment, including\nsystematic uncertainty).  This is a shift of 6.2 arcmin from the\nposition quoted in GCN Circ #6782."}', 'An error was identified in the position measurement of GRB 070913 reported in previous GCN circulars. The correct position, with a uncertainty of 3 arcmin, is RA: 15h 14m 56s, Dec: -24d 17'' 23', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6784', 'gcn', 'GRB 070913', '2007-09-13T02:08:48.000Z', '{"measurements":{"dec":null,"distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":{"I":18.2,"J":15.8},"other_measurements":{"field_of_view_IR":"3 square arcminutes","field_of_view_optical":"6''x6''","mid-exposure_time":"2007-09-13 01:11 UT","post-burst_duration":"34 minutes","total_summed_exposure_times_BRIYJK":"180s","total_summed_exposure_times_HV":"120s"},"ra":null,"redshift":null,"tables":[]},"authors":{"affiliations":["Yale U"],"authors":["B. E. Cobb"],"institutions":["SMARTS consortium"],"universities":["Yale"]},"telescopes":{"facilities":[],"instruments":["ANDICAM"],"observatories":["CTIO"],"telescopes":["1.3m telescope at CTIO"]},"urls":["https://gcn.gsfc.nasa.gov/gcn3/gcn3_circulars.cfm?id=6785","https://gcn.gsfc.nasa.gov/gcn3/gcn3_circulars.cfm?id=6782"],"basic_data":{"author":{"email":"cobb@astro.yale.edu","institution":"Yale U","name":"Bethany Cobb"},"coordinates":{},"detectionTime":"2007-09-13T02:08:48.000Z","event":"GRB 070913","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6784\nSUBJECT: GRB 070913: SMARTS optical/IR observations\nDATE: 07/09/13 02:08:48 GMT\nFROM: Bethany Cobb at Yale U  <cobb@astro.yale.edu>\n\nB. E. Cobb (Yale), part of the larger SMARTS consortium, reports:\n\nUsing the ANDICAM instrument on the 1.3m telescope at CTIO, we\nobtained optical/IR imaging of the error region of GRB 070913\n(Markwardt et al. GCN 6782) with a mid-exposure time of\n(2007-09-13 01:11 UT, ~34 minutes post-burst). Optical imaging in B,V,R\nand I has a field of view of 6''x6'' and, therefore, covers the entire GRB\nerror circle.  IR imaging in J, H, K and Y has a smaller field\nof view and covers a region totalling 3 square arcminutes in\nthe middle of the quoted error region.  Several dithered images\nwere obtained in each filter, with total summed exposure times\nof 180s in each of BRIYJK and 120s in each of H and V.\n\nPreliminary visual comparison of the optical images to the DSS\nand the IR images to 2MASS frames does not reveal any new sources\nto a limiting magnitude of I>18.2 and J>15.8 (calibrated using USNO-B1.0 \nand 2MASS stars).\n\n[GCN OPS NOTE (13sep07): Per author''s request, the following statement was added:\n\"Due to the recalculated BAT position position (#6785), the SMARTS observations\nactually do not cover any of the GRB error region for this burst.\"]"}', 'The SMARTS consortium, led by B. E. Cobb at Yale University, conducted optical and IR observations of GRB 070913 using the ANDICAM instrument on the 1.3m telescope at CTIO. The observations, obtained approximately 34 minutes post-burst, did not reveal any new sources within the error region to a limiting magnitude of I>18.2 and J>15.8.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6783', 'gcn', 'GRB 070913', '2007-09-13T01:23:01.000Z', '{"measurements":{"dec":null,"distance":null,"duration":{"exposure_duration":30,"observation_end":576.5,"observation_notice_delay":69.4,"observation_start":87.3},"energy":null,"fluence":null,"magnitude":{"t0+123.6s to t0+576.5s":18.4,"t0+87.3s to t0+117.3s":17.8},"other_measurements":{"galactic_extinction_R_band":0.4},"ra":null,"redshift":null,"tables":[]},"authors":{"affiliations":["CESR-OMP","OHP","LATT-OMP"],"authors":["Alain.Klotz@free.fr","Klotz, A.","Boer, M.","Atteia, J.L."],"institutions":["CESR-CNRS","OHP","LATT-OMP"],"universities":["CNRS","OMP"]},"telescopes":{"facilities":[],"instruments":[],"observatories":["European Southern Observatory","La Silla observatory"],"telescopes":["TAROT"]},"urls":["http://gcn.gsfc.nasa.gov"],"basic_data":{"author":{"email":"Alain.Klotz@free.fr","institution":"CESR-CNRS","name":"Alain Klotz"},"coordinates":{},"detectionTime":"2007-09-13T01:23:01.000Z","event":"GRB 070913","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6783\nSUBJECT: GRB 070913: TAROT La Silla observatory optical observations\nDATE: 07/09/13 01:23:01 GMT\nFROM: Alain Klotz at CESR-CNRS  <Alain.Klotz@free.fr>\n\nKlotz, A. (CESR-OMP), Boer M. (OHP), Atteia J.L. (LATT-OMP) report:\n\nWe imaged the field of GRB 070913 detected by SWIFT\n(trigger 290843) with the TAROT robotic telescope (D=25cm)\nlocated at the European Southern Observatory,\nLa Silla observatory, Chile.\n\nThe observations started 87.3s after the GRB trigger\n(69.4s after the notice). The elevation of the field decreased from\nfrom 35 degrees above horizon and weather conditions\nwere good.\n\nThe date of trigger : t0 = 2007-09-13T00:36:44.064\n\nThe first image is 30.0s exposure in tracking mode.\nWe do not detect any OT with a limiting magnitude of:\nt0+87.3s to t0+117.3s : R > 17.8\n\nWe co-added a series of exposures:\nt0+123.6s to t0+576.5s : R > 18.4\n\nFurther observations are in progress.\n\nMagnitudes were estimated with the nearby USNO-B1 stars\nand are not corrected for galactic dust extinction.\n\nN.B. Galactic coordinates are lon=340.2109 lat=+27.9232\nand the galactic extinction in R band is 0.4 magnitudes\nestimated from D. Schlegel et al. 1998ApJ...500..525S.\n\nThis message may be cited."}', 'The TAROT team at the European Southern Observatory in Chile observed the field of GRB 070913 using the TAROT robotic telescope 87.3 seconds after the Swift trigger. No optical transient was detected in the first 30 seconds, but co-added exposures from 123.6 to 576.5 seconds post-trigger revealed a faint object with a magnitude of 18.4 in the R band. Further observations are ongoing.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6782', 'gcn', 'GRB 070913', '2007-09-13T00:46:08.000Z', '{"measurements":{"dec":-24.341666666666665,"distance":null,"duration":5,"energy":null,"fluence":null,"magnitude":null,"other_measurements":{"energy_range":"15-350 keV","peak_count_rate":1000},"ra":15.255555555555555,"redshift":null,"tables":[]},"authors":{"affiliations":["CRESST/GSFC/UMD","GSFC","PSU","LANL","NASA/ORAU","U Leicester","NASA/GSFC","GSFC/GWU"],"authors":["C. B. Markwardt","S. D. Barthelmy","J. A. Kennea","H. A. Krimm","K. L. Page","D. M. Palmer","M. Stamatikos","T. N. Ukwatta"],"institutions":["CRESST/GSFC/UMD","GSFC","PSU","LANL","NASA/ORAU"],"universities":["UMD","GSFC","PSU","LANL","GWU","U Leicester"]},"telescopes":{"facilities":[],"instruments":[],"observatories":[],"telescopes":["Swift Burst Alert Telescope (BAT)"]},"urls":["http://www.swift.psu.edu/too.html"],"basic_data":{"author":{"email":"scott@lheamail.gsfc.nasa.gov","institution":"NASA/GSFC","name":"Scott Barthelmy"},"coordinates":{"dec":2.0357866666666666},"detectionTime":"2007-09-13T00:46:08.000Z","event":"GRB 070913","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6782\nSUBJECT: GRB 070913: Swift detection of a burst\nDATE: 07/09/13 00:46:08 GMT\nFROM: Scott Barthelmy at NASA/GSFC  <scott@lheamail.gsfc.nasa.gov>\n\nC. B. Markwardt (CRESST/GSFC/UMD), S. D. Barthelmy (GSFC),\nJ. A. Kennea (PSU), H. A. Krimm (GSFC/USRA),\nK. L. Page (U Leicester), D. M. Palmer (LANL),\nM. Stamatikos (NASA/ORAU) and T. N. Ukwatta (GSFC/GWU) report on\nbehalf of the Swift Team:\n\nAt 00:36:43 UT, the Swift Burst Alert Telescope (BAT) triggered and\nlocated GRB 070913 (trigger=290843). \nThe BAT on-board calculated location is RA, Dec 228.832, -24.342,\nwhich is:\n   RA(J2000)  = 15h 15m 20s\n   Dec(J2000) = -24d 20'' 30\"\nwith an uncertainty of 3 arcmin (radius, 90% containment, including \nsystematic uncertainty).  The BAT light curve shows a single peak\nwith a duration of about 5 sec.  The peak count rate\nwas ~1000 counts/sec (15-350 keV), at ~0 sec after the trigger. \n\nBecause Swift is in the process of returning to normal operations, \nautomatic slewing to GRBs is currently disabled.  Therefore, there \nare no prompt XRT or UVOT observations of this burst. \n\nBurst Advocate for this burst is C. B. Markwardt (craigm AT milkyway.gsfc.nasa.gov). \nPlease contact the BA by email if you require additional information\nregarding Swift followup of this burst. In extremely urgent cases, after\ntrying the Burst Advocate, you can contact the Swift PI by phone (see\nSwift TOO web site for information: http://www.swift.psu.edu/too.html.)"}', 'The Swift Burst Alert Telescope (BAT) detected a gamma-ray burst (GRB 070913) at 00:36:43 UT with a location of RA 15.2556°, Dec -24.3417° and a duration of about 5 seconds. The peak count rate was ~1000 counts/sec in the energy range of 15-350 keV. Swift is currently returning to normal operations, so no prompt XRT or UVOT observations were made. The Burst Advocate for this burst is C.B. Markwardt, and additional information can be obtained by contacting him or the Swift PI.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6781', 'gcn', 'Swift-BAT Notices back to autonomous real-time distribution', '2007-09-12T22:38:51.000Z', '{"measurements":{"dec":null,"distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":null,"other_measurements":{"new_position_error_radius":"4 arcmin","position_error_radius":"3 arcmin","position_error_term":"proportional to the off-axis angle"},"ra":null,"redshift":null,"tables":[]},"authors":{"affiliations":["NASA/GSFC","GSFC/UMD"],"authors":["S. Barthelmy","C. Markwardt","N. Gehrels"],"institutions":["NASA/GSFC","UMD"],"universities":["University of Maryland","NASA/GSFC"]},"telescopes":{"facilities":[],"instruments":[],"observatories":[],"telescopes":[]},"urls":["http://gcn.gsfc.nasa.gov"],"basic_data":{"author":{"email":"scott@lheamail.gsfc.nasa.gov","institution":"NASA/GSFC","name":"Scott Barthelmy"},"coordinates":{},"detectionTime":"2007-09-12T22:38:51.000Z","event":"Swift-BAT Notices back to autonomous real-time distribution","eventType":"EP","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6781\nSUBJECT: Swift-BAT Notices back to autonomous real-time distribution\nDATE: 07/09/12 22:38:51 GMT\nFROM: Scott Barthelmy at NASA/GSFC  <scott@lheamail.gsfc.nasa.gov>\n\nS. Barthelmy (GSFC), C. Markwardt (GSFC/UMD),  and N. Gehrels (GSFC) \non behalf of the Swift-BAT team:\n\nAs part of the several incremental steps of returning to normal\noperations for the Swift mission, the distribution of the BAT-based\nnotices has been re-enabled for autonomous real-time distribution.\nThis includes the BAT_Position, BAT_Lightcurve, and Swift_FOM_Observe\nnotices.  Since the automated target slewing has not yet been enabled,\nthe Swift_SC_Slew notices are still being blocked (as are the XRT and\nUVOT notices).\n\nThe position error quoted in the BAT_Position notice has been changed\nfrom the fixed value of 3 arcmin radius  to 4 arcmin plus a term\nwhich is proportional to the off-axis angle in BAT instrument coordinates.\nThis is to accomodate an increase in the systematic error due\nto an as yet uncalibrated uncertainty in the Roll axis of the\nSwift spacecraft."}', 'Swift-BAT team announced the re-enablement of real-time distribution for BAT-based notices, including position, lightcurve, and observe notices. The position error in the BAT_Position notice has been updated to account for an increase in systematic error due to an uncalibrated uncertainty in the Roll axis of the Swift spacecraft.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6780', 'gcn', 'GRB 070911', '2007-09-12T21:45:33.000Z', '{"measurements":{"dec":null,"distance":null,"duration":"2 hrs, 56 min","energy":null,"fluence":null,"magnitude":{"H":"> 16","J":"> 16.5","Ks":"> 16"},"other_measurements":{},"ra":null,"redshift":null,"tables":[]},"authors":{"affiliations":["MIT/CSR","University of California, Berkeley"],"authors":["N. Butler","D. Starr","J. S. Bloom"],"institutions":["MIT/CSR"],"universities":["Massachusetts Institute of Technology (MIT)","University of California, Berkeley (UCB)"]},"telescopes":{"facilities":[],"instruments":[],"observatories":[],"telescopes":[]},"urls":["http://gcn.gsfc.nasa.gov"],"basic_data":{"author":{"email":"nrbutler@space.mit.edu","institution":"MIT/CSR","name":"Nat Butler"},"coordinates":{},"detectionTime":"2007-09-12T21:45:33.000Z","event":"GRB 070911","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6780\nSUBJECT: GRB 070911: PAIRITEL IR Observations\nDATE: 07/09/12 21:45:33 GMT\nFROM: Nat Butler at MIT/CSR  <nrbutler@space.mit.edu>\n\nN. Butler, D. Starr, J. S. Bloom (UCB) report:\n\nIn simultaneous J, H, and Ks band observations of the GRB 070911  \nfield (Krimm et al.; GCN 6777) starting on September 11 08h53m33s UT,\n2 hrs, 56 min after the burst, we find no new sources in the XRT error  \nregion (Stratta et al.; GCN 6779).  We derive the following limiting \nmagnitudes: J > 16.5 mag, H > 16 mag, and Ks > 16 mag.\n\nThis message may be cited."}', 'No new sources were detected in IR observations of GRB 070911 using the PAIRITEL telescope 2 hours and 56 minutes after the burst. The limiting magnitudes in J, H, and Ks bands were found to be greater than 16.5, 16, and 16 mag, respectively.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-678', 'gcn', 'GRB000529', '2000-05-29T18:28:55.000Z', '{"measurements":{"dec":-26.625,"distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":null,"other_measurements":{"radius_of_annulus":{"sigma_level":"3 sigma","uncertainty":0.171,"unit":"degrees","value":47.85}},"ra":312.943,"redshift":null,"tables":[]},"authors":{"affiliations":["UCBerkeley/SSL"],"authors":["K. Hurley","T. Cline","F. Frontera","C. Guidorzi","E. Montanari","E. Mazets"],"institutions":["SSL (Space Sciences Laboratory)"],"universities":["University of California, Berkeley"]},"telescopes":{"facilities":[],"instruments":[],"observatories":["IPN"],"telescopes":["NEAR","Konus","BeppoSAX/GRBM"]},"urls":[],"basic_data":{"author":{"email":"khurley@sunspot.ssl.berkeley.edu","institution":"UCBerkeley/SSL","name":"Kevin Hurley"},"coordinates":{},"detectionTime":"2000-05-29T18:28:55.000Z","event":"GRB000529","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 678\nSUBJECT: IPN localization of GRB000529\nDATE: 00/05/29 18:28:55 GMT\nFROM: Kevin Hurley at UCBerkeley/SSL  <khurley@sunspot.ssl.berkeley.edu>\n\nK. Hurley, T. Cline, F. Frontera, C. Guidorzi, E. Montanari, and E. Mazets\nreport:\n\nNEAR, Konus, and the BeppoSAX GRBM observed this burst (GCN #676).\n(The NEAR XGRS detector has been turned back on and is operating\nnominally; Ulysses data will not be available until tomorrow due\nto the Memorial Day holiday).  Triangulation gives an annulus \ncentered at RA(2000)=312.943 deg., Decl.(2000)=-26.625 deg., with radius\n47.850 +/- 0.171 degrees (3 sigma).  This is consistent with,\nbut does not further constrain, the BeppoSAX WFC error box.  The\naddition of Ulysses data is expected to improve this localization."}', 'An annulus with a radius of 47.85 degrees and a 3 sigma uncertainty has been determined as the location of GRB000529 based on observations by NEAR, Konus, and BeppoSAX/GRBM. The addition of Ulysses data is expected to improve the localization.', 0.8, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6779', 'gcn', 'GRB 070911', '2007-09-12T17:21:52.000Z', '{"measurements":{"dec":"-33d 29'' 03.1\"","distance":null,"duration":"6.8 ks","energy":"0.3-10 keV","fluence":null,"magnitude":null,"other_measurements":{"alpha":"-1.5+/-0.2","column_density":"(1.3+/-0.5)e21 cm^-2","galactic_column_density":"2.4e20 cm^-2","observed_flux":"1.9e-12 erg cm^-2 s^-1","photon_index":"2.2 +/- 0.3","predicted_count_rate":"0.02 cts/s","predicted_flux":"1.3e-12 erg cm^-2 s^-1","unabsorbed_flux":"2.8e-12 erg cm^-2 s^-1"},"ra":"01h 43m 14.26s","redshift":null,"tables":[]},"authors":{"affiliations":["ISAC/ASDC","PSU"],"authors":["Giulia Stratta","Matteo Perri","David Burrows"],"institutions":["ISAC/ASDC","PSU"],"universities":["ASI","PSU"]},"telescopes":{"facilities":[],"instruments":["Swift-XRT"],"observatories":[],"telescopes":["Swift"]},"urls":["http://gcn.gsfc.nasa.gov"],"basic_data":{"author":{"email":"capalbi@asdc.asi.it","institution":"ISAC/ASDC","name":"Milvia Capalbi"},"coordinates":{},"detectionTime":"2007-09-12T17:21:52.000Z","event":"GRB 070911","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6779\nSUBJECT: GRB 070911: Swift XRT refined analysis\nDATE: 07/09/12 17:21:52 GMT\nFROM: Milvia Capalbi at ISAC/ASDC  <capalbi@asdc.asi.it>\n\nGiulia Stratta (ASDC), Matteo Perri (ASDC) and David\nBurrows (PSU) report, on behalf of the Swift XRT team:\n\nWe have analyzed the first 9 orbits of Swift-XRT\ndata on GRB 070911 (GCN 6777, Krimm et al.) for a\ntotal of 6.8 ks of exposure taken in Photon Counting\nmode starting 14.5 hours after the burst.\nThis is the first BAT GRB after Swift safe-hold recovery.\nSwift-XRT detected an uncatalogued, fading source\nat the following coordinates\nRA,Dec 25.8094,-33.4842 which is\n\n  RA(J2000)  = 01h 43m 14.26s\n  Dec(J2000) = -33d 29'' 03.1\"\n\nwith an estimated error radius of 6 arcseconds\n(90% confidence). This error radius has been increased\nto take into account the uncertainties in the pointing\ncalibration during Swift''s reactivation phase.\nThis position is 0.5'' from the BAT refined position\n(GCN 6778, Palmer et al.). We note however that XRT position\nuncertanties are currently being re-validated.\n\nThe 0.3-10 keV X-ray light curve from T0+14.5 h to T0+27.3 h\ncan be fit with a simple power law model.\nThe best fit decay index is alpha=-1.5+/-0.2\n\nThe 0.3-10.0 keV X-ray spectrum with 6.8 ks of integration\ntime, is well fit by an absorbed power law with a\nphoton index of 2.2 +/- 0.3 and a total column density of\nNH=(1.3+/-0.5)e21 cm**-2 (chi2/dof=0.8/6).\nThe Galactic column density in the direction of the source\nis 2.4e20 cm**-2 (Dickey & Lockmann 1990).\nThe 0.3-10 keV observed flux is 1.9e-12 erg cm**-2 s**-1\n(unabsorbed: 2.8e-12 erg cm**-2 s**-1).\nWe note that the XRT CCD is now operating with a raised\nsubstrate voltage, and thus has a different gain.\nThe new gain is not yet well calibrated, and so our spectral\nresults are only preliminary.\n\nAssuming the X-ray emission continues to decline at the same\nrate, we predict a 0.3-10 keV count rates of 0.02 cts/s 2 days\nafter the burst trigger, that corresponds to a flux of\n1.3e-12 erg cm**-2 s**-1.\n\nThis is an official product of the Swift XRT team."}', 'Swift-XRT team reports the detection of an uncatalogued, fading X-ray source at the position of GRB 070911, with coordinates RA: 01h 43m 14.26s, Dec: -33d 29'' 03.1', 0.9, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6778', 'gcn', 'GRB 070911', '2007-09-11T17:31:54.000Z', '{"measurements":{"dec":"-33.484","distance":null,"duration":"162 +- 10 sec","energy":null,"fluence":"1.2 +- 0.02 x 10^-05 erg/cm2","magnitude":null,"other_measurements":{"duration_band":"15-350 keV","duration_value":"162 +- 10 sec","fluence_band":"15-150 keV","fluence_value":"1.2 +- 0.02 x 10^-05 erg/cm2","partial_coding":"88%","peak_flux_band":"15-150 keV","peak_flux_time":"T+36.13 sec","peak_photon_flux":"3.9 +- 0.2 ph/cm2/sec","time_averaged_spectrum_index":"1.72 +- 0.04"},"ra":"25.819","redshift":null,"tables":[]},"authors":{"affiliations":["LANL","GSFC","UMBC","GSFC/UMD","GSFC/ORAU","GSFC/ISAS"],"authors":["D. Palmer","L. Barbier","S. D. Barthelmy","J. Cummings","E. Fenimore","N. Gehrels","H. Krimm","C. Markwardt","A. Parsons","T. Sakamoto","G. Sato","M. Stamatikos","J. Tueller","T. Ukwatta"],"institutions":["NASA-GSFC","LANL","GSFC/UMBC","GSFC/UMD","GSFC/ORAU","GWU"],"universities":["GSFC","UMBC","UMD","ORAU","ISAS"]},"telescopes":{"facilities":[],"instruments":[],"observatories":[],"telescopes":[]},"urls":["http://gcn.gsfc.nasa.gov"],"basic_data":{"author":{"email":"krimm@milkyway.gsfc.nasa.gov","institution":"NASA-GSFC","name":"Hans Krimm"},"coordinates":{},"detectionTime":"2007-09-11T17:31:54.000Z","event":"GRB 070911","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6778\nSUBJECT: GRB 070911, Swift-BAT refined analysis\nDATE: 07/09/11 17:31:54 GMT\nFROM: Hans Krimm at NASA-GSFC  <krimm@milkyway.gsfc.nasa.gov>\n\nD. Palmer (LANL),  L. Barbier (GSFC), S. D. Barthelmy (GSFC),\nJ. Cummings (GSFC/UMBC), E. Fenimore (LANL), N. Gehrels (GSFC),\nH. Krimm (GSFC/USRA), C. Markwardt (GSFC/UMD), A. Parsons (GSFC),\nT. Sakamoto (GSFC/ORAU), G. Sato (GSFC/ISAS), M. Stamatikos (GSFC/ORAU),\nJ. Tueller (GSFC), T. Ukwatta (GWU) (i.e. the Swift-BAT team):\n\nUsing the data set from T-299 to T+303 sec from the recent telemetry downlink,\nwe report further analysis of BAT GRB  (trigger #290624)\n(Krimm, et al., GCN Circ. 6777).  The BAT ground-calculated position is\nRA, Dec = 25.819, -33.484 deg which is\n    RA(J2000) = 1h 43m 16.5s\n    Dec(J2000) = -33d 29'' 3\"\nwith an uncertainty of 1.5 arcmin, (radius, sys+stat, 90% containment).\nThe partial coding was 88%.\n\nThe mask tagged light curve starts to rise at around T-70 sec and \ncontinues above\nbaseline until  T+160 sec.  The burst contains multiple strong peaks \nin a cluster\nfrom T-5 to T+55 sec, then a drop in flux and another cluster of peaks from\nT+85 to T+145 sec.The first cluster of peaks has a harder spectrum \nthan the second.\nT90 (15-350 keV) is 162 +- 10 sec (estimated error including systematics).\n\nThe time-averaged spectrum from -73.0 to  +158.8 sec is best fit by a simple\npower-law model.  The power law index of the time-averaged spectrum is\n1.72 +- 0.04.  The fluence in the 15-150 keV band is 1.2 +- 0.02 x \n10^-05 erg/cm2.\nThe 1-sec peak photon flux measured from T+36.13 sec in the 15-150 keV band\nis 3.9 +- 0.2 ph/cm2/sec.  All the quoted errors are at the 90% confidence\nlevel."}', 'Astronomical alert: GRB 070911, Swift-BAT refined analysis', 0.5, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6777', 'gcn', 'GRB 070911', '2007-09-11T06:20:20.000Z', '{"measurements":{"dec":"-33d 28'' 21\"","distance":null,"duration":"150 sec","energy":null,"fluence":null,"magnitude":null,"other_measurements":{"duration_seconds":"150 sec","peak_count_rate":"~8000 counts/sec (15-350 keV)","uncertainty_radius":"4 arcmin"},"ra":"01h 43m 12s","redshift":null,"tables":[]},"authors":{"affiliations":["GSFC/USRA","CRESST/GSFC/UMD","U Leicester","LANL","NASA/ORAU"],"authors":["H. A. Krimm","C. B. Markwardt","K. L. Page","D. M. Palmer","M. Stamatikos"],"institutions":["CRESST/GSFC/UMD","GSFC/USRA"],"universities":["University of Leicester","GSFC/USRA","UMD","LANL"]},"telescopes":{"facilities":[],"instruments":[],"observatories":[],"telescopes":["Swift Burst Alert Telescope (BAT)"]},"urls":["krimm@milkyway.gsfc.nasa.gov","http://www.swift.psu.edu/too.html"],"basic_data":{"author":{"email":"palmer@lanl.gov","institution":"LANL","name":"David Palmer"},"coordinates":{},"detectionTime":"2007-09-11T06:20:20.000Z","event":"GRB 070911","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6777\nSUBJECT: GRB 070911: Swift detection of a burst\nDATE: 07/09/11 06:20:20 GMT\nFROM: David Palmer at LANL  <palmer@lanl.gov>\n\nH. A. Krimm (GSFC/USRA), C. B. Markwardt (CRESST/GSFC/UMD),\nK. L. Page (U Leicester), D. M. Palmer (LANL) and\nM. Stamatikos (NASA/ORAU) report on behalf of the Swift Team:\n\nAt 05:57:44 UT, the Swift Burst Alert Telescope (BAT) triggered and\nlocated GRB 070911 (trigger=290624).  Swift automatic slews are\ncurrently disabled, as we are currently recovering from a safehold. \nThe BAT on-board calculated location is \nRA, Dec 25.799, -33.473 which is \n   RA(J2000) = 01h 43m 12s\n   Dec(J2000) = -33d 28'' 21\"\nwith an uncertainty of 4 arcmin (radius, 90% containment, including \nsystematic uncertainty, however there is an uncalibrated boresight\nshift due to operations with a different set of gyros than we have\nused previously).  The BAT light curve showed a complex multi-peaked\nstructure with a duration of about 150 sec.  The peak count rate\nwas ~8000 counts/sec (15-350 keV), at ~36 sec after the trigger. \n\nBecause we are in the process of resuming normal operations,\nthere is no automatic follow-up observation by\nthe XRT and UVOT. \n\nBurst Advocate for this burst is H. A. Krimm (krimm AT milkyway.gsfc.nasa.gov). \nPlease contact the BA by email if you require additional information\nregarding Swift followup of this burst. In extremely urgent cases, after\ntrying the Burst Advocate, you can contact the Swift PI by phone (see\nSwift TOO web site for information: http://www.swift.psu.edu/too.html.)"}', 'The Swift Burst Alert Telescope (BAT) detected a gamma-ray burst (GRB 070911) at 05:57:44 UT with a location of RA: 01h 43m 12s, Dec: -33d 28'' 21'''' and a peak count rate of ~8000 counts/sec (15-350 keV). The burst had a complex multi-peaked structure with a duration of about 150 sec. Swift''s automatic follow-up observations by XRT and UVOT were not possible due to the spacecraft being in recovery mode. The Burst Advocate for this event is H. A. Krimm and additional information can be obtained by contacting him.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6776', 'gcn', 'IPN search for a GRB associated with TAROT transient on August 31', '2007-09-10T18:03:04.000Z', '{"measurements":{"dec":null,"distance":null,"duration":null,"energy":null,"fluence":"10^-6 erg cm^-2","magnitude":null,"other_measurements":{},"ra":null,"redshift":null,"tables":[]},"authors":{"affiliations":[],"authors":[],"institutions":[],"universities":[]},"telescopes":{"facilities":[],"instruments":[],"observatories":[],"telescopes":[]},"urls":[],"basic_data":{"author":{"email":"khurley@ssl.berkeley.edu","institution":"UCBerkeley/SSL","name":"Kevin Hurley"},"coordinates":{},"detectionTime":"2007-09-10T18:03:04.000Z","event":"IPN search for a GRB associated with TAROT transient on August 31","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6776\nSUBJECT: IPN search for a GRB associated with TAROT transient on August 31\nDATE: 07/09/10 18:03:04 GMT\nFROM: Kevin Hurley at UCBerkeley/SSL  <khurley@ssl.berkeley.edu>\n\nK. Hurley and T. Cline, on behalf of the Ulysses, Mars Odyssey, MESSENGER,\nand Konus GRB teams,\n\nI.G. Mitrofanov, M.L. Litvak, A.S. Kozyrev, A.B. Sanin and V.I. Tretyakov,\non behalf of the HEND-Odyssey GRB team,\n\nW. Boynton, C. Fellows, K. Harshman, C. Shinohara and R. Starr, on\nbehalf of the GRS-Odyssey GRB team,\n\nS. Golenetskii, R.Aptekar, E. Mazets, V. Pal''shin, and D. Frederiks,\non behalf of the Konus-Wind team,\n\nD. M. Smith, R. P. Lin, J. McTiernan, R. Schwartz, C. Wigger, W.\nHajdas, and A. Zehnder, on behalf of the RHESSI GRB team, \n\nA. von Kienlin, G. Lichti, and A. Rau, on behalf of the\nINTEGRAL SPI-ACS GRB team,\n\nK.Yamaoka, M.Ohno, Y.Fukazawa, T.Takahashi, M.Tashiro, Y. Terada,\nT.Murakami, and K.Makishima on behalf of the Suzaku WAM team,\n\nS. Barthelmy, J. Cummings, N. Gehrels, and H. Krimm, on behalf of\nthe Swift-BAT team,\n\nJ. Goldsten, on behalf of the MESSENGER NS GRB team, and\n\nI. Donnarumma, L. Pacciani, F. Fuschino, and M. Marisaldi, \non behalf of the AGILE Team, \n\nreport:\n\nWe have searched the triggered and real-time data of the Odyssey (HEND\nand GRS), Konus-Wind, MESSENGER, Suzaku, Swift-BAT, RHESSI, and AGILE\n(SuperAGILE and mini-calorimeter) spacecraft for any burst (long- or\nshort-duration) which might correspond to the TAROT orphan GRB\ncandidate on August 31 (Klotz et al. GCN 6769).   The search was\nconcentrated on times up to the time of the first exposure, at 00:20:38\nUT. (INTEGRAL SPI-ACS and Ulysses were not returning data during this\nperiod.) Without knowledge of the exact burst time and profile, it is\ndifficult to completely rule out the existence of any corresponding\nevent; for example, some spacecraft were planet-blocked for varying\nportions of the search window.  However, no bursts of any kind were\nobserved; a very rough upper limit to the >25 keV fluence of a short duration\nburst is 10^-6 erg cm^-2."}', 'A group of astronomers searched various spacecraft data for a gamma-ray burst (GRB) associated with an orphan candidate detected by the TAROT transient on August 31. No burst was detected up to a very rough upper limit of 10^-6 erg cm^-2 for a short-duration burst.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6775', 'gcn', 'Intense burst from SGR 1806-20 detected on September 7', '2007-09-10T16:59:15.000Z', '{"measurements":{"dec":-7.254,"distance":null,"duration":2,"energy":null,"fluence":0.0000147,"magnitude":null,"other_measurements":{"duration_hump":100,"duration_spike":30,"peak_flux":0.0000167,"temperature":20.9,"time_first_spike":60384.6,"time_main_pulse":60387.314,"time_small_hump":60393.214},"ra":330.018,"redshift":null,"tables":[]},"authors":{"affiliations":["Ioffe Inst","Konus-Wind team","Swift-BAT team","INTEGRAL GRB team"],"authors":["S. Golenetskii","R. Aptekar","E. Mazets","V. Pal''shin","D. Frederiks","T. Cline","J. Cummings","S. Barthelmy","N. Gehrels","H. Krimm","D. Palmer","K. Hurley","A. von Kienlin","G. Lichti","A. Rau","D. Gotz","S. Mereghetti"],"institutions":["Ioffe Inst","Konus-Wind team","Swift-BAT team","INTEGRAL GRB team"],"universities":["Ioffe Inst"]},"telescopes":{"facilities":["IPN"],"instruments":["Konus-BAT","Konus-SPI-ACS"],"observatories":["Ioffe Inst"],"telescopes":["Konus-Wind","Swift-BAT","INTEGRAL"]},"urls":["http://www.ioffe.rssi.ru/LEA/SGRs/070907_T60387/"],"basic_data":{"author":{"email":"val@mail.ioffe.ru","institution":"Ioffe Inst","name":"Valentin Pal''shin"},"coordinates":{},"detectionTime":"2007-09-10T16:59:15.000Z","event":"Intense burst from SGR 1806-20 detected on September 7","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6775\nSUBJECT: Intense burst from SGR 1806-20 detected on September 7\nDATE: 07/09/10 16:59:15 GMT\nFROM: Valentin Pal''shin at Ioffe Inst  <val@mail.ioffe.ru>\n\nS. Golenetskii, R. Aptekar, E. Mazets, V. Pal''shin, D. Frederiks,\nand T. Cline on behalf of the Konus-Wind team,\n\nJ. Cummings, S. Barthelmy, N. Gehrels, H. Krimm, and D. Palmer\non behalf of the Swift-BAT team,\n\nK. Hurley, A. von Kienlin, G. Lichti, A. Rau, D. Gotz, and\nS. Mereghetti, on behalf of the INTEGRAL GRB team,\nreport:\n\nAn intense, short SGR-like event triggered Konus-Wind\nat 2007-09-07 T0=60387.314 s UT (16:46:27.314).\nIt was also detected by Swift-BAT (out FoV) and INTEGRAL-SPI-ACS.\nIt was not detected by any other IPN spacecraft.\n\nWe have triangulated this burst to the Konus-BAT annulus\ncentered at RA(2000)=330.018 (22h 00m 04s)  Dec(2000)=-7.254 (-7d 15'' \n14\"), whose radius is 57.445 +/- 0.407 deg (3 sigma)\nand to the Konus-SPI-ACS annulus\ncentered at RA(2000)=328.332 (21h 53m 20s)  Dec(2000)=-1.259 (-1d 15'' \n31\"), whose radius is 58.080 +/- 0.653 deg (3 sigma).\nThe center lines of these annuli pass 0.041 deg from the position of SGR \n1806-20 (correspondingly 0.3 and 0.2 sigma). They are inconsistent with \nthe positions of all other known SGRs. The Konus ecliptic latitude \nresponse indicates that the source of the burst is near the ecliptic \nplane. Thus we conclude that this burst originated from SGR 1806-20.\n\nThe burst light curve shows a ~30-ms long spike at T-T0 ~-0.240 s \nfollowed by the main pulse with a duration of ~2 s, and\na small hump at T-T0 ~5.9 s with a duration of ~100 ms.\nThe Earth-crossing time of the first spike was 60384.6 s UT (16:46:24.6).\n\nAs observed by Konus-Wind the burst had a fluence of\n1.47(-0.05, +0.04)x10^-5 erg/cm2, and a 16-ms peak flux\nmeasured from T0+0.016 s of (1.67 +/- 0.21)x10^-5 erg/cm2\n(both in the 20-200 keV range).\n\nThe spectrum of the burst (from T0 to T0+8.448) can be fitted\n(in the 20-200 keV range) by the OTTB spectral model:\ndN/dE ~ E^{-1} exp(-E/kT)\nwith kT = 20.9 +/- 0.9 keV (chi2 = 36/27 dof).\n\nAll the quoted errors are at 90% c.l.\n\nThe Konus-Wind light curve of this burst is available\nat http://www.ioffe.rssi.ru/LEA/SGRs/070907_T60387/\n\nThe last burst from SGR 1806-20 to trigger Konus-Wind\nwas on July 27, 2007 (Golenetskii et al., GCN 6684).\n\nAdditional smaller bursts have been detected by BAT at\n2007-09-09 22:45:36 and 2007-09-10 05:31:06 UT."}', 'An intense burst from SGR 1806-20 was detected on September 7, 2007, by the Konus-Wind, Swift-BAT, and INTEGRAL teams. The burst was triangulated to the position of SGR 1806-20 and had a fluence of 1.47x10^-5 erg/cm2 and a peak flux of 1.67x10^-5 erg/cm2 in the 20-200 keV range. The burst consisted of a 30-ms long spike, a main pulse with a duration of 2 seconds, and a small hump with a duration of 100 ms. The spectrum of the burst was fitted by an OTTB model with a temperature of 20.9 keV.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6774', 'gcn', 'GRB 070809', '2007-09-08T22:39:45.000Z', '{"measurements":{"dec":null,"distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":{"R_2007-08-10_06:35":24.1,"R_2007-08-11_06:31":25,"g_2007-08-10_06:35":25.7,"g_2007-08-11_06:31":null},"other_measurements":{"airmass":"very high","exposure_time_R":"640s","exposure_time_g":"880s"},"ra":null,"redshift":null,"tables":[{"UT (mid-time)":"2007-08-10 06:35","magnitude_R":24.1,"magnitude_g":25.7,"t_burst (hr)":11.21},{"UT (mid-time)":"2007-08-11 06:31","magnitude_R":25,"magnitude_g":null,"t_burst (hr)":35.14}]},"authors":{"affiliations":["UC Berkeley"],"authors":["D. A. Perley","C. C. Thoene","J. S. Bloom"],"institutions":["DARK (Dark Energy Survey)"],"universities":["University of California, Berkeley (UCB)"]},"telescopes":{"facilities":["Dark Energy Survey"],"instruments":["LRIS (Low Resolution Imaging Spectrometer)"],"observatories":["Keck Observatory"],"telescopes":["Keck I"]},"urls":[],"basic_data":{"author":{"email":"dperley@astro.berkeley.edu","institution":"U.C. Berkeley","name":"Daniel Perley"},"coordinates":{},"detectionTime":"2007-09-08T22:39:45.000Z","event":"GRB 070809","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6774\nSUBJECT: GRB 070809: Confirmation of optical transient\nDATE: 07/09/08 22:39:45 GMT\nFROM: Daniel Perley at U.C. Berkeley  <dperley@astro.berkeley.edu>\n\nD. A. Perley (UC Berkeley), C. C. Thoene (DARK, UCB), and J. S. Bloom\n(UCB) report:\n\nAfter our initial observations (GCN 6739) of the possibly short GRB\n070809 (Palmer et al., GCN 6728), we obtained a second series of imaging\nthe following night using the Keck I telescope (+LRIS).\n\nWe imaged the field for a total of 640s (R) and 880s (g) simultaneously\nin a series of images starting at 06:20:17 UT (2007-08-11) at very high\nairmass.\n\nThe point-like source reported in GCN 6739 visible the first night has\nsignificantly faded, and is detectable only at the 3 sigma level in\nR-band and is undetected in g-band.  Using an absolute calibration\nrelative to Landolt standard stars, we calculate magnitudes of this\nsource of:\n\nUT (mid-time)     t_burst (hr)  magnitude\n2007-08-10 06:35  11.21         R = 24.1 +/- 0.2\n                                 g = 25.7 +/- 0.2\n2007-08-11 06:31  35.14         R = 25.0 +/- 0.3\n                                 g > 26.0 (3-sigma)\n\nWe caution that the source is very close to a bright (R~13) star and\nslightly blended with a diffraction spike in our imaging.  This and the\nvery high airmass of the observations may create additional\nuncertainties in the photometry.\n\nIn addition, we acquired a 2x600s spectrum of the nearby edge-on galaxy\nnoted in GCN 6739 during twilight starting at 05:46 UT (2007-08-11),\ncovering the wavelength range from about 3800 to 9200 AA. No obvious\nemission lines are detected."}', 'Astronomers at UC Berkeley and DARK report the confirmation of an optical transient associated with GRB 070809 using the Keck I telescope. The source, which was initially detected at a magnitude of R = 24.1 and g = 25.7 on August 10, 2007, has significantly faded and is only detectable at the 3 sigma level in R-band and undetected in g-band on August 11, 2007. The team obtained a spectrum of a nearby edge-on galaxy but did not detect any obvious emission lines.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6773', 'gcn', 'Observations of possible TAROT GRB transient near IC 4779', '2007-09-01T09:22:26.000Z', '{"measurements":{"dec":null,"distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":23,"other_measurements":{"exposure_time":30,"seeing":1.2,"time_of_observation":"Sep 1.0489 UT"},"ra":null,"redshift":null,"tables":[]},"authors":{"affiliations":["Niels Bohr Inst, Dark Cosmology Center","SUPA, St. Andrews"],"authors":["Daniele Malesani","K. Horne","N. Kains"],"institutions":["Dark Cosmology Center","SUPA, St. Andrews"],"universities":["Niels Bohr Inst, Dark Cosmology Center"]},"telescopes":{"facilities":[],"instruments":[],"observatories":["La Silla observatory"],"telescopes":["Danish telescope"]},"urls":["http://gcn.gsfc.nasa.gov"],"basic_data":{"author":{"email":"malesani@astro.ku.dk","institution":"Niels Bohr Inst,Dark Cosmology Center","name":"Daniele Malesani"},"coordinates":{},"detectionTime":"2007-09-01T09:22:26.000Z","event":"Observations of possible TAROT GRB transient near IC 4779","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6773\nSUBJECT: Observations of possible TAROT GRB transient near IC 4779\nDATE: 07/09/01 09:22:26 GMT\nFROM: Daniele Malesani at Niels Bohr Inst,Dark Cosmology Center  <malesani@astro.ku.dk>\n\nD. Malesani (DARK), K. Horne, and N. Kains (SUPA, St. Andrews), report \non behalf of a larger collaboration:\n\nWe observed the location of the candidate optical transient reported by \nKlotz et al. (GCN 6769) with the Danish telescope located at the La \nSilla observatory. Observations were carried out in the R band for a \ntotal of 30 min exposure, with mean time Sep 1.0489 UT. The seeing was 1.2\".\n\nConsistent with the reports of other observers (Berger et al., GCN 6770; \nFruchter et al., GCN 6772), at the location of the TAROT object we \ndetect no sources down to R~23 (calibrated against USNO-B1)."}', 'Astronomers using the Danish telescope at La Silla observatory report no detection of a possible TAROT GRB transient near IC 4779 down to a magnitude of R~23, consistent with other observations.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6772', 'gcn', 'Candidate Orphan GRB Optical Transient in IC 4779', '2007-09-01T06:38:20.000Z', '{"measurements":{"dec":null,"distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":24.5,"other_measurements":{"alignment_accuracy":"0.\"1","integration_time":"10 minutes","seeing":"0.\"5"},"ra":null,"redshift":null,"tables":[]},"authors":{"affiliations":["Stanford University","University of California, Berkeley","Space Telescope Science Institute (STSci)"],"authors":["A. Fruchter","J. Graham","A. Levan"],"institutions":["Space Telescope Science Institute (STScI)"],"universities":["Stanford University","University of California, Berkeley"]},"telescopes":{"facilities":["Gemini South"],"instruments":["GMOS"],"observatories":["Gemini Observatory"],"telescopes":["Gemini South telescope"]},"urls":[""],"basic_data":{"author":{"email":"fruchter@stsci.edu","institution":"STScI","name":"Andrew S. Fruchter"},"coordinates":{},"detectionTime":"2007-09-01T06:38:20.000Z","event":"Candidate Orphan GRB Optical Transient in IC 4779","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6772\nSUBJECT: Candidate Orphan GRB Optical Transient in IC 4779\nDATE: 07/09/01 06:38:20 GMT\nFROM: Andrew S. Fruchter at STScI  <fruchter@stsci.edu>\n\nA. Fruchter, J. Graham and A. Levan report for a larger group:\n\nWe observed the field of the candidate orphan optical transient in IC  \n4779 with GMOS on the Gemini South telescope for a total integration  \ntime of 10 minutes, starting at 1:03  UT on 1 September 2007.  The  \nsky was photometric and the seeing in the combined image was 0.\"5.    \nWe find no evidence of a point source on the field of the galaxy at  \nthe location of the candidate orphan down to a magnitude of about  \n24.5  in r.   We thank Alain Klotz for sending us copies of the  \noriginal discovery images, which allowed us to align the Gemini and  \ndiscovery images with an accuracy of nearly 0.\"1."}', 'A team led by A. Fruchter, J. Graham, and A. Levan used the Gemini South telescope with GMOS to observe the field of a candidate orphan optical transient in IC 4779, finding no evidence of a point source at the location down to a magnitude of 24.5 in r. The team thanks Alain Klotz for providing discovery images, allowing for accurate alignment.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6771', 'gcn', 'GRB 070810b', '2007-09-01T04:05:55.000Z', '{"measurements":{"dec":null,"distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":25.5,"other_measurements":{"exposure_time_first_epoch":630,"exposure_time_second_epoch":900,"time_difference_between_epochs":6},"ra":null,"redshift":null,"tables":[]},"authors":{"affiliations":["UC Berkeley"],"authors":["D. Kocevski","J.S. Bloom","C. C. Thoene","J. Prochaska"],"institutions":["UC Berkeley"],"universities":["University of California, Berkeley"]},"telescopes":{"facilities":[],"instruments":["LRIS"],"observatories":["Keck Observatory"],"telescopes":["Keck I"]},"urls":["http://pan-starrs.ifa.hawaii.edu/project/IPP/software/"],"basic_data":{"author":{"email":"kocevski@berkeley.edu","institution":"UC Berkeley","name":"Daniel Kocevski"},"coordinates":{},"detectionTime":"2007-09-01T04:05:55.000Z","event":"GRB 070810b","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6771\nSUBJECT: GRB 070810b: Image Subtraction of Multiple Keck Observations\nDATE: 07/09/01 04:05:55 GMT\nFROM: Daniel Kocevski at UC Berkeley  <kocevski@berkeley.edu>\n\nD. Kocevski, J.S. Bloom, C. C. Thoene, and J. Prochaska report:\n\nWe performed image subtraction between multiple R-band observations  \nof the error box of short burst GRB070810b (Marshall et al., GCN  \n6743) with the Keck I telescope (+LRIS).  The first epoch of  \nobservations began at (UT)  2007-08-11 14:45:00 followed by a second  \nepoch six nights later at (UT) 2007-08-17 12:02:00, with equivalent  \nexposures of 630 and 900 seconds respectively.  Image subtraction  \nusing the public POIS-IPP package(*) software shows no variable  \nsources associated with the S1, S2 XRT positions (GCN 6754 , Starling  \net al.) or the S3 position (Thoene et al., GCN 6756) nor any  \nsignificant residual sources within the BAT error circle down to a  \nlimiting magnitude of ~25.5 mag in R band.  The potential candidate  \nafterglow close to S2, reported by Pozanenko et al. can be resolved  \nas two objects in our images, which show no sign of variability  \nbetween the two epochs.\n\n* See http://pan-starrs.ifa.hawaii.edu/project/IPP/software/"}', 'Astronomers using the Keck I telescope with LRIS reported no significant variable sources or residual sources within the error circle of short burst GRB070810b down to a limiting magnitude of ~25.5 mag in R band. The potential candidate afterglow reported by Pozanenko et al. was resolved as two non-variable objects.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6770', 'gcn', 'Las Campanas observations of possible TAROT GRB transient near IC', '2007-09-01T02:56:39.000Z', '{"measurements":{"dec":null,"distance":null,"duration":null,"energy":null,"fluence":null,"magnitude":21,"other_measurements":{"exposure_time":600,"number_of_images":2,"observation_start_time":"Sep 1.009 UT"},"ra":null,"redshift":null,"tables":[]},"authors":{"affiliations":["Princeton","OCIW","CAMK"],"authors":["Edo Berger","J. Kaluzny","I. Thompson"],"institutions":["Carnegie Observatories","OCIW","CAMK"],"universities":["Princeton","CAMK"]},"telescopes":{"facilities":[],"instruments":[],"observatories":["Las Campanas Observatory"],"telescopes":["Swope 40-inch telescope"]},"urls":["http://www.ociw.edu/~eberger/swope.gif"],"basic_data":{"author":{"email":"eberger@ociw.edu","institution":"Carnegie Obs","name":"Edo Berger"},"coordinates":{},"detectionTime":"2007-09-01T02:56:39.000Z","event":"Las Campanas observations of possible TAROT GRB transient near IC","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6770\nSUBJECT: Las Campanas observations of possible TAROT GRB transient near IC\nDATE: 07/09/01 02:56:39 GMT\nFROM: Edo Berger at Carnegie Obs  <eberger@ociw.edu>\n\nE. Berger (Princeton, OCIW), J. Kaluzny (CAMK), and I. Thompson (OCIW) report:\n\nWe observed the position of the possible TAROT transient near IC 4779 (GCN \n6769) with the Swope 40-inch telescope at Las Campanas Observatory starting on \nSep 1.009 UT.  We obtained two 600-sec I-band images.  We do not detect any \nobject at the position of the possible transient to a limit of I~21 mag.  An \nimage of the field is available at:\n \thttp://www.ociw.edu/~eberger/swope.gif"}', 'Astronomers using the Swope 40-inch telescope at Las Campanas Observatory did not detect any transient object near IC 4779 to a limit of I~21 mag based on two 600-sec I-band images obtained on Sep 1.009 UT.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-677', 'gcn', 'GRB 000528', '2000-05-29T15:30:36.000Z', '{"measurements":{"dec":"-33o58''59\"","distance":null,"duration":{"gamma-rays":"80 s","x-rays":"120 s"},"energy":{"gamma-rays":"40-700 keV","x-rays":"2-26 keV"},"fluence":null,"magnitude":null,"other_measurements":{"peak_flux":"1.9 Crab units"},"ra":"10h45m06.3s","redshift":null,"tables":[]},"authors":{"affiliations":["Space Research Organization of the Netherlands (SRON), Utrecht","SRON and Astronomical Institute, Utrecht University","BeppoSAX Science Operations Center, Telespazio, Rome","SRON and BeppoSAX Science Data Center, Telespazio, Rome","Istituto di Astrofisica Spaziale, CNR, Rome","Istituto Tecnologie e Studi Radiazioni Extraterrestri, Bologna"],"authors":["J. in ''t Zand","J. Heise","E. Kuulkers","G. D''Andreta","G. Celidonio","J.M. Muller","G. Gandolfi","E. Costa","F. Frontera"],"institutions":["Space Research Organization of the Netherlands (SRON)","BeppoSAX Science Operations Center, Telespazio, Rome","Astronomical Institute, Utrecht University","Istituto di Astrofisica Spaziale, CNR, Rome","Istituto Tecnologie e Studi Radiazioni Extraterrestri, Bologna"],"universities":["Utrecht University"]},"telescopes":{"facilities":[],"instruments":["Wide Field Camera (WFC) unit 2"],"observatories":[],"telescopes":["BeppoSAX Gamma-Ray Burst Monitor"]},"urls":[],"basic_data":{"author":{"email":"jeanz@sron.nl","institution":"SRON","name":"Jean int Zand"},"coordinates":{},"detectionTime":"2000-05-29T15:30:36.000Z","event":"GRB 000528","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 677\nSUBJECT: GRB 000528 - WFC measurements\nDATE: 00/05/29 15:30:36 GMT\nFROM: Jean int Zand at SRON  <jeanz@sron.nl>\n\nJ. in ''t Zand and J. Heise, Space Research Organization of the\nNetherlands (SRON), Utrecht; E. Kuulkers, SRON and Astronomical Institute,\nUtrecht University; G. D''Andreta and G. Celidonio, BeppoSAX Science\nOperations Center, Telespazio, Rome; J.M. Muller, SRON and BeppoSAX Science\nData Center, Telespazio, Rome; G. Gandolfi and E. Costa, Istituto di\nAstrofisica Spaziale, CNR, Rome; and F. Frontera, Istituto Tecnologie e\nStudio Radiazioni Extraterrestri, Bologna, report: \"GRB 000528, which was \ndetected by the BeppoSAX Gamma-Ray Burst Monitor on May 28.366 UT (GCN Circ.\n675), was simultaneously detected with Wide Field Camera (WFC) unit 2.  While\nthe burst lasted for about 80 s in gamma-rays (40-700 keV), it lasted about\n120 s in x-rays (2-26 keV). The WFC-determined position is R.A. = 10h45m06.3s,\nDecl. = -33o58''59\" (equinox 2000.0), with an error radius of 2'' (99-percent\nconfidence level). The 2-26 keV peak flux is 1.9 Crab units.\""}', 'Astronomical alert: GRB 000528 - WFC measurements', 0.5, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6769', 'gcn', 'Orphan GRB candidate in IC 4779 at TAROT La Silla observatory', '2007-08-31T21:03:38.000Z', '{"measurements":{"dec":"-63d01m00s3","distance":null,"duration":[{"unit":"sec","value":"120"},{"unit":"sec","value":"10"},{"unit":"sec","value":"1"}],"energy":null,"fluence":null,"magnitude":"11.7","other_measurements":{"spread":"25 pixels"},"ra":"18h50m32s0","redshift":"0.016752","tables":[{"exposure":["120","sec"],"filter":["R"]},{"duration":["120","10","1"],"expected_magnitude":["11.7","9.0","6.5"],"unit":["sec","sec","sec"]}]},"authors":{"affiliations":["CESR-OMP"],"authors":["Alain.Klotz"],"institutions":["CESR-CNRS"],"universities":["CNRS"]},"telescopes":{"facilities":[],"instruments":[],"observatories":["La Silla observatory"],"telescopes":["TAROT"]},"urls":["http://www.cesr.fr/~klotz/ic4779/"],"basic_data":{"author":{"email":"Alain.Klotz@free.fr","institution":"CESR-CNRS","name":"Alain Klotz"},"coordinates":{},"detectionTime":"2007-08-31T21:03:38.000Z","event":"Orphan GRB candidate in IC 4779 at TAROT La Silla observatory","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6769\nSUBJECT: Orphan GRB candidate in IC 4779 at TAROT La Silla observatory\nDATE: 07/08/31 21:03:38 GMT\nFROM: Alain Klotz at CESR-CNRS  <Alain.Klotz@free.fr>\n\nKlotz, A. (CESR-OMP), Boer M. (OHP), Atteia J.L. (LATT-OMP) report:\n\nDuring the night 30-31 August 2007,\nwe imaged six times a 2x2 degrees field\ncentered on RA=18h47.3min DEC=-63d20m (J2000,0)\nto search supernovae.\n\nDates of beginning of exposures are following:\n\n#1 2007-08-31T00:20:38.69 exposure=120s, filter=R\n#2 2007-08-31T00:22:44.56 exposure=120s, filter=R\n#3 2007-08-31T01:16:47.89 exposure=120s, filter=R\n#4 2007-08-31T01:18:53.76 exposure=120s, filter=R\n#5 2007-08-31T02:22:15.39 exposure=120s, filter=R\n#6 2007-08-31T02:24:21.26 exposure=120s, filter=R\n\nWe detect a bright like-star object R=11.7\nonly in the #5 image, at coordinates:\n\nRA=18h50m32s0 DEC=-63d01m00s3 (J2000,0)\n\nThis object is at 18 arcsec S-E of the IC 4779 nucleus\n(redshift z=0.016752 from NED).\n\nNone is seen at this place in other images,\nimplying R>18.5.\n\nScreen copies of images are available at:\n\nhttp://www.cesr.fr/~klotz/ic4779/\n\nAll the evidence available at that time is in favor\nof a real astronomical optical transient (hereafter OT).\nThe 2D profile of the OT is very close to that of\nthe PSF derived from nearby stars of same magnitude\n(OT spreads on about 25 pixels). An artificial satellite\nor a plane flashlight are rejected because none is\nseen in the #6 image.\n\nWe suggest that if this OT is an astronomical\ntransient, one hypothesis is an optical flash\noccurring when a short burst (SHGRB) is active in\ngamma wavelengths. This idea is supported\nby the fact the #6 image taken just after the #5 one\ndoes not show the OT. Moreover, the low distance\nof IC 4779 is compatible with a host galaxy\nof SHGRB.\n\nWe remind that, due to their very short durations (<0.2s)\nno optical telescope had ever observed a SHGRB\nduring its gamma emission phase.\n\nWe are currently regarding other possibilities than\na GRB (a cosmic trace is almost excluded at\nthe current step of analysis).\n\nComplementary observations are strongly encouraged.\nSome suggestions to do to confirm a SHGRB are:\n\n- Searching in large field surveys archives\n   at the #5 image date. Following table indicates\n   the expected magnitudes reached for various duration\n   of the optical transient during the exposure:\n   R=11.7 if duration=120 sec.\n   R=9.0 if duration=10 sec.\n   R=6.5 if duration=1 sec.\n\n- Deep image at OT position (mag lim > 23)\n   as soon as possible with a very large telescope.\n\n- Searching in the high-energy satellites\n   archive to find a SHGRB signal\n   at the #5 image date.\n\nFITS files are available asking to alain.klotz@free.fr\n\nThis message may be cited."}', 'An orphan GRB (gamma-ray burst) candidate was detected as a bright, transient object in the IC 4779 galaxy during observations by the TAROT La Silla observatory. The object, with a magnitude of 11.7, was only visible in one image and was not present in subsequent images, suggesting a short duration. The evidence points towards an astronomical transient, potentially an optical flash from a SHGRB (short-hard gamma-ray burst) active in gamma wavelengths.', 0.85, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6768', 'gcn', 'GRB 070824', '2007-08-31T12:05:53.000Z', '{"measurements":{"dec":null,"distance":null,"duration":12,"energy":null,"fluence":0.0000284,"magnitude":null,"other_measurements":{"Ep_band_model_error":20,"Ep_error":19,"alpha_band_model_error":0.084,"alpha_error":0.081,"duration_unit":"s","fluence_unit":"erg/cm2","peak_flux":0.0000285,"peak_flux_unit":"erg/cm2/s"},"ra":null,"redshift":null,"tables":[{"Ep":253,"alpha":1.051,"chi2":66.2,"dof":60},{"Ep":243,"alpha":-1.025,"beta":"< -2.55","chi2":64.5,"dof":59}]},"authors":{"affiliations":["Ioffe Inst, on behalf of the Konus-Wind team"],"authors":["S. Golenetskii","R. Aptekar","E. Mazets","V. Pal''shin","D. Frederiks","T. Cline"],"institutions":["Ioffe Inst"],"universities":["Ioffe Inst"]},"telescopes":{"facilities":[],"instruments":[],"observatories":[],"telescopes":[]},"urls":["http://www.ioffe.rssi.ru/LEA/GRBs/GRB070824_T74999/"],"basic_data":{"author":{"email":"val@mail.ioffe.ru","institution":"Ioffe Inst","name":"Valentin Pal''shin"},"coordinates":{},"detectionTime":"2007-08-31T12:05:53.000Z","event":"GRB 070824","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6768\nSUBJECT: Konus-Wind observation of GRB 070824\nDATE: 07/08/31 12:05:53 GMT\nFROM: Valentin Pal''shin at Ioffe Inst  <val@mail.ioffe.ru>\n\nS. Golenetskii, R.Aptekar, E. Mazets, V. Pal''shin, D. Frederiks,\nand T. Cline on behalf of the Konus-Wind team:\n\nThe bright long GRB 070824 localized by SuperAGILE/IPN\n(Donnarumma et al., GCN 6767) triggered Konus-Wind\nat T0=74999.585 s UT (20:49:59.585).\n\nThe Konus-Wind light curve shows two pulses\nwith a total duration of ~12 s.\n\nAs observed by Konus-Wind the burst\nhad a fluence of 2.84(-0.26, +0.09)x10^-5 erg/cm2,\nand a 16-ms peak flux measured from T0+8.368 s\nof 2.85(-0.38, +0.29)x10^-5 erg/cm2/s\n(both in the 20 keV - 2 MeV energy range).\n\nThe time-integrated spectrum of the burst\n(from T0 s to T0+16.986 s) is well fitted\n(in the 20 keV - 2 MeV range)\nby a power law with exponential cutoff model:\ndN/dE ~ E^(-alpha)*exp(-E*(2-alpha)/Ep)\nwith alpha = 1.051 (-0.081, +0.078)\nand Ep = 253 (-19, +22) keV (chi2 = 66.2/60 dof).\nFitting by a GRBM (Band) model yields:\nthe low-energy photon index alpha = -1.025 +/- 0.084,\nthe high energy photon index beta < -2.55,\nthe peak energy Ep = 243(-20, +24) keV (chi2 = 64.5/59 dof).\n\nAll the quoted errors are at the 90% confidence level.\n\nThe Konus-Wind light curve of this GRB is available\nat http://www.ioffe.rssi.ru/LEA/GRBs/GRB070824_T74999/"}', 'The Konus-Wind team reported the observation of GRB 070824, a long gamma-ray burst triggered by SuperAGILE/IPN. The burst had a duration of approximately 12 seconds and a fluence of 2.84x10^-5 erg/cm2 in the 20 keV - 2 MeV energy range. The time-integrated spectrum was fitted with a power law with exponential cutoff model and a GRBM (Band) model, yielding different values for the low-energy and high-energy photon indices and peak energies.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6767', 'gcn', 'GRB 070824', '2007-08-30T17:46:04.000Z', '{"measurements":{"dec":[-27.24,-26.648,-34.944,-34.281,-26.864,-27.715,-27.24],"distance":null,"duration":3,"energy":null,"fluence":null,"magnitude":null,"other_measurements":{"T90":9.5,"error radius":20,"off-axis angle":48.1,"significance":4.6},"ra":[172.281,171.938,147.942,148.056,172.055,171.188,172.281],"redshift":null,"tables":[{"Dec":-27.24,"RA":172.281},{"Dec":-26.648,"RA":171.938},{"Dec":-34.944,"RA":147.942},{"Dec":-34.281,"RA":148.056},{"Dec":-26.864,"RA":172.055},{"Dec":-27.715,"RA":171.188},{"Dec":-27.24,"RA":172.281}]},"authors":{"affiliations":["AGILE Team","AGILE Science Data Center","Konus-Wind and Konus-A teams","IPN Teams","Swift/BAT team","RHESSI GRB team","AGILE/Minicalorimeter","AGILE/Anticoincidence","Cosmos-2421"],"authors":["I. Donnarumma","E. Del Monte","F. Lazzarotto","M. Feroci","A. Giuliani","M. Marisaldi","B. Preger","S. Golenetskii","R.Aptekar","E. Mazets","V. Pal''shin","D. Frederiks","P. Oleynik","M. Ulanov","T. Cline","K. Hurley","J. Cummings","D. Palmer","H. Krimm","D. M. Smith","R. P. Lin","J. McTiernan","R. Schwartz","C. Wigger","W. Hajdas","A. Zehnder"],"institutions":["AGILE Team","AGILE Science Data Center","IPN Teams","Swift/BAT team","RHESSI GRB team","AGILE/Minicalorimeter","AGILE/Anticoincidence","Cosmos-2421"],"universities":["IASF/INAF","SSL, Berkeley"]},"telescopes":{"facilities":["AGILE Science Data Center"],"instruments":["SuperAGILE"],"observatories":["AGILE Science Data Center"],"telescopes":["SuperAGILE","AGILE/Minicalorimeter","AGILE/Anticoincidence","Konus-Wind","Konus-A"]},"urls":["www.ssl.berkeley.edu/ipn3/070824"],"basic_data":{"author":{"email":"feroci@iasf-roma.inaf.it","institution":"IASF/INAF","name":"Marco Feroci"},"coordinates":{},"detectionTime":"2007-08-30T17:46:04.000Z","event":"GRB 070824","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6767\nSUBJECT: GRB 070824 - Combined SuperAGILE/IPN Localization\nDATE: 07/08/30 17:46:04 GMT\nFROM: Marco Feroci at IASF/INAF  <feroci@iasf-roma.inaf.it>\n\nCombined SuperAGILE/IPN Localization of the long and bright GRB 070824\n\n\nI. Donnarumma, E. Del Monte, F. Lazzarotto, M. Feroci, A. Giuliani,\nM. Marisaldi, on behalf of the AGILE Team, \n\nB. Preger, on behalf of the AGILE Science Data Center, \n\nS. Golenetskii, R.Aptekar, E. Mazets, V. Pal''shin, D. Frederiks, P. \nOleynik, M. Ulanov and T. Cline on behalf of the Konus-Wind and Konus-A \nteams, \n\nK. Hurley on behalf of the IPN Teams, \n\nJ. Cummings, D. Palmer and H. Krimm, on behalf of the Swift/BAT team,\n\nD. M. Smith, R. P. Lin, J. McTiernan, R. Schwartz, C. Wigger, W. Hajdas, \nand A. Zehnder, on behalf of the RHESSI GRB team, \n\nreport: \n\nGRB 070824 triggered the SuperAGILE ground software trigger on 24\nAugust 2007, at 20:50:09 UT. The GRB was seen as a 3 s long event,\npreceded by a weaker 2 s precursor 5 s earlier. The SuperAGILE T90 for \nthis event was 9.5 s.  The event was observed by SuperAGILE at 48.1 deg \noff-axis,  which is in a region of the instrument field of view with only \none-dimensional imaging. In spite of this, the event was observed on all \nSuperAGILE detectors; due to its hardness,  it passed through the \ncollimator shields. In addition, its arrival direction was partially \nobscured by the Earth''s atmosphere for AGILE. For these reasons, the event \nwas imaged by SuperAGILE with only 4.6 sigma significance. The \nSuperAGILE-only error box is thus a long, narrow strip, limited by the \ninstrument field of view and Earth occultation in one direction and by the \nimaging uncertainty in the other. For the latter we assumed a 20 arcmin \nerror radius, including statistics and systematics, due to the low \nstatistics of the detection and the far off-axis position. The resulting \nerror box is:\t\t\n\nRA\t  Dec\n===============\n172.281 -27.240 \n171.938 -26.648\n147.942 -34.944 \n148.056 -34.281\n\nThe SuperAGILE light curve may be found at the AGILE Science Data Center \nand AGILE-Team web pages.\n\nThis event was independently detected by other IPN experiments, namely \nKonus-Wind, Swift/BAT, RHESSI, AGILE/Minicalorimeter, and the\nAGILE/Anticoincidence, as well as by Konus-A (Cosmos-2421). Their\ndetection combined to provide further constraints to the burst\nlocalization, as shown in the figure at\nwww.ssl.berkeley.edu/ipn3/070824. \n\nThe final localization of GRB 070824 is thus limited by the\ncorners of a triangular area:\n\n   RA      Dec \t\n==================\n1: 172.055 -26.864\n2: 171.188 -27.715\n3: 172.281 -27.240"}', 'GRB 070824, a long and bright gamma-ray burst detected by multiple experiments including SuperAGILE, Konus-Wind, Swift/BAT, RHESSI, AGILE/Minicalorimeter, AGILE/Anticoincidence, and Konus-A, was localized using combined data. The event triggered SuperAGILE on August 24, 2007, and was observed off-axis with limited imaging significance due to Earth occultation and instrument limitations. The final error box was determined by combining data from all experiments and is limited by the corners of a triangular area with RA values of approximately 171.188°, 172.055°, and 172.281°, and Dec values of approximately -27.715°, -26.864°, and -27.24°.', 0.9, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6766', 'gcn', 'GRB 070821', '2007-08-28T15:42:39.000Z', '{"measurements":{"dec":null,"distance":null,"duration":215,"energy":null,"fluence":0.000102,"magnitude":null,"other_measurements":{"Ep_main_episode":268,"Ep_pulse":289,"alpha_main_episode":1.299,"alpha_pulse":1.215,"fluence_pulse":0.0000834,"peak_flux":0.0000138},"ra":null,"redshift":null,"tables":[]},"authors":{"affiliations":["Ioffe Inst, on behalf of the Konus-Wind team"],"authors":["S. Golenetskii","R.Aptekar","E. Mazets","V. Pal''shin","D. Frederiks","T. Cline"],"institutions":["Ioffe Inst"],"universities":["Ioffe Inst"]},"telescopes":{"facilities":[],"instruments":[],"observatories":[],"telescopes":[]},"urls":["<http://www.ioffe.rssi.ru/LEA/GRBs/GRB070821_T46164/>","http://www.ioffe.rssi.ru/LEA/GRBs/GRB070821_T46164/"],"basic_data":{"author":{"email":"val@mail.ioffe.ru","institution":"Ioffe Inst","name":"Valentin Pal''shin"},"coordinates":{},"detectionTime":"2007-08-28T15:42:39.000Z","event":"GRB 070821","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6766\nSUBJECT: Konus-Wind observation of very bright GRB 070821\nDATE: 07/08/28 15:42:39 GMT\nFROM: Valentin Pal''shin at Ioffe Inst  <val@mail.ioffe.ru>\n\nS. Golenetskii, R.Aptekar, E. Mazets, V. Pal''shin, D. Frederiks,\nand T. Cline on behalf of the Konus-Wind team:\n\nThe very bright long GRB 070821 localized by the IPN (Hurley et al.,\nGCN 6764) triggered Konus-Wind at T0=46164.332 s UT (12:49:24.332).\n\nThe Konus-Wind light curve shows a soft precursor started at T-T0 ~-6 s \n(with a duration of ~8 s), followed by a very intense multipeaked pulse \nat T-T0 ~120 s and a weaker pulse at T-T0 ~180 s\n(there is an emission between these two intense pulses).\nThe total burst duration is ~215 s.\n\nAs observed by Konus-Wind the burst\nhad a fluence of 1.02(-0.04, +0.03)x10^-4 erg/cm2,\nand a 256-ms peak flux measured from T0+126.720 s\nof 1.38(-0.11, +0.09)x10^-5 erg/cm2/s\n(both in the 20 keV - 2 MeV energy range).\n\nThe time-integrated spectrum of the main episode\n(from T0+114.944 s to T0+203.776 s) can be fitted\n(in the 20 keV - 2 MeV range)\nby a power law with exponential cutoff model:\ndN/dE ~ E^(-alpha)*exp(-E*(2-alpha)/Ep)\nwith alpha = 1.299  +/- 0.037\nand Ep = 268 (-17, +19) keV (chi2 = 67.8/59 dof).\n\nThe spectrum of the most intense pulse\n(accumulated from T0+114.944 s to T0+146.432 s)\nis well fitted (in the 20 keV - 2 MeV range)\nby a power law with exponential cutoff model\nwith alpha = 1.215  +/- 0.030\nand Ep = 289 (-14, +15) keV (chi2 = 68.3/59 dof).\nThis pulse had a fluence of 8.34(-0.24, +0.17)x10^-5 erg/cm2.\n\nAll the quoted errors are at the 90% confidence level.\n\nThe Konus-Wind light curve of this GRB is available\nat http://www.ioffe.rssi.ru/LEA/GRBs/GRB070821_T46164/"}', 'The Konus-Wind team reported observing a very bright gamma-ray burst (GRB 070821) triggered at T0=46164.332 s UT. The burst consisted of a soft precursor, a very intense multipeaked pulse, and a weaker pulse. The total duration was ~215 seconds. The main episode had a fluence of 1.02x10^-4 erg/cm2 and a peak flux of 1.38x10^-5 erg/cm2/s in the 20 keV - 2 MeV energy range. The spectrum of the most intense pulse was fitted by a power law with exponential cutoff model with alpha = 1.215 and Ep = 289 keV.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6765', 'gcn', 'GRB 070731', '2007-08-27T13:21:53.000Z', '{"measurements":{"dec":null,"distance":null,"duration":{"unit":"s","value":1154},"energy":null,"fluence":null,"magnitude":20.9,"other_measurements":{"exposure_time_1":{"unit":"ks","value":144},"exposure_time_2":{"unit":"ks","value":219},"exposure_time_3":{"unit":"ks","value":155}},"ra":null,"redshift":null,"tables":[]},"authors":{"affiliations":["NASA/GSFC","INAF-OAB"],"authors":["F.E. Marshall","A. Moretti"],"institutions":["GSFC","INAF-OAB"],"universities":["NASA/GSFC"]},"telescopes":{"facilities":[],"instruments":["Swift/UVOT"],"observatories":[],"telescopes":["Swift"]},"urls":["http://gcn.gsfc.nasa.gov"],"basic_data":{"author":{"email":"marshall@milkyway.gsfc.nasa.gov","institution":"GSFC","name":"Frank Marshall"},"coordinates":{},"detectionTime":"2007-08-27T13:21:53.000Z","event":"GRB 070731","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6765\nSUBJECT: GRB 070731: Swift/UVOT Upper Limit\nDATE: 07/08/27 13:21:53 GMT\nFROM: Frank Marshall at GSFC  <marshall@milkyway.gsfc.nasa.gov>\n\nF.E. Marshall (NASA/GSFC) and A. Moretti (INAF-OAB)\nreport on behalf of the Swift team:\n\nThe Swift/UVOT observed the field of GRB 070731 starting 144 ks \nafter the BAT trigger (Tueller et al., GCN Circ. 6691), which\noccurred at 09:33:22 UT (Moretti et al., GCN Report 79.1). \nAll of the UVOT exposures used the White (160-650 nm) filter, \nand the final exposure started 219 ks after the trigger. \nNo XRT source was detected (Moretti et al., GCN Report 79.1) \ninside the BAT error circle, and we do not find any afterglow \ncandidate inside the BAT error circle in the UVOT observations. \nThe first long (1154 s) exposure that covered the entire \nBAT error circle started 155 ks after the BAT trigger. \nThe 3-sigma upper limit for detecting a source is 20.9 mag. \n(uncorrected for the expected Galactic extinction corresponding \nto a reddening of E(B-V) = 0.04 mag in the direction of the burst \n(Schlegel et al. 1998))."}', 'The Swift team reports no detection of an afterglow or source within the error circle of GRB 070731 using Swift/UVOT, with a 3-sigma upper limit of 20.9 mag (uncorrected for Galactic extinction). The first long exposure covering the entire error circle started 155 ks after the trigger.', 0.95, ARRAY[], NOW(), NOW());

INSERT INTO alerts (alert_key, broker, event, date, data, summary, confidence_level, tags, created_at, updated_at) 
VALUES ('GCN-6764', 'gcn', 'GRB 070821', '2007-08-24T21:20:45.000Z', '{"measurements":[{"DEC(2000)":-63.85,"RA(2000)":95.527,"unit":"DEGREES"},{"DEC(2000)":-63.928,"RA(2000)":95.422,"unit":"DEGREES"},{"DEC(2000)":-63.842,"RA(2000)":95.811,"unit":"DEGREES"},{"DEC(2000)":-63.858,"RA(2000)":95.242,"unit":"DEGREES"},{"DEC(2000)":-63.772,"RA(2000)":95.631,"unit":"DEGREES"}],"authors":{"affiliations":["UCBerkeley/SSL","Mars Odyssey (HEND and GRS)","Konus","MESSENGER","HEND-Odyssey","GRS-Odyssey","Konus-Wind","RHESSI"],"authors":["K. Hurley","T. Cline","I.G. Mitrofanov","M.L. Litvak","A.S. Kozyrev","A.B. Sanin","V.I. Tretyakov","W. Boynton","C. Fellows","K. Harshman","C. Shinohara","R. Starr","S. Golenetskii","R.Aptekar","E. Mazets","V. Pal''shin","D. Frederiks","T. Cline","D. M. Smith","R. P. Lin","J. McTiernan","R. Schwartz","C. Wigger","W. Hajdas","A. Zehnder","J. Goldsten"],"institutions":["SSL (Space Sciences Laboratory)","Mars Odyssey","Konus","MESSENGER","HEND-Odyssey","GRS-Odyssey","Konus-Wind","RHESSI","MESSENGER (NS)"],"universities":["University of California, Berkeley"]},"telescopes":{"facilities":["Mars Odyssey","HEND-Odyssey","GRS-Odyssey","Konus-Wind","RHESSI","MESSENGER (NS)"],"instruments":["HEND","GRS","Konus"],"observatories":["Konus-Wind"],"telescopes":["Mars Odyssey","HEND-Odyssey","GRS-Odyssey","Konus-Wind","RHESSI"]},"urls":[],"basic_data":{"author":{"email":"khurley@ssl.berkeley.edu","institution":"UCBerkeley/SSL","name":"Kevin Hurley"},"coordinates":{},"detectionTime":"2007-08-24T21:20:45.000Z","event":"GRB 070821","eventType":"GRB","source":"GCN"},"raw":"TITLE: GCN CIRCULAR\nNUMBER: 6764\nSUBJECT: IPN Localization of GRB 070821 (long, very bright)\nDATE: 07/08/24 21:20:45 GMT\nFROM: Kevin Hurley at UCBerkeley/SSL  <khurley@ssl.berkeley.edu>\n\nK. Hurley and T. Cline, on behalf of the Mars Odyssey, Konus, and\nMESSENGER GRB teams,\n\nI.G. Mitrofanov, M.L. Litvak, A.S. Kozyrev, A.B. Sanin and V.I. Tretyakov,\non behalf of the HEND-Odyssey GRB team,\n\nW. Boynton, C. Fellows, K. Harshman, C. Shinohara and R. Starr, on\nbehalf of the GRS-Odyssey GRB team,\n\nS. Golenetskii, R.Aptekar, E. Mazets, V. Pal''shin, D. Frederiks, and\nT. Cline on behalf of the Konus-Wind team,\n\nD. M. Smith, R. P. Lin, J. McTiernan, R. Schwartz, C. Wigger, W.\nHajdas, and A. Zehnder, on behalf of the RHESSI GRB team, and\n\nJ. Goldsten, on behalf of the MESSENGER NS GRB team,\n\nKonus-Wind, Mars Odyssey (HEND and GRS), RHESSI, and MESSENGER (NS)\nobserved this burst at 46164 s.  (MESSENGER data downlinks were delayed\nbecause the spacecraft is in conjunction.)  As observed by Konus, it had a\nduration ~ 180 s, a 20-2000 keV fluence ~ 10^-4 erg/cm2, and an\nEpeak ~ 300 keV.  We have triangulated it to a preliminary, 3\nsigma error box whose area is ~ 70 sq. arcmin. and whose coordinates are:\n\n\nRA(2000) DEC(2000)\n95.527   -63.850 DEGREES (CENTER)\n95.422   -63.928 DEGREES (CORNER)\n95.811   -63.842 DEGREES (CORNER)\n95.242   -63.858 DEGREES (CORNER)\n95.631   -63.772 DEGREES (CORNER)\n\nThis error box may be improved.  Spectral information will follow in\na separate circular."}', 'A group of astronomers, including teams from Mars Odyssey, Konus, MESSENGER, HEND-Odyssey, GRS-Odyssey, Konus-Wind, RHESSI, and MESSENGER (NS), have detected and localized a long, very bright gamma-ray burst (GRB 070821) with a preliminary error box of approximately 70 sq. arcmin. The burst had a duration of around 180 seconds and a fluence of ~10^-4 erg/cm2 in the 20-2000 keV energy range. The peak energy was estimated to be ~300 keV.', 0.95, ARRAY[], NOW(), NOW());